var VERSES_JEREMIAH=[{"ref":"Jeremiah 1:1","short":"Jer 1:1","text":"The words of Jeremiah, the son of Hilkiah, one of the priests who were in Anathoth in the land of Benjamin,","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":1},{"ref":"Jeremiah 1:2","short":"Jer 1:2","text":"to whom the word of the LORD came in the days of Josiah the son of Amon, king of Judah, in the thirteenth year of his reign.","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":2},{"ref":"Jeremiah 1:3","short":"Jer 1:3","text":"It came also in the days of Jehoiakim the son of Josiah, king of Judah, and until the end of the eleventh year of Zedekiah, the son of Josiah, king of Judah, until the captivity of Jerusalem in the fifth month.","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":3},{"ref":"Jeremiah 1:4","short":"Jer 1:4","text":"Now the word of the LORD came to me, saying,","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":4},{"ref":"Jeremiah 1:5","short":"Jer 1:5","text":"“Before I formed you in the womb I knew you, and before you were born I consecrated you; I appointed you a prophet to the nations.”","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":5},{"ref":"Jeremiah 1:6","short":"Jer 1:6","text":"Then I said, “Ah, Lord GOD! Behold, I do not know how to speak, for I am only a youth.”","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":6},{"ref":"Jeremiah 1:7","short":"Jer 1:7","text":"But the LORD said to me, “Do not say, ‘I am only a youth’; for to all to whom I send you, you shall go, and whatever I command you, you shall speak.","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":7},{"ref":"Jeremiah 1:8","short":"Jer 1:8","text":"Do not be afraid of them, for I am with you to deliver you, declares the LORD.”","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":8},{"ref":"Jeremiah 1:9","short":"Jer 1:9","text":"Then the LORD put out his hand and touched my mouth. And the LORD said to me, “Behold, I have put my words in your mouth.","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":9},{"ref":"Jeremiah 1:10","short":"Jer 1:10","text":"See, I have set you this day over nations and over kingdoms, to pluck up and to break down, to destroy and to overthrow, to build and to plant.”","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":10},{"ref":"Jeremiah 1:11","short":"Jer 1:11","text":"And the word of the LORD came to me, saying, “Jeremiah, what do you see?” And I said, “I see an almond branch.”","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":11},{"ref":"Jeremiah 1:12","short":"Jer 1:12","text":"Then the LORD said to me, “You have seen well, for I am watching over my word to perform it.”","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":12},{"ref":"Jeremiah 1:13","short":"Jer 1:13","text":"The word of the LORD came to me a second time, saying, “What do you see?” And I said, “I see a boiling pot, facing away from the north.”","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":13},{"ref":"Jeremiah 1:14","short":"Jer 1:14","text":"Then the LORD said to me, “Out of the north disaster shall be let loose upon all the inhabitants of the land.","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":14},{"ref":"Jeremiah 1:15","short":"Jer 1:15","text":"For behold, I am calling all the tribes of the kingdoms of the north, declares the LORD, and they shall come, and every one shall set his throne at the entrance of the gates of Jerusalem, against all its walls all around and against all the cities of Judah.","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":15},{"ref":"Jeremiah 1:16","short":"Jer 1:16","text":"And I will declare my judgments against them, for all their evil in forsaking me. They have made offerings to other gods and worshiped the works of their own hands.","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":16},{"ref":"Jeremiah 1:17","short":"Jer 1:17","text":"But you, dress yourself for work; arise, and say to them everything that I command you. Do not be dismayed by them, lest I dismay you before them.","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":17},{"ref":"Jeremiah 1:18","short":"Jer 1:18","text":"And I, behold, I make you this day a fortified city, an iron pillar, and bronze walls, against the whole land, against the kings of Judah, its officials, its priests, and the people of the land.","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":18},{"ref":"Jeremiah 1:19","short":"Jer 1:19","text":"They will fight against you, but they shall not prevail against you, for I am with you, declares the LORD, to deliver you.”","url":"ot/jeremiah/Jeremiah_1.html","book":"Jeremiah","ch":1,"v":19},{"ref":"Jeremiah 2:1","short":"Jer 2:1","text":"The word of the LORD came to me, saying,","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":1},{"ref":"Jeremiah 2:2","short":"Jer 2:2","text":"“Go and proclaim in the hearing of Jerusalem, Thus says the LORD, “I remember the devotion of your youth, your love as a bride, how you followed me in the wilderness, in a land not sown.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":2},{"ref":"Jeremiah 2:3","short":"Jer 2:3","text":"Israel was holy to the LORD, the firstfruits of his harvest. All who ate of it incurred guilt; disaster came upon them, declares the LORD.”","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":3},{"ref":"Jeremiah 2:4","short":"Jer 2:4","text":"Hear the word of the LORD, O house of Jacob, and all the clans of the house of Israel.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":4},{"ref":"Jeremiah 2:5","short":"Jer 2:5","text":"Thus says the LORD: “What wrong did your fathers find in me that they went far from me, and went after worthlessness, and became worthless?","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":5},{"ref":"Jeremiah 2:6","short":"Jer 2:6","text":"They did not say, ‘Where is the LORD who brought us up from the land of Egypt, who led us in the wilderness, in a land of deserts and pits, in a land of drought and deep darkness, in a land that none passes through, where no man dwells?’","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":6},{"ref":"Jeremiah 2:7","short":"Jer 2:7","text":"And I brought you into a plentiful land to enjoy its fruits and its good things. But when you came in, you defiled my land and made my heritage an abomination.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":7},{"ref":"Jeremiah 2:8","short":"Jer 2:8","text":"The priests did not say, ‘Where is the LORD?’ Those who handle the law did not know me; the shepherds transgressed against me; the prophets prophesied by Baal and went after things that do not profit.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":8},{"ref":"Jeremiah 2:9","short":"Jer 2:9","text":"“Therefore I still contend with you, declares the LORD, and with your children’s children I will contend.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":9},{"ref":"Jeremiah 2:10","short":"Jer 2:10","text":"For cross to the coasts of Cyprus and see, or send to Kedar and examine with care; see if there has been such a thing.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":10},{"ref":"Jeremiah 2:11","short":"Jer 2:11","text":"Has a nation changed its gods, even though they are no gods? But my people have changed their glory for that which does not profit.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":11},{"ref":"Jeremiah 2:12","short":"Jer 2:12","text":"Be appalled, O heavens, at this; be shocked, be utterly desolate, declares the LORD,","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":12},{"ref":"Jeremiah 2:13","short":"Jer 2:13","text":"for my people have committed two evils: they have forsaken me, the fountain of living waters, and hewed out cisterns for themselves, broken cisterns that can hold no water.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":13},{"ref":"Jeremiah 2:14","short":"Jer 2:14","text":"“Is Israel a slave? Is he a homeborn servant? Why then has he become a prey?","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":14},{"ref":"Jeremiah 2:15","short":"Jer 2:15","text":"The lions have roared against him; they have roared loudly. They have made his land a waste; his cities are in ruins, without inhabitant.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":15},{"ref":"Jeremiah 2:16","short":"Jer 2:16","text":"Moreover, the men of Memphis and Tahpanhes have shaved the crown of your head.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":16},{"ref":"Jeremiah 2:17","short":"Jer 2:17","text":"Have you not brought this upon yourself by forsaking the LORD your God, when he led you in the way?","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":17},{"ref":"Jeremiah 2:18","short":"Jer 2:18","text":"And now what do you gain by going to Egypt to drink the waters of the Nile? Or what do you gain by going to Assyria to drink the waters of the Euphrates?","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":18},{"ref":"Jeremiah 2:19","short":"Jer 2:19","text":"Your evil will chastise you, and your apostasy will reprove you. Know and see that it is evil and bitter for you to forsake the LORD your God; the fear of me is not in you, declares the Lord GOD of hosts.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":19},{"ref":"Jeremiah 2:20","short":"Jer 2:20","text":"“For long ago I broke your yoke and burst your bonds; but you said, ‘I will not serve.’ Yes, on every high hill and under every green tree you bowed down like a whore.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":20},{"ref":"Jeremiah 2:21","short":"Jer 2:21","text":"Yet I planted you a choice vine, wholly of pure seed. How then have you turned degenerate and become a wild vine?","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":21},{"ref":"Jeremiah 2:22","short":"Jer 2:22","text":"Though you wash yourself with lye and use much soap, the stain of your guilt is still before me, declares the Lord GOD.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":22},{"ref":"Jeremiah 2:23","short":"Jer 2:23","text":"How can you say, ‘I am not unclean, I have not gone after the Baals’? Look at your way in the valley; know what you have done— a restless young camel running here and there,","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":23},{"ref":"Jeremiah 2:24","short":"Jer 2:24","text":"a wild donkey used to the wilderness, in her heat sniffing the wind! Who can restrain her lust? None who seek her need weary themselves; in her month they will find her.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":24},{"ref":"Jeremiah 2:25","short":"Jer 2:25","text":"Keep your feet from going unshod and your throat from thirst. But you said, ‘It is hopeless, for I have loved foreigners, and after them I will go.’","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":25},{"ref":"Jeremiah 2:26","short":"Jer 2:26","text":"“As a thief is shamed when caught, so the house of Israel shall be shamed: they, their kings, their officials, their priests, and their prophets,","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":26},{"ref":"Jeremiah 2:27","short":"Jer 2:27","text":"who say to a tree, ‘You are my father,’ and to a stone, ‘You gave me birth.’ For they have turned their back to me, and not their face. But in the time of their trouble they say, ‘Arise and save us!’","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":27},{"ref":"Jeremiah 2:28","short":"Jer 2:28","text":"But where are your gods that you made for yourself? Let them arise, if they can save you, in your time of trouble; for as many as your cities are your gods, O Judah.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":28},{"ref":"Jeremiah 2:29","short":"Jer 2:29","text":"“Why do you contend with me? You have all transgressed against me, declares the LORD.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":29},{"ref":"Jeremiah 2:30","short":"Jer 2:30","text":"In vain have I struck your children; they took no correction; your own sword devoured your prophets like a ravening lion.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":30},{"ref":"Jeremiah 2:31","short":"Jer 2:31","text":"And you, O generation, behold the word of the LORD. Have I been a wilderness to Israel, or a land of thick darkness? Why then do my people say, ‘We are free, we will come no more to you’?","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":31},{"ref":"Jeremiah 2:32","short":"Jer 2:32","text":"Can a virgin forget her ornaments, or a bride her attire? Yet my people have forgotten me days without number.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":32},{"ref":"Jeremiah 2:33","short":"Jer 2:33","text":"“How well you direct your course to seek love! So that even to wicked women you have taught your ways.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":33},{"ref":"Jeremiah 2:34","short":"Jer 2:34","text":"Also on your skirts is found the lifeblood of the guiltless poor; you did not find them breaking in. Yet in spite of all these things","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":34},{"ref":"Jeremiah 2:35","short":"Jer 2:35","text":"you say, ‘I am innocent; surely his anger has turned from me.’ Behold, I will bring you to judgment for saying, ‘I have not sinned.’","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":35},{"ref":"Jeremiah 2:36","short":"Jer 2:36","text":"How much you go about, changing your way! You shall be put to shame by Egypt as you were put to shame by Assyria.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":36},{"ref":"Jeremiah 2:37","short":"Jer 2:37","text":"From it too you will come away with your hands on your head, for the LORD has rejected those in whom you trust, and you will not prosper by them.","url":"ot/jeremiah/Jeremiah_2.html","book":"Jeremiah","ch":2,"v":37},{"ref":"Jeremiah 3:1","short":"Jer 3:1","text":"“If a man divorces his wife and she goes from him and becomes another man’s wife, will he return to her? Would not that land be greatly polluted? You have played the whore with many lovers; and would you return to me? declares the LORD.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":1},{"ref":"Jeremiah 3:2","short":"Jer 3:2","text":"Lift up your eyes to the bare heights, and see! Where have you not been ravished? By the waysides you have sat awaiting lovers like an Arab in the wilderness. You have polluted the land with your vile whoredom.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":2},{"ref":"Jeremiah 3:3","short":"Jer 3:3","text":"Therefore the showers have been withheld, and the spring rain has not come; yet you have the forehead of a whore; you refuse to be ashamed.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":3},{"ref":"Jeremiah 3:4","short":"Jer 3:4","text":"Have you not just now called to me, ‘My father, you are the friend of my youth—","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":4},{"ref":"Jeremiah 3:5","short":"Jer 3:5","text":"will he be angry forever, will he be indignant to the end?’ Behold, you have spoken, but you have done all the evil that you could.”","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":5},{"ref":"Jeremiah 3:6","short":"Jer 3:6","text":"The LORD said to me in the days of King Josiah: “Have you seen what she did, that faithless one, Israel, how she went up on every high hill and under every green tree, and there played the whore?","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":6},{"ref":"Jeremiah 3:7","short":"Jer 3:7","text":"And I thought, ‘After she has done all this she will return to me,’ but she did not return, and her treacherous sister Judah saw it.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":7},{"ref":"Jeremiah 3:8","short":"Jer 3:8","text":"She saw that for all the adulteries of that faithless one, Israel, I had sent her away with a decree of divorce. Yet her treacherous sister Judah did not fear, but she too went and played the whore.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":8},{"ref":"Jeremiah 3:9","short":"Jer 3:9","text":"Because she took her whoredom lightly, she polluted the land, committing adultery with stone and tree.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":9},{"ref":"Jeremiah 3:10","short":"Jer 3:10","text":"Yet for all this her treacherous sister Judah did not return to me with her whole heart, but in pretense, declares the LORD.”","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":10},{"ref":"Jeremiah 3:11","short":"Jer 3:11","text":"And the LORD said to me, “Faithless Israel has shown herself more righteous than treacherous Judah.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":11},{"ref":"Jeremiah 3:12","short":"Jer 3:12","text":"Go, and proclaim these words toward the north, and say, “‘Return, faithless Israel, declares the LORD. I will not look on you in anger, for I am merciful, declares the LORD; I will not be angry forever.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":12},{"ref":"Jeremiah 3:13","short":"Jer 3:13","text":"Only acknowledge your guilt, that you rebelled against the LORD your God and scattered your favors among foreigners under every green tree, and that you have not obeyed my voice, declares the LORD.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":13},{"ref":"Jeremiah 3:14","short":"Jer 3:14","text":"Return, O faithless children, declares the LORD; for I am your master; I will take you, one from a city and two from a family, and I will bring you to Zion.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":14},{"ref":"Jeremiah 3:15","short":"Jer 3:15","text":"“‘And I will give you shepherds after my own heart, who will feed you with knowledge and understanding.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":15},{"ref":"Jeremiah 3:16","short":"Jer 3:16","text":"And when you have multiplied and been fruitful in the land, in those days, declares the LORD, they shall no more say, “The ark of the covenant of the LORD.” It shall not come to mind or be remembered or missed; it shall not be made again.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":16},{"ref":"Jeremiah 3:17","short":"Jer 3:17","text":"At that time Jerusalem shall be called the throne of the LORD, and all nations shall gather to it, to the presence of the LORD in Jerusalem, and they shall no more stubbornly follow their own evil heart.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":17},{"ref":"Jeremiah 3:18","short":"Jer 3:18","text":"In those days the house of Judah shall join the house of Israel, and together they shall come from the land of the north to the land that I gave your fathers for a heritage.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":18},{"ref":"Jeremiah 3:19","short":"Jer 3:19","text":"“‘I said, How I would set you among my sons, and give you a pleasant land, a heritage most beautiful of all nations. And I thought you would call me, My Father, and would not turn from following me.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":19},{"ref":"Jeremiah 3:20","short":"Jer 3:20","text":"Surely, as a treacherous wife leaves her husband, so have you been treacherous to me, O house of Israel, declares the LORD.’”","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":20},{"ref":"Jeremiah 3:21","short":"Jer 3:21","text":"A voice on the bare heights is heard, the weeping and pleading of Israel’s sons because they have perverted their way; they have forgotten the LORD their God.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":21},{"ref":"Jeremiah 3:22","short":"Jer 3:22","text":"“Return, O faithless sons; I will heal your faithlessness.” “Behold, we come to you, for you are the LORD our God.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":22},{"ref":"Jeremiah 3:23","short":"Jer 3:23","text":"Truly the hills are a delusion, the orgies on the mountains. Truly in the LORD our God is the salvation of Israel.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":23},{"ref":"Jeremiah 3:24","short":"Jer 3:24","text":"“But from our youth the shameful thing has devoured all for which our fathers labored, their flocks and their herds, their sons and their daughters.","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":24},{"ref":"Jeremiah 3:25","short":"Jer 3:25","text":"Let us lie down in our shame, and let our dishonor cover us. For we have sinned against the LORD our God, we and our fathers, from our youth even to this day, and we have not obeyed the voice of the LORD our God.”","url":"ot/jeremiah/Jeremiah_3.html","book":"Jeremiah","ch":3,"v":25},{"ref":"Jeremiah 4:1","short":"Jer 4:1","text":"“If you return, O Israel, declares the LORD, to me you should return. If you remove your detestable things from my presence, and do not waver,","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":1},{"ref":"Jeremiah 4:2","short":"Jer 4:2","text":"and if you swear, ‘As the LORD lives,’ in truth, in justice, and in righteousness, then nations shall bless themselves in him, and in him shall they glory.”","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":2},{"ref":"Jeremiah 4:3","short":"Jer 4:3","text":"For thus says the LORD to the men of Judah and Jerusalem: “Break up your fallow ground, and sow not among thorns.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":3},{"ref":"Jeremiah 4:4","short":"Jer 4:4","text":"Circumcise yourselves to the LORD; remove the foreskin of your hearts, O men of Judah and inhabitants of Jerusalem; lest my wrath go forth like fire, and burn with none to quench it, because of the evil of your deeds.”","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":4},{"ref":"Jeremiah 4:5","short":"Jer 4:5","text":"Declare in Judah, and proclaim in Jerusalem, and say, “Blow the trumpet through the land; cry aloud and say, ‘Assemble, and let us go into the fortified cities!’","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":5},{"ref":"Jeremiah 4:6","short":"Jer 4:6","text":"Raise a standard toward Zion, flee for safety, stay not, for I bring disaster from the north, and great destruction.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":6},{"ref":"Jeremiah 4:7","short":"Jer 4:7","text":"A lion has gone up from his thicket, a destroyer of nations has set out; he has gone out from his place to make your land a waste; your cities will be ruins without inhabitant.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":7},{"ref":"Jeremiah 4:8","short":"Jer 4:8","text":"For this put on sackcloth, lament and wail, for the fierce anger of the LORD has not turned back from us.”","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":8},{"ref":"Jeremiah 4:9","short":"Jer 4:9","text":"“In that day, declares the LORD, courage shall fail both king and officials. The priests shall be appalled and the prophets astounded.”","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":9},{"ref":"Jeremiah 4:10","short":"Jer 4:10","text":"Then I said, “Ah, Lord GOD, surely you have utterly deceived this people and Jerusalem, saying, ‘It shall be well with you,’ whereas the sword has reached their very life.”","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":10},{"ref":"Jeremiah 4:11","short":"Jer 4:11","text":"At that time it will be said to this people and to Jerusalem, “A hot wind from the bare heights in the desert toward the daughter of my people, not to winnow or cleanse,","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":11},{"ref":"Jeremiah 4:12","short":"Jer 4:12","text":"a wind too full for this comes for me. Now it is I who speak in judgment upon them.”","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":12},{"ref":"Jeremiah 4:13","short":"Jer 4:13","text":"Behold, he comes up like clouds; his chariots like the whirlwind; his horses are swifter than eagles— woe to us, for we are ruined!","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":13},{"ref":"Jeremiah 4:14","short":"Jer 4:14","text":"O Jerusalem, wash your heart from evil, that you may be saved. How long shall your wicked thoughts lodge within you?","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":14},{"ref":"Jeremiah 4:15","short":"Jer 4:15","text":"For a voice declares from Dan and proclaims trouble from Mount Ephraim.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":15},{"ref":"Jeremiah 4:16","short":"Jer 4:16","text":"Warn the nations that he is coming; announce to Jerusalem, “Besiegers come from a distant land; they shout against the cities of Judah.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":16},{"ref":"Jeremiah 4:17","short":"Jer 4:17","text":"Like keepers of a field are they against her all around, because she has rebelled against me, declares the LORD.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":17},{"ref":"Jeremiah 4:18","short":"Jer 4:18","text":"Your ways and your deeds have brought this upon you. This is your doom, and it is bitter; it has reached your very heart.”","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":18},{"ref":"Jeremiah 4:19","short":"Jer 4:19","text":"My anguish, my anguish! I writhe in pain! Oh the walls of my heart! My heart is beating wildly; I cannot keep silent, for I hear the sound of the trumpet, the alarm of war.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":19},{"ref":"Jeremiah 4:20","short":"Jer 4:20","text":"Crash follows hard on crash; the whole land is laid waste. Suddenly my tents are laid waste, my curtains in a moment.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":20},{"ref":"Jeremiah 4:21","short":"Jer 4:21","text":"How long must I see the standard and hear the sound of the trumpet?","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":21},{"ref":"Jeremiah 4:22","short":"Jer 4:22","text":"“For my people are foolish; they know me not; they are stupid children; they have no understanding. They are ‘wise’—in doing evil! But how to do good they know not.”","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":22},{"ref":"Jeremiah 4:23","short":"Jer 4:23","text":"I looked on the earth, and behold, it was without form and void; and to the heavens, and they had no light.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":23},{"ref":"Jeremiah 4:24","short":"Jer 4:24","text":"I looked on the mountains, and behold, they were quaking, and all the hills moved to and fro.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":24},{"ref":"Jeremiah 4:25","short":"Jer 4:25","text":"I looked, and behold, there was no man, and all the birds of the air had fled.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":25},{"ref":"Jeremiah 4:26","short":"Jer 4:26","text":"I looked, and behold, the fruitful land was a desert, and all its cities were laid in ruins before the LORD, before his fierce anger.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":26},{"ref":"Jeremiah 4:27","short":"Jer 4:27","text":"For thus says the LORD, “The whole land shall be a desolation; yet I will not make a full end.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":27},{"ref":"Jeremiah 4:28","short":"Jer 4:28","text":"“For this the earth shall mourn, and the heavens above be dark; for I have spoken; I have purposed; I have not relented, nor will I turn back.”","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":28},{"ref":"Jeremiah 4:29","short":"Jer 4:29","text":"At the noise of horseman and archer every city takes to flight; they enter thickets; they climb among rocks; all the cities are forsaken, and no man dwells in them.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":29},{"ref":"Jeremiah 4:30","short":"Jer 4:30","text":"And you, O desolate one, what do you mean that you dress in scarlet, that you adorn yourself with ornaments of gold, that you enlarge your eyes with paint? In vain you beautify yourself. Your lovers despise you; they seek your life.","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":30},{"ref":"Jeremiah 4:31","short":"Jer 4:31","text":"For I heard a cry as of a woman in labor, anguish as of one giving birth to her first child, the cry of the daughter of Zion gasping for breath, stretching out her hands, “Woe is me! I am fainting before murderers.”","url":"ot/jeremiah/Jeremiah_4.html","book":"Jeremiah","ch":4,"v":31},{"ref":"Jeremiah 5:1","short":"Jer 5:1","text":"Run to and fro through the streets of Jerusalem, look and take note! Search her squares to see if you can find a man, one who does justice and seeks truth, that I may pardon her.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":1},{"ref":"Jeremiah 5:2","short":"Jer 5:2","text":"Though they say, “As the LORD lives,” yet they swear falsely.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":2},{"ref":"Jeremiah 5:3","short":"Jer 5:3","text":"O LORD, do not your eyes look for truth? You have struck them down, but they felt no anguish; you have consumed them, but they refused to take correction. They have made their faces harder than rock; they have refused to repent.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":3},{"ref":"Jeremiah 5:4","short":"Jer 5:4","text":"Then I said, “These are only the poor; they have no sense; for they do not know the way of the LORD, the justice of their God.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":4},{"ref":"Jeremiah 5:5","short":"Jer 5:5","text":"I will go to the great and will speak to them, for they know the way of the LORD, the justice of their God.” But they all alike had broken the yoke; they had burst the bonds.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":5},{"ref":"Jeremiah 5:6","short":"Jer 5:6","text":"Therefore a lion from the forest shall strike them down; a wolf from the desert shall devastate them. A leopard is watching their cities; everyone who goes out of them shall be torn in pieces, because their transgressions are many, their apostasies are great.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":6},{"ref":"Jeremiah 5:7","short":"Jer 5:7","text":"“How can I pardon you? Your children have forsaken me and have sworn by those who are no gods. When I fed them to the full, they committed adultery and trooped to the houses of whores.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":7},{"ref":"Jeremiah 5:8","short":"Jer 5:8","text":"They were well-fed, lusty stallions, each neighing for his neighbor’s wife.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":8},{"ref":"Jeremiah 5:9","short":"Jer 5:9","text":"Shall I not punish them for these things? declares the LORD; and shall I not avenge myself on a nation such as this?","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":9},{"ref":"Jeremiah 5:10","short":"Jer 5:10","text":"“Go up through her vine rows and destroy, but make not a full end; strip away her branches, for they are not the LORD’s.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":10},{"ref":"Jeremiah 5:11","short":"Jer 5:11","text":"For the house of Israel and the house of Judah have been utterly treacherous to me, declares the LORD.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":11},{"ref":"Jeremiah 5:12","short":"Jer 5:12","text":"They have spoken falsely of the LORD and have said, ‘He will do nothing; no disaster will come upon us, nor shall we see sword or famine.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":12},{"ref":"Jeremiah 5:13","short":"Jer 5:13","text":"The prophets will become wind; the word is not in them. Thus shall it be done to them!’”","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":13},{"ref":"Jeremiah 5:14","short":"Jer 5:14","text":"Therefore thus says the LORD, the God of hosts: “Because you have spoken this word, behold, I am making my words in your mouth a fire, and this people wood, and the fire shall consume them.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":14},{"ref":"Jeremiah 5:15","short":"Jer 5:15","text":"Behold, I am bringing against you a nation from afar, O house of Israel, declares the LORD. It is an enduring nation; it is an ancient nation, a nation whose language you do not know, nor can you understand what they say.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":15},{"ref":"Jeremiah 5:16","short":"Jer 5:16","text":"Their quiver is like an open tomb; they are all mighty warriors.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":16},{"ref":"Jeremiah 5:17","short":"Jer 5:17","text":"They shall eat up your harvest and your food; they shall eat up your sons and your daughters; they shall eat up your flocks and your herds; they shall eat up your vines and your fig trees; your fortified cities in which you trust they shall beat down with the sword.”","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":17},{"ref":"Jeremiah 5:18","short":"Jer 5:18","text":"“But even in those days, declares the LORD, I will not make a full end of you.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":18},{"ref":"Jeremiah 5:19","short":"Jer 5:19","text":"And when your people say, ‘Why has the LORD our God done all these things to us?’ you shall say to them, ‘As you have forsaken me and served foreign gods in your land, so you shall serve foreigners in a land that is not yours.’”","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":19},{"ref":"Jeremiah 5:20","short":"Jer 5:20","text":"Declare this in the house of Jacob; proclaim it in Judah:","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":20},{"ref":"Jeremiah 5:21","short":"Jer 5:21","text":"“Hear this, O foolish and senseless people, who have eyes, but see not, who have ears, but hear not.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":21},{"ref":"Jeremiah 5:22","short":"Jer 5:22","text":"Do you not fear me? declares the LORD. Do you not tremble before me? I placed the sand as the boundary for the sea, a perpetual barrier that it cannot pass; though the waves toss, they cannot prevail; though they roar, they cannot pass over it.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":22},{"ref":"Jeremiah 5:23","short":"Jer 5:23","text":"But this people has a stubborn and rebellious heart; they have turned aside and gone away.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":23},{"ref":"Jeremiah 5:24","short":"Jer 5:24","text":"They do not say in their hearts, ‘Let us fear the LORD our God, who gives the rain in its season, the autumn rain and the spring rain, and keeps for us the weeks appointed for the harvest.’","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":24},{"ref":"Jeremiah 5:25","short":"Jer 5:25","text":"Your iniquities have turned these away, and your sins have kept good from you.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":25},{"ref":"Jeremiah 5:26","short":"Jer 5:26","text":"For wicked men are found among my people; they lurk like fowlers lying in wait. They set a trap; they catch men.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":26},{"ref":"Jeremiah 5:27","short":"Jer 5:27","text":"Like a cage full of birds, their houses are full of deceit; therefore they have become great and rich;","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":27},{"ref":"Jeremiah 5:28","short":"Jer 5:28","text":"they have grown fat and sleek. They know no bounds in deeds of evil; they judge not with justice the cause of the fatherless, to make it prosper, and they do not defend the rights of the needy.","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":28},{"ref":"Jeremiah 5:29","short":"Jer 5:29","text":"Shall I not punish them for these things? declares the LORD, and shall I not avenge myself on a nation such as this?”","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":29},{"ref":"Jeremiah 5:30","short":"Jer 5:30","text":"An appalling and horrible thing has happened in the land:","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":30},{"ref":"Jeremiah 5:31","short":"Jer 5:31","text":"the prophets prophesy falsely, and the priests rule at their direction; my people love to have it so, but what will you do when the end comes?","url":"ot/jeremiah/Jeremiah_5.html","book":"Jeremiah","ch":5,"v":31},{"ref":"Jeremiah 6:1","short":"Jer 6:1","text":"Flee for safety, O people of Benjamin, from the midst of Jerusalem! Blow the trumpet in Tekoa, and raise a signal on Beth-haccherem, for disaster looms out of the north, and great destruction.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":1},{"ref":"Jeremiah 6:2","short":"Jer 6:2","text":"The lovely and delicately bred I will destroy, the daughter of Zion.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":2},{"ref":"Jeremiah 6:3","short":"Jer 6:3","text":"Shepherds with their flocks shall come against her; they shall pitch their tents around her; they shall pasture, each in his place.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":3},{"ref":"Jeremiah 6:4","short":"Jer 6:4","text":"“Prepare war against her; arise, and let us attack at noon! Woe to us, for the day declines, for the shadows of evening lengthen!","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":4},{"ref":"Jeremiah 6:5","short":"Jer 6:5","text":"Arise, and let us attack by night and destroy her palaces!”","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":5},{"ref":"Jeremiah 6:6","short":"Jer 6:6","text":"For thus says the LORD of hosts: “Cut down her trees; cast up a siege mound against Jerusalem. This is the city that must be punished; there is nothing but oppression within her.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":6},{"ref":"Jeremiah 6:7","short":"Jer 6:7","text":"As a well keeps its water fresh, so she keeps fresh her evil; violence and destruction are heard within her; sickness and wounds are ever before me.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":7},{"ref":"Jeremiah 6:8","short":"Jer 6:8","text":"Be warned, O Jerusalem, lest I turn from you in disgust, lest I make you a desolation, an uninhabited land.”","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":8},{"ref":"Jeremiah 6:9","short":"Jer 6:9","text":"Thus says the LORD of hosts: “They shall glean thoroughly as a vine the remnant of Israel; like a grape gatherer pass your hand again over its branches.”","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":9},{"ref":"Jeremiah 6:10","short":"Jer 6:10","text":"To whom shall I speak and give warning, that they may hear? Behold, their ears are uncircumcised, they cannot listen; behold, the word of the LORD is to them an object of scorn; they take no pleasure in it.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":10},{"ref":"Jeremiah 6:11","short":"Jer 6:11","text":"Therefore I am full of the wrath of the LORD; I am weary of holding it in. “Pour it out upon the children in the street, and upon the gatherings of young men, also; both husband and wife shall be taken, the elderly and the very aged.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":11},{"ref":"Jeremiah 6:12","short":"Jer 6:12","text":"Their houses shall be turned over to others, their fields and wives together, for I will stretch out my hand against the inhabitants of the land,” declares the LORD.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":12},{"ref":"Jeremiah 6:13","short":"Jer 6:13","text":"“For from the least to the greatest of them, everyone is greedy for unjust gain; and from prophet to priest, everyone deals falsely.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":13},{"ref":"Jeremiah 6:14","short":"Jer 6:14","text":"They have healed the wound of my people lightly, saying, ‘Peace, peace,’ when there is no peace.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":14},{"ref":"Jeremiah 6:15","short":"Jer 6:15","text":"Were they ashamed when they committed abomination? No, they were not at all ashamed; they did not know how to blush. Therefore they shall fall among those who fall; at the time that I punish them, they shall be overthrown,” says the LORD.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":15},{"ref":"Jeremiah 6:16","short":"Jer 6:16","text":"Thus says the LORD: “Stand by the roads, and look, and ask for the ancient paths, where the good way is; and walk in it, and find rest for your souls. But they said, ‘We will not walk in it.’","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":16},{"ref":"Jeremiah 6:17","short":"Jer 6:17","text":"I set watchmen over you, saying, ‘Pay attention to the sound of the trumpet!’ But they said, ‘We will not pay attention.’","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":17},{"ref":"Jeremiah 6:18","short":"Jer 6:18","text":"Therefore hear, O nations, and know, O congregation, what will happen to them.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":18},{"ref":"Jeremiah 6:19","short":"Jer 6:19","text":"Hear, O earth; behold, I am bringing disaster upon this people, the fruit of their devices, because they have not paid attention to my words; and as for my law, they have rejected it.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":19},{"ref":"Jeremiah 6:20","short":"Jer 6:20","text":"What use to me is frankincense that comes from Sheba, or sweet cane from a distant land? Your burnt offerings are not acceptable, nor your sacrifices pleasing to me.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":20},{"ref":"Jeremiah 6:21","short":"Jer 6:21","text":"Therefore thus says the LORD: ‘Behold, I will lay before this people stumbling blocks against which they shall stumble; fathers and sons together, neighbor and friend shall perish.’”","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":21},{"ref":"Jeremiah 6:22","short":"Jer 6:22","text":"Thus says the LORD: “Behold, a people is coming from the north country, a great nation is stirring from the farthest parts of the earth.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":22},{"ref":"Jeremiah 6:23","short":"Jer 6:23","text":"They lay hold on bow and javelin; they are cruel and have no mercy; the sound of them is like the roaring sea; they ride on horses, set in array as a man for battle, against you, O daughter of Zion!”","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":23},{"ref":"Jeremiah 6:24","short":"Jer 6:24","text":"We have heard the report of it; our hands fall helpless; anguish has taken hold of us, pain as of a woman in labor.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":24},{"ref":"Jeremiah 6:25","short":"Jer 6:25","text":"Go not out into the field, nor walk on the road, for the enemy has a sword; terror is on every side.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":25},{"ref":"Jeremiah 6:26","short":"Jer 6:26","text":"O daughter of my people, put on sackcloth, and roll in ashes; make mourning as for an only son, most bitter lamentation, for suddenly the destroyer will come upon us.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":26},{"ref":"Jeremiah 6:27","short":"Jer 6:27","text":"“I have made you a tester of metals among my people, that you may know and test their ways.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":27},{"ref":"Jeremiah 6:28","short":"Jer 6:28","text":"They are all stubbornly rebellious, going about with slanders; they are bronze and iron; all of them act corruptly.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":28},{"ref":"Jeremiah 6:29","short":"Jer 6:29","text":"The bellows blow fiercely; the lead is consumed by the fire; in vain the refining goes on, for the wicked are not removed.","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":29},{"ref":"Jeremiah 6:30","short":"Jer 6:30","text":"Rejected silver they are called, for the LORD has rejected them.”","url":"ot/jeremiah/Jeremiah_6.html","book":"Jeremiah","ch":6,"v":30},{"ref":"Jeremiah 7:1","short":"Jer 7:1","text":"The word that came to Jeremiah from the LORD:","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":1},{"ref":"Jeremiah 7:2","short":"Jer 7:2","text":"“Stand in the gate of the LORD’s house, and proclaim there this word, and say, Hear the word of the LORD, all you men of Judah who enter these gates to worship the LORD.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":2},{"ref":"Jeremiah 7:3","short":"Jer 7:3","text":"Thus says the LORD of hosts, the God of Israel: Amend your ways and your deeds, and I will let you dwell in this place.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":3},{"ref":"Jeremiah 7:4","short":"Jer 7:4","text":"Do not trust in these deceptive words: ‘This is the temple of the LORD, the temple of the LORD, the temple of the LORD.’","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":4},{"ref":"Jeremiah 7:5","short":"Jer 7:5","text":"“For if you truly amend your ways and your deeds, if you truly execute justice one with another,","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":5},{"ref":"Jeremiah 7:6","short":"Jer 7:6","text":"if you do not oppress the sojourner, the fatherless, or the widow, or shed innocent blood in this place, and if you do not go after other gods to your own harm,","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":6},{"ref":"Jeremiah 7:7","short":"Jer 7:7","text":"then I will let you dwell in this place, in the land that I gave of old to your fathers forever.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":7},{"ref":"Jeremiah 7:8","short":"Jer 7:8","text":"“Behold, you trust in deceptive words to no avail.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":8},{"ref":"Jeremiah 7:9","short":"Jer 7:9","text":"Will you steal, murder, commit adultery, swear falsely, make offerings to Baal, and go after other gods that you have not known,","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":9},{"ref":"Jeremiah 7:10","short":"Jer 7:10","text":"and then come and stand before me in this house, which is called by my name, and say, ‘We are delivered!’—only to go on doing all these abominations?","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":10},{"ref":"Jeremiah 7:11","short":"Jer 7:11","text":"Has this house, which is called by my name, become a den of robbers in your eyes? Behold, I myself have seen it, declares the LORD.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":11},{"ref":"Jeremiah 7:12","short":"Jer 7:12","text":"Go now to my place that was in Shiloh, where I made my name dwell at first, and see what I did to it because of the evil of my people Israel.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":12},{"ref":"Jeremiah 7:13","short":"Jer 7:13","text":"And now, because you have done all these things, declares the LORD, and when I spoke to you persistently you did not listen, and when I called you, you did not answer,","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":13},{"ref":"Jeremiah 7:14","short":"Jer 7:14","text":"therefore I will do to the house that is called by my name, and in which you trust, and to the place that I gave to you and to your fathers, as I did to Shiloh.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":14},{"ref":"Jeremiah 7:15","short":"Jer 7:15","text":"And I will cast you out of my sight, as I cast out all your kinsmen, all the offspring of Ephraim.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":15},{"ref":"Jeremiah 7:16","short":"Jer 7:16","text":"“As for you, do not pray for this people, or lift up a cry or prayer for them, and do not intercede with me, for I will not hear you.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":16},{"ref":"Jeremiah 7:17","short":"Jer 7:17","text":"Do you not see what they are doing in the cities of Judah and in the streets of Jerusalem?","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":17},{"ref":"Jeremiah 7:18","short":"Jer 7:18","text":"The children gather wood, the fathers kindle fire, and the women knead dough, to make cakes for the queen of heaven. And they pour out drink offerings to other gods, to provoke me to anger.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":18},{"ref":"Jeremiah 7:19","short":"Jer 7:19","text":"Is it I whom they provoke? declares the LORD. Is it not themselves, to their own shame?","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":19},{"ref":"Jeremiah 7:20","short":"Jer 7:20","text":"Therefore thus says the Lord GOD: Behold, my anger and my wrath will be poured out on this place, upon man and beast, upon the trees of the field and the fruit of the ground; it will burn and not be quenched.”","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":20},{"ref":"Jeremiah 7:21","short":"Jer 7:21","text":"Thus says the LORD of hosts, the God of Israel: “Add your burnt offerings to your sacrifices, and eat the flesh.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":21},{"ref":"Jeremiah 7:22","short":"Jer 7:22","text":"For in the day that I brought them out of the land of Egypt, I did not speak to your fathers or command them concerning burnt offerings and sacrifices.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":22},{"ref":"Jeremiah 7:23","short":"Jer 7:23","text":"But this command I gave them: ‘Obey my voice, and I will be your God, and you shall be my people. And walk in all the way that I command you, that it may be well with you.’","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":23},{"ref":"Jeremiah 7:24","short":"Jer 7:24","text":"But they did not obey or incline their ear, but walked in their own counsels and the stubbornness of their evil hearts, and went backward and not forward.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":24},{"ref":"Jeremiah 7:25","short":"Jer 7:25","text":"From the day that your fathers came out of the land of Egypt to this day, I have persistently sent all my servants the prophets to them, day after day.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":25},{"ref":"Jeremiah 7:26","short":"Jer 7:26","text":"Yet they did not listen to me or incline their ear, but stiffened their neck. They did worse than their fathers.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":26},{"ref":"Jeremiah 7:27","short":"Jer 7:27","text":"“So you shall speak all these words to them, but they will not listen to you. You shall call to them, but they will not answer you.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":27},{"ref":"Jeremiah 7:28","short":"Jer 7:28","text":"And you shall say to them, ‘This is the nation that did not obey the voice of the LORD their God, and did not accept discipline; truth has perished; it is cut off from their lips.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":28},{"ref":"Jeremiah 7:29","short":"Jer 7:29","text":"“‘Cut off your hair and cast it away; raise a lamentation on the bare heights, for the LORD has rejected and forsaken the generation of his wrath.’","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":29},{"ref":"Jeremiah 7:30","short":"Jer 7:30","text":"“For the sons of Judah have done evil in my sight, declares the LORD. They have set their detestable things in the house that is called by my name, to defile it.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":30},{"ref":"Jeremiah 7:31","short":"Jer 7:31","text":"And they have built the high places of Topheth, which is in the Valley of the Son of Hinnom, to burn their sons and their daughters in the fire, which I did not command, nor did it come into my mind.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":31},{"ref":"Jeremiah 7:32","short":"Jer 7:32","text":"Therefore, behold, the days are coming, declares the LORD, when it will no more be called Topheth, or the Valley of the Son of Hinnom, but the Valley of Slaughter; for they will bury in Topheth, because there is no room elsewhere.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":32},{"ref":"Jeremiah 7:33","short":"Jer 7:33","text":"And the dead bodies of this people will be food for the birds of the air, and for the beasts of the earth, and none will frighten them away.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":33},{"ref":"Jeremiah 7:34","short":"Jer 7:34","text":"And I will silence in the cities of Judah and in the streets of Jerusalem the voice of mirth and the voice of gladness, the voice of the bridegroom and the voice of the bride, for the land shall become a waste.","url":"ot/jeremiah/Jeremiah_7.html","book":"Jeremiah","ch":7,"v":34},{"ref":"Jeremiah 8:1","short":"Jer 8:1","text":"“At that time, declares the LORD, the bones of the kings of Judah, the bones of its officials, the bones of the priests, the bones of the prophets, and the bones of the inhabitants of Jerusalem shall be brought out of their tombs.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":1},{"ref":"Jeremiah 8:2","short":"Jer 8:2","text":"And they shall be spread before the sun and the moon and all the host of heaven, which they have loved and served, which they have gone after, and which they have sought and worshiped. And they shall not be gathered or buried. They shall be as dung on the surface of the ground.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":2},{"ref":"Jeremiah 8:3","short":"Jer 8:3","text":"Death shall be preferred to life by all the remnant that remains of this evil family in all the places where I have driven them, declares the LORD of hosts.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":3},{"ref":"Jeremiah 8:4","short":"Jer 8:4","text":"“You shall say to them, Thus says the LORD: When men fall, do they not rise again? If one turns away, does he not return?","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":4},{"ref":"Jeremiah 8:5","short":"Jer 8:5","text":"Why then has this people turned away in perpetual backsliding? They hold fast to deceit; they refuse to return.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":5},{"ref":"Jeremiah 8:6","short":"Jer 8:6","text":"I have paid attention and listened, but they have not spoken rightly; no man relents of his evil, saying, ‘What have I done?’ Everyone turns to his own course, like a horse plunging headlong into battle.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":6},{"ref":"Jeremiah 8:7","short":"Jer 8:7","text":"Even the stork in the heavens knows her times, and the turtledove, swallow, and crane keep the time of their coming, but my people know not the rules of the LORD.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":7},{"ref":"Jeremiah 8:8","short":"Jer 8:8","text":"“How can you say, ‘We are wise, and the law of the LORD is with us’? But behold, the lying pen of the scribes has made it into a lie.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":8},{"ref":"Jeremiah 8:9","short":"Jer 8:9","text":"The wise men shall be put to shame; they shall be dismayed and taken; behold, they have rejected the word of the LORD, so what wisdom is in them?","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":9},{"ref":"Jeremiah 8:10","short":"Jer 8:10","text":"Therefore I will give their wives to others and their fields to conquerors, because from the least to the greatest everyone is greedy for unjust gain; from prophet to priest, everyone deals falsely.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":10},{"ref":"Jeremiah 8:11","short":"Jer 8:11","text":"They have healed the wound of my people lightly, saying, ‘Peace, peace,’ when there is no peace.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":11},{"ref":"Jeremiah 8:12","short":"Jer 8:12","text":"Were they ashamed when they committed abomination? No, they were not at all ashamed; they did not know how to blush. Therefore they shall fall among the fallen; when I punish them, they shall be overthrown, says the LORD.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":12},{"ref":"Jeremiah 8:13","short":"Jer 8:13","text":"When I would gather them, declares the LORD, there are no grapes on the vine, nor figs on the fig tree; even the leaves are withered, and what I gave them has passed away from them.”","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":13},{"ref":"Jeremiah 8:14","short":"Jer 8:14","text":"Why do we sit still? Gather together; let us go into the fortified cities and perish there, for the LORD our God has doomed us to perish and has given us poisoned water to drink, because we have sinned against the LORD.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":14},{"ref":"Jeremiah 8:15","short":"Jer 8:15","text":"We looked for peace, but no good came; for a time of healing, but behold, terror.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":15},{"ref":"Jeremiah 8:16","short":"Jer 8:16","text":"“The snorting of their horses is heard from Dan; at the sound of the neighing of their stallions the whole land quakes. They come and devour the land and all that fills it, the city and those who dwell in it.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":16},{"ref":"Jeremiah 8:17","short":"Jer 8:17","text":"For behold, I am sending among you serpents, adders that cannot be charmed, and they shall bite you,” declares the LORD.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":17},{"ref":"Jeremiah 8:18","short":"Jer 8:18","text":"My joy is gone; grief is upon me; my heart is sick within me.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":18},{"ref":"Jeremiah 8:19","short":"Jer 8:19","text":"Behold, the cry of the daughter of my people from the length and breadth of the land: “Is the LORD not in Zion? Is her King not in her?” “Why have they provoked me to anger with their carved images and with their foreign idols?”","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":19},{"ref":"Jeremiah 8:20","short":"Jer 8:20","text":"“The harvest is past, the summer is ended, and we are not saved.”","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":20},{"ref":"Jeremiah 8:21","short":"Jer 8:21","text":"For the wound of the daughter of my people is my heart wounded; I mourn, and dismay has taken hold on me.","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":21},{"ref":"Jeremiah 8:22","short":"Jer 8:22","text":"Is there no balm in Gilead? Is there no physician there? Why then has the health of the daughter of my people not been restored?","url":"ot/jeremiah/Jeremiah_8.html","book":"Jeremiah","ch":8,"v":22},{"ref":"Jeremiah 9:1","short":"Jer 9:1","text":"Oh that my head were waters, and my eyes a fountain of tears, that I might weep day and night for the slain of the daughter of my people!","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":1},{"ref":"Jeremiah 9:2","short":"Jer 9:2","text":"Oh that I had in the desert a travelers’ lodging place, that I might leave my people and go away from them! For they are all adulterers, a company of treacherous men.","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":2},{"ref":"Jeremiah 9:3","short":"Jer 9:3","text":"They bend their tongue like a bow; falsehood and not truth has grown strong in the land; for they proceed from evil to evil, and they do not know me, declares the LORD.","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":3},{"ref":"Jeremiah 9:4","short":"Jer 9:4","text":"Let everyone beware of his neighbor, and put no trust in any brother, for every brother is a deceiver, and every neighbor goes about as a slanderer.","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":4},{"ref":"Jeremiah 9:5","short":"Jer 9:5","text":"Everyone deceives his neighbor, and no one speaks the truth; they have taught their tongue to speak lies; they weary themselves committing iniquity.","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":5},{"ref":"Jeremiah 9:6","short":"Jer 9:6","text":"Heaping oppression upon oppression, and deceit upon deceit, they refuse to know me, declares the LORD.","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":6},{"ref":"Jeremiah 9:7","short":"Jer 9:7","text":"Therefore thus says the LORD of hosts: “Behold, I will refine them and test them, for what else can I do, because of my people?","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":7},{"ref":"Jeremiah 9:8","short":"Jer 9:8","text":"Their tongue is a deadly arrow; it speaks deceitfully; with his mouth each speaks peace to his neighbor, but in his heart he plans an ambush for him.","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":8},{"ref":"Jeremiah 9:9","short":"Jer 9:9","text":"Shall I not punish them for these things? declares the LORD, and shall I not avenge myself on a nation such as this?","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":9},{"ref":"Jeremiah 9:10","short":"Jer 9:10","text":"“I will take up weeping and wailing for the mountains, and a lamentation for the pastures of the wilderness, because they are laid waste so that no one passes through, and the lowing of cattle is not heard; both the birds of the air and the beasts have fled and are gone.","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":10},{"ref":"Jeremiah 9:11","short":"Jer 9:11","text":"I will make Jerusalem a heap of ruins, a lair of jackals, and I will make the cities of Judah a desolation, without inhabitant.”","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":11},{"ref":"Jeremiah 9:12","short":"Jer 9:12","text":"Who is the man so wise that he can understand this? To whom has the mouth of the LORD spoken, that he may declare it? Why is the land ruined and laid waste like a wilderness, so that no one passes through?","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":12},{"ref":"Jeremiah 9:13","short":"Jer 9:13","text":"And the LORD says: “Because they have forsaken my law that I set before them, and have not obeyed my voice or walked in accord with it,","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":13},{"ref":"Jeremiah 9:14","short":"Jer 9:14","text":"but have stubbornly followed their own hearts and have gone after the Baals, as their fathers taught them.","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":14},{"ref":"Jeremiah 9:15","short":"Jer 9:15","text":"Therefore thus says the LORD of hosts, the God of Israel: Behold, I will feed this people with bitter food, and give them poisonous water to drink.","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":15},{"ref":"Jeremiah 9:16","short":"Jer 9:16","text":"I will scatter them among the nations whom neither they nor their fathers have known, and I will send the sword after them, until I have consumed them.”","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":16},{"ref":"Jeremiah 9:17","short":"Jer 9:17","text":"Thus says the LORD of hosts: “Consider, and call for the mourning women to come; send for the skillful women to come;","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":17},{"ref":"Jeremiah 9:18","short":"Jer 9:18","text":"let them make haste and raise a wailing over us, that our eyes may run down with tears and our eyelids flow with water.","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":18},{"ref":"Jeremiah 9:19","short":"Jer 9:19","text":"For a sound of wailing is heard from Zion: ‘How we are ruined! We are utterly shamed, because we have left the land, because they have cast down our dwellings.’”","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":19},{"ref":"Jeremiah 9:20","short":"Jer 9:20","text":"Hear, O women, the word of the LORD, and let your ear receive the word of his mouth; teach to your daughters a lament, and each to her neighbor a dirge.","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":20},{"ref":"Jeremiah 9:21","short":"Jer 9:21","text":"For death has come up into our windows; it has entered our palaces, cutting off the children from the streets and the young men from the squares.","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":21},{"ref":"Jeremiah 9:22","short":"Jer 9:22","text":"Speak: “Thus declares the LORD, ‘The dead bodies of men shall fall like dung upon the open field, like sheaves after the reaper, and none shall gather them.’”","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":22},{"ref":"Jeremiah 9:23","short":"Jer 9:23","text":"Thus says the LORD: “Let not the wise man boast in his wisdom, let not the mighty man boast in his might, let not the rich man boast in his riches,","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":23},{"ref":"Jeremiah 9:24","short":"Jer 9:24","text":"but let him who boasts boast in this, that he understands and knows me, that I am the LORD who practices steadfast love, justice, and righteousness in the earth. For in these things I delight, declares the LORD.”","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":24},{"ref":"Jeremiah 9:25","short":"Jer 9:25","text":"“Behold, the days are coming, declares the LORD, when I will punish all those who are circumcised merely in the flesh—","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":25},{"ref":"Jeremiah 9:26","short":"Jer 9:26","text":"Egypt, Judah, Edom, the sons of Ammon, Moab, and all who dwell in the desert who cut the corners of their hair, for all these nations are uncircumcised, and all the house of Israel are uncircumcised in heart.”","url":"ot/jeremiah/Jeremiah_9.html","book":"Jeremiah","ch":9,"v":26},{"ref":"Jeremiah 10:1","short":"Jer 10:1","text":"Hear the word that the LORD speaks to you, O house of Israel.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":1},{"ref":"Jeremiah 10:2","short":"Jer 10:2","text":"Thus says the LORD: “Learn not the way of the nations, nor be dismayed at the signs of the heavens because the nations are dismayed at them,","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":2},{"ref":"Jeremiah 10:3","short":"Jer 10:3","text":"for the customs of the peoples are vanity. A tree from the forest is cut down and worked with an axe by the hands of a craftsman.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":3},{"ref":"Jeremiah 10:4","short":"Jer 10:4","text":"They decorate it with silver and gold; they fasten it with hammer and nails so that it cannot move.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":4},{"ref":"Jeremiah 10:5","short":"Jer 10:5","text":"Their idols are like scarecrows in a cucumber field, and they cannot speak; they have to be carried, for they cannot walk. Do not be afraid of them, for they cannot do evil, neither is it in them to do good.”","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":5},{"ref":"Jeremiah 10:6","short":"Jer 10:6","text":"There is none like you, O LORD; you are great, and your name is great in might.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":6},{"ref":"Jeremiah 10:7","short":"Jer 10:7","text":"Who would not fear you, O King of the nations? For this is your due; for among all the wise ones of the nations and in all their kingdoms there is none like you.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":7},{"ref":"Jeremiah 10:8","short":"Jer 10:8","text":"They are both stupid and foolish; the instruction of idols is but wood!","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":8},{"ref":"Jeremiah 10:9","short":"Jer 10:9","text":"Beaten silver is brought from Tarshish, and gold from Uphaz. They are the work of the craftsman and of the hands of the goldsmith; their clothing is violet and purple; they are all the work of skilled men.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":9},{"ref":"Jeremiah 10:10","short":"Jer 10:10","text":"But the LORD is the true God; he is the living God and the everlasting King. At his wrath the earth quakes, and the nations cannot endure his indignation.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":10},{"ref":"Jeremiah 10:11","short":"Jer 10:11","text":"Thus shall you say to them: “The gods who did not make the heavens and the earth shall perish from the earth and from under the heavens.”","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":11},{"ref":"Jeremiah 10:12","short":"Jer 10:12","text":"It is he who made the earth by his power, who established the world by his wisdom, and by his understanding stretched out the heavens.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":12},{"ref":"Jeremiah 10:13","short":"Jer 10:13","text":"When he utters his voice, there is a tumult of waters in the heavens, and he makes the mist rise from the ends of the earth. He makes lightning for the rain, and he brings forth the wind from his storehouses.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":13},{"ref":"Jeremiah 10:14","short":"Jer 10:14","text":"Every man is stupid and without knowledge; every goldsmith is put to shame by his idols, for his images are false, and there is no breath in them.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":14},{"ref":"Jeremiah 10:15","short":"Jer 10:15","text":"They are worthless, a work of delusion; at the time of their punishment they shall perish.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":15},{"ref":"Jeremiah 10:16","short":"Jer 10:16","text":"Not like these is he who is the portion of Jacob, for he is the one who formed all things, and Israel is the tribe of his inheritance; the LORD of hosts is his name.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":16},{"ref":"Jeremiah 10:17","short":"Jer 10:17","text":"Gather up your bundle from the ground, O you who dwell under siege!","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":17},{"ref":"Jeremiah 10:18","short":"Jer 10:18","text":"For thus says the LORD: “Behold, I am slinging out the inhabitants of the land at this time, and I will bring distress on them, that they may feel it.”","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":18},{"ref":"Jeremiah 10:19","short":"Jer 10:19","text":"Woe is me because of my hurt! My wound is grievous. But I said, “Truly this is an affliction, and I must bear it.”","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":19},{"ref":"Jeremiah 10:20","short":"Jer 10:20","text":"My tent is destroyed, and all my cords are broken; my children have gone from me, and they are not; there is no one to spread my tent again and to set up my curtains.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":20},{"ref":"Jeremiah 10:21","short":"Jer 10:21","text":"For the shepherds are stupid and do not inquire of the LORD; therefore they have not prospered, and all their flock is scattered.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":21},{"ref":"Jeremiah 10:22","short":"Jer 10:22","text":"A voice, a rumor! Behold, it comes!— a great commotion out of the north country to make the cities of Judah a desolation, a lair of jackals.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":22},{"ref":"Jeremiah 10:23","short":"Jer 10:23","text":"I know, O LORD, that the way of man is not in himself, that it is not in man who walks to direct his steps.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":23},{"ref":"Jeremiah 10:24","short":"Jer 10:24","text":"Correct me, O LORD, but in justice; not in your anger, lest you bring me to nothing.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":24},{"ref":"Jeremiah 10:25","short":"Jer 10:25","text":"Pour out your wrath on the nations that know you not, and on the peoples that call not on your name, for they have devoured Jacob; they have devoured him and consumed him, and have laid waste his habitation.","url":"ot/jeremiah/Jeremiah_10.html","book":"Jeremiah","ch":10,"v":25},{"ref":"Jeremiah 11:1","short":"Jer 11:1","text":"The word that came to Jeremiah from the LORD:","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":1},{"ref":"Jeremiah 11:2","short":"Jer 11:2","text":"“Hear the words of this covenant, and speak to the men of Judah and the inhabitants of Jerusalem.","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":2},{"ref":"Jeremiah 11:3","short":"Jer 11:3","text":"You shall say to them, Thus says the LORD, the God of Israel: Cursed be the man who does not hear the words of this covenant","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":3},{"ref":"Jeremiah 11:4","short":"Jer 11:4","text":"that I commanded your fathers when I brought them out of the land of Egypt, from the iron furnace, saying, Listen to my voice, and do all that I command you. So shall you be my people, and I will be your God,","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":4},{"ref":"Jeremiah 11:5","short":"Jer 11:5","text":"that I may confirm the oath that I swore to your fathers, to give them a land flowing with milk and honey, as at this day.” Then I answered, “So be it, LORD.”","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":5},{"ref":"Jeremiah 11:6","short":"Jer 11:6","text":"And the LORD said to me, “Proclaim all these words in the cities of Judah and in the streets of Jerusalem: Hear the words of this covenant and do them.","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":6},{"ref":"Jeremiah 11:7","short":"Jer 11:7","text":"For I solemnly warned your fathers when I brought them up out of the land of Egypt, warning them persistently, even to this day, saying, Obey my voice.","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":7},{"ref":"Jeremiah 11:8","short":"Jer 11:8","text":"Yet they did not obey or incline their ear, but everyone walked in the stubbornness of his evil heart. Therefore I brought upon them all the words of this covenant, which I commanded them to do, but they did not.”","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":8},{"ref":"Jeremiah 11:9","short":"Jer 11:9","text":"Again the LORD said to me, “A conspiracy exists among the men of Judah and the inhabitants of Jerusalem.","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":9},{"ref":"Jeremiah 11:10","short":"Jer 11:10","text":"They have turned back to the iniquities of their forefathers, who refused to hear my words. They have gone after other gods to serve them. The house of Israel and the house of Judah have broken my covenant that I made with their fathers.","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":10},{"ref":"Jeremiah 11:11","short":"Jer 11:11","text":"Therefore, thus says the LORD, Behold, I am bringing disaster upon them that they cannot escape. Though they cry to me, I will not listen to them.","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":11},{"ref":"Jeremiah 11:12","short":"Jer 11:12","text":"Then the cities of Judah and the inhabitants of Jerusalem will go and cry to the gods to whom they make offerings, but they cannot save them in the time of their trouble.","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":12},{"ref":"Jeremiah 11:13","short":"Jer 11:13","text":"For your gods have become as many as your cities, O Judah, and as many as the streets of Jerusalem are the altars you have set up to shame, altars to make offerings to Baal.","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":13},{"ref":"Jeremiah 11:14","short":"Jer 11:14","text":"“Therefore do not pray for this people, or lift up a cry or prayer on their behalf, for I will not listen when they call to me in the time of their trouble.","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":14},{"ref":"Jeremiah 11:15","short":"Jer 11:15","text":"What right has my beloved in my house, when she has done many vile deeds? Can even sacrificial flesh avert your doom? Can you then exult?","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":15},{"ref":"Jeremiah 11:16","short":"Jer 11:16","text":"The LORD once called you ‘a green olive tree, beautiful with good fruit.’ But with the roar of a great tempest he will set fire to it, and its branches will be consumed.","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":16},{"ref":"Jeremiah 11:17","short":"Jer 11:17","text":"The LORD of hosts, who planted you, has decreed disaster against you, because of the evil that the house of Israel and the house of Judah have done, provoking me to anger by making offerings to Baal.”","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":17},{"ref":"Jeremiah 11:18","short":"Jer 11:18","text":"The LORD made it known to me and I knew; then you showed me their deeds.","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":18},{"ref":"Jeremiah 11:19","short":"Jer 11:19","text":"But I was like a gentle lamb led to the slaughter. I did not know it was against me they devised schemes, saying, “Let us destroy the tree with its fruit, let us cut him off from the land of the living, that his name be remembered no more.”","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":19},{"ref":"Jeremiah 11:20","short":"Jer 11:20","text":"But, O LORD of hosts, who judges righteously, who tests the heart and the mind, let me see your vengeance upon them, for to you have I committed my cause.","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":20},{"ref":"Jeremiah 11:21","short":"Jer 11:21","text":"Therefore thus says the LORD concerning the men of Anathoth, who seek your life, and say, “Do not prophesy in the name of the LORD, or you will die by our hand”—","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":21},{"ref":"Jeremiah 11:22","short":"Jer 11:22","text":"therefore thus says the LORD of hosts: “Behold, I will punish them. The young men shall die by the sword, their sons and their daughters shall die by famine,","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":22},{"ref":"Jeremiah 11:23","short":"Jer 11:23","text":"and none of them shall be left. For I will bring disaster upon the men of Anathoth, the year of their punishment.”","url":"ot/jeremiah/Jeremiah_11.html","book":"Jeremiah","ch":11,"v":23},{"ref":"Jeremiah 12:1","short":"Jer 12:1","text":"Righteous are you, O LORD, when I complain to you; yet I would plead my case before you. Why does the way of the wicked prosper? Why do all who are treacherous thrive?","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":1},{"ref":"Jeremiah 12:2","short":"Jer 12:2","text":"You plant them, and they take root; they grow and produce fruit; you are near in their mouth and far from their heart.","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":2},{"ref":"Jeremiah 12:3","short":"Jer 12:3","text":"But you, O LORD, know me; you see me, and test my heart toward you. Pull them out like sheep for the slaughter, and set them apart for the day of slaughter.","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":3},{"ref":"Jeremiah 12:4","short":"Jer 12:4","text":"How long will the land mourn and the grass of every field wither? For the evil of those who dwell in it the beasts and the birds are swept away, because they said, “He will not see our latter end.”","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":4},{"ref":"Jeremiah 12:5","short":"Jer 12:5","text":"“If you have raced with men on foot, and they have wearied you, how will you compete with horses? And if in a safe land you are so trusting, what will you do in the thicket of the Jordan?","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":5},{"ref":"Jeremiah 12:6","short":"Jer 12:6","text":"For even your brothers and the house of your father, even they have dealt treacherously with you; they are in full cry after you; do not believe them, though they speak friendly words to you.”","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":6},{"ref":"Jeremiah 12:7","short":"Jer 12:7","text":"“I have forsaken my house; I have abandoned my heritage; I have given the beloved of my soul into the hands of her enemies.","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":7},{"ref":"Jeremiah 12:8","short":"Jer 12:8","text":"My heritage has become to me like a lion in the forest; she has lifted up her voice against me; therefore I hate her.","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":8},{"ref":"Jeremiah 12:9","short":"Jer 12:9","text":"Is my heritage to me like a hyena’s lair? Are the birds of prey against her all around? Go, assemble all the wild beasts; bring them to devour.","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":9},{"ref":"Jeremiah 12:10","short":"Jer 12:10","text":"Many shepherds have destroyed my vineyard; they have trampled down my portion; they have made my pleasant portion a desolate wilderness.","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":10},{"ref":"Jeremiah 12:11","short":"Jer 12:11","text":"They have made it a desolation; desolate, it mourns to me. The whole land is made desolate, but no man lays it to heart.","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":11},{"ref":"Jeremiah 12:12","short":"Jer 12:12","text":"Upon all the bare heights in the desert destroyers have come, for the sword of the LORD devours from one end of the land to the other; no flesh has peace.","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":12},{"ref":"Jeremiah 12:13","short":"Jer 12:13","text":"They have sown wheat and have reaped thorns; they have tired themselves out but profit nothing. They shall be ashamed of their harvests because of the fierce anger of the LORD.”","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":13},{"ref":"Jeremiah 12:14","short":"Jer 12:14","text":"Thus says the LORD concerning all my evil neighbors who touch the heritage that I have given my people Israel to inherit: “Behold, I will pluck them up from their land, and I will pluck up the house of Judah from among them.","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":14},{"ref":"Jeremiah 12:15","short":"Jer 12:15","text":"And after I have plucked them up, I will again have compassion on them, and I will bring them again each to his heritage and each to his land.","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":15},{"ref":"Jeremiah 12:16","short":"Jer 12:16","text":"And it shall come to pass, if they will diligently learn the ways of my people, to swear by my name, ‘As the LORD lives,’ even as they taught my people to swear by Baal, then they shall be built up in the midst of my people.","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":16},{"ref":"Jeremiah 12:17","short":"Jer 12:17","text":"But if any nation will not listen, then I will utterly pluck it up and destroy it, declares the LORD.”","url":"ot/jeremiah/Jeremiah_12.html","book":"Jeremiah","ch":12,"v":17},{"ref":"Jeremiah 13:1","short":"Jer 13:1","text":"Thus says the LORD to me, “Go and buy a linen loincloth and put it around your waist, and do not dip it in water.”","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":1},{"ref":"Jeremiah 13:2","short":"Jer 13:2","text":"So I bought a loincloth according to the word of the LORD, and put it around my waist.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":2},{"ref":"Jeremiah 13:3","short":"Jer 13:3","text":"And the word of the LORD came to me a second time,","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":3},{"ref":"Jeremiah 13:4","short":"Jer 13:4","text":"“Take the loincloth that you have bought, which is around your waist, and arise, go to the Euphrates and hide it there in a cleft of the rock.”","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":4},{"ref":"Jeremiah 13:5","short":"Jer 13:5","text":"So I went and hid it by the Euphrates, as the LORD commanded me.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":5},{"ref":"Jeremiah 13:6","short":"Jer 13:6","text":"And after many days the LORD said to me, “Arise, go to the Euphrates, and take from there the loincloth that I commanded you to hide there.”","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":6},{"ref":"Jeremiah 13:7","short":"Jer 13:7","text":"Then I went to the Euphrates, and dug, and I took the loincloth from the place where I had hidden it. And behold, the loincloth was spoiled; it was good for nothing.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":7},{"ref":"Jeremiah 13:8","short":"Jer 13:8","text":"Then the word of the LORD came to me:","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":8},{"ref":"Jeremiah 13:9","short":"Jer 13:9","text":"“Thus says the LORD: Even so will I spoil the pride of Judah and the great pride of Jerusalem.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":9},{"ref":"Jeremiah 13:10","short":"Jer 13:10","text":"This evil people, who refuse to hear my words, who stubbornly follow their own heart and have gone after other gods to serve them and worship them, shall be like this loincloth, which is good for nothing.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":10},{"ref":"Jeremiah 13:11","short":"Jer 13:11","text":"For as the loincloth clings to the waist of a man, so I made the whole house of Israel and the whole house of Judah cling to me, declares the LORD, that they might be for me a people, a name, a praise, and a glory, but they would not listen.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":11},{"ref":"Jeremiah 13:12","short":"Jer 13:12","text":"“You shall speak to them this word: ‘Thus says the LORD, the God of Israel, “Every jar shall be filled with wine.”’ And they will say to you, ‘Do we not indeed know that every jar will be filled with wine?’","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":12},{"ref":"Jeremiah 13:13","short":"Jer 13:13","text":"Then you shall say to them, ‘Thus says the LORD: Behold, I will fill with drunkenness all the inhabitants of this land: the kings who sit on David’s throne, the priests, the prophets, and all the inhabitants of Jerusalem.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":13},{"ref":"Jeremiah 13:14","short":"Jer 13:14","text":"And I will dash them one against another, fathers and sons together, declares the LORD. I will not pity or spare or have compassion, that I should not destroy them.’”","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":14},{"ref":"Jeremiah 13:15","short":"Jer 13:15","text":"Hear and give ear; be not proud, for the LORD has spoken.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":15},{"ref":"Jeremiah 13:16","short":"Jer 13:16","text":"Give glory to the LORD your God before he brings darkness, before your feet stumble on the twilight mountains, and while you look for light he turns it into gloom and makes it deep darkness.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":16},{"ref":"Jeremiah 13:17","short":"Jer 13:17","text":"But if you will not listen, my soul will weep in secret for your pride; my eyes will weep bitterly and run down with tears, because the LORD’s flock has been taken captive.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":17},{"ref":"Jeremiah 13:18","short":"Jer 13:18","text":"Say to the king and the queen mother: “Take a lowly seat, for your beautiful crown has come down from your head.”","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":18},{"ref":"Jeremiah 13:19","short":"Jer 13:19","text":"The cities of the Negeb are shut up, with none to open them; all Judah is taken into exile, wholly taken into exile.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":19},{"ref":"Jeremiah 13:20","short":"Jer 13:20","text":"“Lift up your eyes and see those who come from the north. Where is the flock that was given you, your beautiful flock?","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":20},{"ref":"Jeremiah 13:21","short":"Jer 13:21","text":"What will you say when they set as head over you those whom you yourself have taught to be friends to you? Will not pangs take hold of you like those of a woman in labor?","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":21},{"ref":"Jeremiah 13:22","short":"Jer 13:22","text":"And if you say in your heart, ‘Why have these things come upon me?’ it is for the greatness of your iniquity that your skirts are lifted up and you suffer violence.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":22},{"ref":"Jeremiah 13:23","short":"Jer 13:23","text":"Can the Ethiopian change his skin or the leopard his spots? Then also you can do good who are accustomed to do evil.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":23},{"ref":"Jeremiah 13:24","short":"Jer 13:24","text":"I will scatter you like chaff driven by the wind from the desert.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":24},{"ref":"Jeremiah 13:25","short":"Jer 13:25","text":"This is your lot, the portion I have measured out to you, declares the LORD, because you have forgotten me and trusted in lies.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":25},{"ref":"Jeremiah 13:26","short":"Jer 13:26","text":"I myself will lift up your skirts over your face, and your shame will be seen.","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":26},{"ref":"Jeremiah 13:27","short":"Jer 13:27","text":"I have seen your abominations, your adulteries and neighings, your lewd whorings, on the hills in the field. Woe to you, O Jerusalem! How long will it be before you are made clean?”","url":"ot/jeremiah/Jeremiah_13.html","book":"Jeremiah","ch":13,"v":27},{"ref":"Jeremiah 14:1","short":"Jer 14:1","text":"The word of the LORD that came to Jeremiah concerning the drought:","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":1},{"ref":"Jeremiah 14:2","short":"Jer 14:2","text":"“Judah mourns, and her gates languish; her people lament on the ground, and the cry of Jerusalem goes up.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":2},{"ref":"Jeremiah 14:3","short":"Jer 14:3","text":"Her nobles send their servants for water; they come to the cisterns; they find no water; they return with their vessels empty; they are ashamed and confounded and cover their heads.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":3},{"ref":"Jeremiah 14:4","short":"Jer 14:4","text":"Because of the ground that is dismayed, since there is no rain on the land, the farmers are ashamed; they cover their heads.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":4},{"ref":"Jeremiah 14:5","short":"Jer 14:5","text":"Even the doe in the field forsakes her newborn fawn because there is no grass.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":5},{"ref":"Jeremiah 14:6","short":"Jer 14:6","text":"The wild donkeys stand on the bare heights; they pant for air like jackals; their eyes fail because there is no vegetation.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":6},{"ref":"Jeremiah 14:7","short":"Jer 14:7","text":"“Though our iniquities testify against us, act, O LORD, for your name’s sake; for our backslidings are many; we have sinned against you.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":7},{"ref":"Jeremiah 14:8","short":"Jer 14:8","text":"O you hope of Israel, its savior in time of trouble, why should you be like a stranger in the land, like a traveler who turns aside to tarry for a night?","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":8},{"ref":"Jeremiah 14:9","short":"Jer 14:9","text":"Why should you be like a man confused, like a mighty warrior who cannot save? Yet you, O LORD, are in the midst of us, and we are called by your name; do not leave us.”","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":9},{"ref":"Jeremiah 14:10","short":"Jer 14:10","text":"Thus says the LORD concerning this people: “They have loved to wander thus; they have not restrained their feet; therefore the LORD does not accept them; now he will remember their iniquity and punish their sins.”","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":10},{"ref":"Jeremiah 14:11","short":"Jer 14:11","text":"The LORD said to me: “Do not pray for the welfare of this people.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":11},{"ref":"Jeremiah 14:12","short":"Jer 14:12","text":"Though they fast, I will not hear their cry, and though they offer burnt offering and grain offering, I will not accept them. But I will consume them by the sword, by famine, and by pestilence.”","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":12},{"ref":"Jeremiah 14:13","short":"Jer 14:13","text":"Then I said: “Ah, Lord GOD, behold, the prophets say to them, ‘You shall not see the sword, nor shall you have famine, but I will give you assured peace in this place.’”","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":13},{"ref":"Jeremiah 14:14","short":"Jer 14:14","text":"And the LORD said to me: “The prophets are prophesying lies in my name. I did not send them, nor did I command them or speak to them. They are prophesying to you a lying vision, worthless divination, and the deceit of their own minds.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":14},{"ref":"Jeremiah 14:15","short":"Jer 14:15","text":"Therefore thus says the LORD concerning the prophets who prophesy in my name although I did not send them, and who say, ‘Sword and famine shall not come upon this land’: By sword and famine those prophets shall be consumed.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":15},{"ref":"Jeremiah 14:16","short":"Jer 14:16","text":"And the people to whom they prophesy shall be cast out in the streets of Jerusalem, victims of famine and sword, with none to bury them—them, their wives, their sons, and their daughters. For I will pour out their evil upon them.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":16},{"ref":"Jeremiah 14:17","short":"Jer 14:17","text":"“You shall say to them this word: ‘Let my eyes run down with tears night and day, and let them not cease, for the virgin daughter of my people is shattered with a great wound, with a very grievous blow.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":17},{"ref":"Jeremiah 14:18","short":"Jer 14:18","text":"If I go out into the field, behold, those pierced by the sword! And if I enter the city, behold, the diseases of famine! For both prophet and priest ply their trade through the land and have no knowledge.’”","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":18},{"ref":"Jeremiah 14:19","short":"Jer 14:19","text":"Have you utterly rejected Judah? Does your soul loathe Zion? Why have you struck us down so that there is no healing for us? We looked for peace, but no good came; for a time of healing, but behold, terror.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":19},{"ref":"Jeremiah 14:20","short":"Jer 14:20","text":"We acknowledge our wickedness, O LORD, and the iniquity of our fathers, for we have sinned against you.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":20},{"ref":"Jeremiah 14:21","short":"Jer 14:21","text":"Do not spurn us, for your name’s sake; do not dishonor your glorious throne; remember and do not break your covenant with us.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":21},{"ref":"Jeremiah 14:22","short":"Jer 14:22","text":"Are there any among the false gods of the nations that can bring rain? Or can the heavens give showers? Are you not he, O LORD our God? We set our hope on you, for you do all these things.","url":"ot/jeremiah/Jeremiah_14.html","book":"Jeremiah","ch":14,"v":22},{"ref":"Jeremiah 15:1","short":"Jer 15:1","text":"Then the LORD said to me, “Though Moses and Samuel stood before me, yet my heart would not turn toward this people. Send them out of my sight, and let them go!","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":1},{"ref":"Jeremiah 15:2","short":"Jer 15:2","text":"And when they ask you, ‘Where shall we go?’ you shall say to them, ‘Thus says the LORD: “‘Those who are for pestilence, to pestilence, and those who are for the sword, to the sword; those who are for famine, to famine, and those who are for captivity, to captivity.’","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":2},{"ref":"Jeremiah 15:3","short":"Jer 15:3","text":"I will appoint over them four kinds of destroyers, declares the LORD: the sword to kill, the dogs to tear, and the birds of the air and the beasts of the earth to devour and destroy.","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":3},{"ref":"Jeremiah 15:4","short":"Jer 15:4","text":"And I will make them a horror to all the kingdoms of the earth because of what Manasseh the son of Hezekiah, king of Judah, did in Jerusalem.","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":4},{"ref":"Jeremiah 15:5","short":"Jer 15:5","text":"“Who will have pity on you, O Jerusalem, or who will grieve for you? Who will turn aside to ask about your welfare?","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":5},{"ref":"Jeremiah 15:6","short":"Jer 15:6","text":"You have rejected me, declares the LORD; you keep going backward, so I have stretched out my hand against you and destroyed you— I am weary of relenting.","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":6},{"ref":"Jeremiah 15:7","short":"Jer 15:7","text":"I have winnowed them with a winnowing fork in the gates of the land; I have bereaved them; I have destroyed my people; they did not turn from their ways.","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":7},{"ref":"Jeremiah 15:8","short":"Jer 15:8","text":"I have made their widows more in number than the sand of the seas; I have brought against the mothers of young men a destroyer at noonday; I have made anguish and terror fall upon them suddenly.","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":8},{"ref":"Jeremiah 15:9","short":"Jer 15:9","text":"She who bore seven has grown feeble; she has fainted away; her sun went down while it was yet day; she has been shamed and disgraced. And the rest of them I will give to the sword before their enemies, declares the LORD.”","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":9},{"ref":"Jeremiah 15:10","short":"Jer 15:10","text":"Woe is me, my mother, that you bore me, a man of strife and contention to the whole land! I have not lent, nor have I borrowed, yet all of them curse me.","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":10},{"ref":"Jeremiah 15:11","short":"Jer 15:11","text":"The LORD said, “Have I not set you free for their good? Have I not pleaded for you before the enemy in the time of trouble and in the time of distress?","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":11},{"ref":"Jeremiah 15:12","short":"Jer 15:12","text":"Can one break iron, iron from the north, and bronze?","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":12},{"ref":"Jeremiah 15:13","short":"Jer 15:13","text":"“Your wealth and your treasures I will give as spoil, without price, for all your sins, throughout all your territory.","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":13},{"ref":"Jeremiah 15:14","short":"Jer 15:14","text":"I will make you serve your enemies in a land that you do not know, for in my anger a fire is kindled that shall burn forever.”","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":14},{"ref":"Jeremiah 15:15","short":"Jer 15:15","text":"O LORD, you know; remember me and visit me, and take vengeance for me on my persecutors. In your forbearance take me not away; know that for your sake I bear reproach.","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":15},{"ref":"Jeremiah 15:16","short":"Jer 15:16","text":"Your words were found, and I ate them, and your words became to me a joy and the delight of my heart, for I am called by your name, O LORD, God of hosts.","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":16},{"ref":"Jeremiah 15:17","short":"Jer 15:17","text":"I did not sit in the company of revelers, nor did I rejoice; I sat alone, because your hand was upon me, for you had filled me with indignation.","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":17},{"ref":"Jeremiah 15:18","short":"Jer 15:18","text":"Why is my pain unceasing, my wound incurable, refusing to be healed? Will you be to me like a deceitful brook, like waters that fail?","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":18},{"ref":"Jeremiah 15:19","short":"Jer 15:19","text":"Therefore thus says the LORD: “If you return, I will restore you, and you shall stand before me. If you utter what is precious, and not what is worthless, you shall be as my mouth. They shall turn to you, but you shall not turn to them.","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":19},{"ref":"Jeremiah 15:20","short":"Jer 15:20","text":"And I will make you to this people a fortified wall of bronze; they will fight against you, but they shall not prevail over you, for I am with you to save you and deliver you, declares the LORD.","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":20},{"ref":"Jeremiah 15:21","short":"Jer 15:21","text":"I will deliver you out of the hand of the wicked, and redeem you from the grasp of the ruthless.”","url":"ot/jeremiah/Jeremiah_15.html","book":"Jeremiah","ch":15,"v":21},{"ref":"Jeremiah 16:1","short":"Jer 16:1","text":"The word of the LORD came to me:","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":1},{"ref":"Jeremiah 16:2","short":"Jer 16:2","text":"“You shall not take a wife, nor shall you have sons or daughters in this place.","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":2},{"ref":"Jeremiah 16:3","short":"Jer 16:3","text":"For thus says the LORD concerning the sons and daughters who are born in this place, and concerning the mothers who bore them and the fathers who fathered them in this land:","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":3},{"ref":"Jeremiah 16:4","short":"Jer 16:4","text":"They shall die of deadly diseases. They shall not be lamented, nor shall they be buried. They shall be as dung on the surface of the ground. They shall perish by the sword and by famine, and their dead bodies shall be food for the birds of the air and for the beasts of the earth.","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":4},{"ref":"Jeremiah 16:5","short":"Jer 16:5","text":"“For thus says the LORD: Do not enter the house of mourning, or go to lament or grieve for them, for I have taken away my peace from this people, my steadfast love and mercy, declares the LORD.","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":5},{"ref":"Jeremiah 16:6","short":"Jer 16:6","text":"Both great and small shall die in this land. They shall not be buried, and no one shall lament for them or cut himself or make himself bald for them.","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":6},{"ref":"Jeremiah 16:7","short":"Jer 16:7","text":"No one shall break bread for the mourner, to comfort him for the dead, nor shall anyone give him the cup of consolation to drink for his father or his mother.","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":7},{"ref":"Jeremiah 16:8","short":"Jer 16:8","text":"You shall not go into the house of feasting to sit with them, to eat and drink.","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":8},{"ref":"Jeremiah 16:9","short":"Jer 16:9","text":"For thus says the LORD of hosts, the God of Israel: Behold, I will silence in this place, before your eyes and in your days, the voice of mirth and the voice of gladness, the voice of the bridegroom and the voice of the bride.","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":9},{"ref":"Jeremiah 16:10","short":"Jer 16:10","text":"“And when you tell this people all these words, and they say to you, ‘Why has the LORD pronounced all this great evil against us? What is our iniquity? What is the sin that we have committed against the LORD our God?’","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":10},{"ref":"Jeremiah 16:11","short":"Jer 16:11","text":"then you shall say to them: ‘Because your fathers have forsaken me, declares the LORD, and have gone after other gods and have served and worshiped them, and have forsaken me and have not kept my law,","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":11},{"ref":"Jeremiah 16:12","short":"Jer 16:12","text":"and because you have done worse than your fathers, for behold, every one of you follows his stubborn, evil will, refusing to listen to me.","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":12},{"ref":"Jeremiah 16:13","short":"Jer 16:13","text":"Therefore I will hurl you out of this land into a land that neither you nor your fathers have known, and there you shall serve other gods day and night, for I will show you no favor.’","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":13},{"ref":"Jeremiah 16:14","short":"Jer 16:14","text":"“Therefore, behold, the days are coming, declares the LORD, when it shall no longer be said, ‘As the LORD lives who brought up the people of Israel out of the land of Egypt,’","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":14},{"ref":"Jeremiah 16:15","short":"Jer 16:15","text":"but ‘As the LORD lives who brought up the people of Israel out of the north country and out of all the countries where he had driven them.’ For I will bring them back to their own land that I gave to their fathers.","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":15},{"ref":"Jeremiah 16:16","short":"Jer 16:16","text":"“Behold, I am sending for many fishers, declares the LORD, and they shall catch them. And afterward I will send for many hunters, and they shall hunt them from every mountain and every hill, and out of the clefts of the rocks.","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":16},{"ref":"Jeremiah 16:17","short":"Jer 16:17","text":"For my eyes are on all their ways. They are not hidden from me, nor is their iniquity concealed from my eyes.","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":17},{"ref":"Jeremiah 16:18","short":"Jer 16:18","text":"But first I will doubly repay their iniquity and their sin, because they have polluted my land with the carcasses of their detestable idols, and have filled my inheritance with their abominations.”","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":18},{"ref":"Jeremiah 16:19","short":"Jer 16:19","text":"O LORD, my strength and my stronghold, my refuge in the day of trouble, to you shall the nations come from the ends of the earth and say: “Our fathers have inherited nothing but lies, worthless things in which there is no profit.","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":19},{"ref":"Jeremiah 16:20","short":"Jer 16:20","text":"Can man make for himself gods? Such are not gods!”","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":20},{"ref":"Jeremiah 16:21","short":"Jer 16:21","text":"“Therefore, behold, I will make them know, this once I will make them know my power and my might, and they shall know that my name is the LORD.”","url":"ot/jeremiah/Jeremiah_16.html","book":"Jeremiah","ch":16,"v":21},{"ref":"Jeremiah 17:1","short":"Jer 17:1","text":"“The sin of Judah is written with a pen of iron; with a point of diamond it is engraved on the tablet of their heart, and on the horns of their altars,","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":1},{"ref":"Jeremiah 17:2","short":"Jer 17:2","text":"while their children remember their altars and their Asherim, beside every green tree and on the high hills,","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":2},{"ref":"Jeremiah 17:3","short":"Jer 17:3","text":"on the mountains in the open country. Your wealth and all your treasures I will give for spoil as the price of your high places for sin throughout all your territory.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":3},{"ref":"Jeremiah 17:4","short":"Jer 17:4","text":"You shall loosen your hand from your heritage that I gave to you, and I will make you serve your enemies in a land that you do not know, for in my anger a fire is kindled that shall burn forever.”","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":4},{"ref":"Jeremiah 17:5","short":"Jer 17:5","text":"Thus says the LORD: “Cursed is the man who trusts in man and makes flesh his strength, whose heart turns away from the LORD.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":5},{"ref":"Jeremiah 17:6","short":"Jer 17:6","text":"He is like a shrub in the desert, and shall not see any good come. He shall dwell in the parched places of the wilderness, in an uninhabited salt land.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":6},{"ref":"Jeremiah 17:7","short":"Jer 17:7","text":"“Blessed is the man who trusts in the LORD, whose trust is the LORD.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":7},{"ref":"Jeremiah 17:8","short":"Jer 17:8","text":"He is like a tree planted by water, that sends out its roots by the stream, and does not fear when heat comes, for its leaves remain green, and is not anxious in the year of drought, for it does not cease to bear fruit.”","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":8},{"ref":"Jeremiah 17:9","short":"Jer 17:9","text":"The heart is deceitful above all things, and desperately sick; who can understand it?","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":9},{"ref":"Jeremiah 17:10","short":"Jer 17:10","text":"“I the LORD search the heart and test the mind, to give every man according to his ways, according to the fruit of his deeds.”","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":10},{"ref":"Jeremiah 17:11","short":"Jer 17:11","text":"Like the partridge that gathers a brood that she did not hatch, so is he who gets riches but not by justice; in the midst of his days they will leave him, and at his end he will be a fool.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":11},{"ref":"Jeremiah 17:12","short":"Jer 17:12","text":"A glorious throne set on high from the beginning is the place of our sanctuary.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":12},{"ref":"Jeremiah 17:13","short":"Jer 17:13","text":"O LORD, the hope of Israel, all who forsake you shall be put to shame; those who turn away from you shall be written in the earth, for they have forsaken the LORD, the fountain of living water.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":13},{"ref":"Jeremiah 17:14","short":"Jer 17:14","text":"Heal me, O LORD, and I shall be healed; save me, and I shall be saved, for you are my praise.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":14},{"ref":"Jeremiah 17:15","short":"Jer 17:15","text":"Behold, they say to me, “Where is the word of the LORD? Let it come!”","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":15},{"ref":"Jeremiah 17:16","short":"Jer 17:16","text":"I have not run away from being your shepherd, nor have I desired the day of sickness. You know what came out of my lips; it was before your face.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":16},{"ref":"Jeremiah 17:17","short":"Jer 17:17","text":"Be not a terror to me; you are my refuge in the day of disaster.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":17},{"ref":"Jeremiah 17:18","short":"Jer 17:18","text":"Let those be put to shame who persecute me, but let me not be put to shame; let them be dismayed, but let me not be dismayed; bring upon them the day of disaster; destroy them with double destruction!","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":18},{"ref":"Jeremiah 17:19","short":"Jer 17:19","text":"Thus said the LORD to me: “Go and stand in the People’s Gate, by which the kings of Judah enter and by which they go out, and in all the gates of Jerusalem,","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":19},{"ref":"Jeremiah 17:20","short":"Jer 17:20","text":"and say: ‘Hear the word of the LORD, you kings of Judah, and all Judah, and all the inhabitants of Jerusalem, who enter by these gates.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":20},{"ref":"Jeremiah 17:21","short":"Jer 17:21","text":"Thus says the LORD: Take care for the sake of your lives, and do not bear a burden on the Sabbath day or bring it in by the gates of Jerusalem.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":21},{"ref":"Jeremiah 17:22","short":"Jer 17:22","text":"And do not carry a burden out of your houses on the Sabbath or do any work, but keep the Sabbath day holy, as I commanded your fathers.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":22},{"ref":"Jeremiah 17:23","short":"Jer 17:23","text":"Yet they did not listen or incline their ear, but stiffened their neck, that they might not hear and receive instruction.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":23},{"ref":"Jeremiah 17:24","short":"Jer 17:24","text":"“‘But if you listen to me, declares the LORD, and bring in no burden by the gates of this city on the Sabbath day, but keep the Sabbath day holy and do no work on it,","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":24},{"ref":"Jeremiah 17:25","short":"Jer 17:25","text":"then there shall enter by the gates of this city kings and princes who sit on the throne of David, riding in chariots and on horses, they and their officials, the men of Judah and the inhabitants of Jerusalem. And this city shall be inhabited forever.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":25},{"ref":"Jeremiah 17:26","short":"Jer 17:26","text":"And people shall come from the cities of Judah and the places around Jerusalem, from the land of Benjamin, from the Shephelah, from the hill country, and from the Negeb, bringing burnt offerings and sacrifices, grain offerings and frankincense, and bringing thank offerings to the house of the LORD.","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":26},{"ref":"Jeremiah 17:27","short":"Jer 17:27","text":"But if you do not listen to me, to keep the Sabbath day holy, and not to bear a burden and enter by the gates of Jerusalem on the Sabbath day, then I will kindle a fire in its gates, and it shall devour the palaces of Jerusalem and shall not be quenched.’”","url":"ot/jeremiah/Jeremiah_17.html","book":"Jeremiah","ch":17,"v":27},{"ref":"Jeremiah 18:1","short":"Jer 18:1","text":"The word that came to Jeremiah from the LORD:","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":1},{"ref":"Jeremiah 18:2","short":"Jer 18:2","text":"“Arise, and go down to the potter’s house, and there I will let you hear my words.”","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":2},{"ref":"Jeremiah 18:3","short":"Jer 18:3","text":"So I went down to the potter’s house, and there he was working at his wheel.","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":3},{"ref":"Jeremiah 18:4","short":"Jer 18:4","text":"And the vessel he was making of clay was spoiled in the potter’s hand, and he reworked it into another vessel, as it seemed good to the potter to do.","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":4},{"ref":"Jeremiah 18:5","short":"Jer 18:5","text":"Then the word of the LORD came to me:","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":5},{"ref":"Jeremiah 18:6","short":"Jer 18:6","text":"“O house of Israel, can I not do with you as this potter has done? declares the LORD. Behold, like the clay in the potter’s hand, so are you in my hand, O house of Israel.","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":6},{"ref":"Jeremiah 18:7","short":"Jer 18:7","text":"If at any time I declare concerning a nation or a kingdom, that I will pluck up and break down and destroy it,","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":7},{"ref":"Jeremiah 18:8","short":"Jer 18:8","text":"and if that nation, concerning which I have spoken, turns from its evil, I will relent of the disaster that I intended to do to it.","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":8},{"ref":"Jeremiah 18:9","short":"Jer 18:9","text":"And if at any time I declare concerning a nation or a kingdom that I will build and plant it,","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":9},{"ref":"Jeremiah 18:10","short":"Jer 18:10","text":"and if it does evil in my sight, not listening to my voice, then I will relent of the good that I had intended to do to it.","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":10},{"ref":"Jeremiah 18:11","short":"Jer 18:11","text":"Now, therefore, say to the men of Judah and the inhabitants of Jerusalem: ‘Thus says the LORD, Behold, I am shaping disaster against you and devising a plan against you. Return, every one from his evil way, and amend your ways and your deeds.’","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":11},{"ref":"Jeremiah 18:12","short":"Jer 18:12","text":"“But they say, ‘That is in vain! We will follow our own plans, and will every one act according to the stubbornness of his evil heart.’","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":12},{"ref":"Jeremiah 18:13","short":"Jer 18:13","text":"“Therefore thus says the LORD: Ask among the nations, Who has heard the like of this? The virgin Israel has done a very horrible thing.","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":13},{"ref":"Jeremiah 18:14","short":"Jer 18:14","text":"Does the snow of Lebanon leave the crags of Sirion? Do the mountain waters run dry, the cold flowing streams?","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":14},{"ref":"Jeremiah 18:15","short":"Jer 18:15","text":"But my people have forgotten me; they make offerings to false gods; they made them stumble in their ways, in the ancient roads, and to walk into side roads, not the highway,","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":15},{"ref":"Jeremiah 18:16","short":"Jer 18:16","text":"making their land a horror, a thing to be hissed at forever. Everyone who passes by it is horrified and shakes his head.","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":16},{"ref":"Jeremiah 18:17","short":"Jer 18:17","text":"Like the east wind I will scatter them before the enemy. I will show them my back, not my face, in the day of their calamity.”","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":17},{"ref":"Jeremiah 18:18","short":"Jer 18:18","text":"Then they said, “Come, let us make plots against Jeremiah, for the law shall not perish from the priest, nor counsel from the wise, nor the word from the prophet. Come, let us strike him with the tongue, and let us not pay attention to any of his words.”","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":18},{"ref":"Jeremiah 18:19","short":"Jer 18:19","text":"Hear me, O LORD, and listen to the voice of my adversaries.","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":19},{"ref":"Jeremiah 18:20","short":"Jer 18:20","text":"Should good be repaid with evil? Yet they have dug a pit for my life. Remember how I stood before you to speak good for them, to turn away your wrath from them.","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":20},{"ref":"Jeremiah 18:21","short":"Jer 18:21","text":"Therefore deliver up their children to famine; give them over to the power of the sword; let their wives become childless and widowed. May their men meet death by pestilence, their youths be struck down by the sword in battle.","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":21},{"ref":"Jeremiah 18:22","short":"Jer 18:22","text":"May a cry be heard from their houses, when you bring the plunderer suddenly upon them! For they have dug a pit to take me and laid snares for my feet.","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":22},{"ref":"Jeremiah 18:23","short":"Jer 18:23","text":"Yet you, O LORD, know all their plotting to kill me. Forgive not their iniquity, nor blot out their sin from your sight. Let them be overthrown before you; deal with them in the time of your anger.","url":"ot/jeremiah/Jeremiah_18.html","book":"Jeremiah","ch":18,"v":23},{"ref":"Jeremiah 19:1","short":"Jer 19:1","text":"Thus says the LORD, “Go, buy a potter’s earthenware flask, and take some of the elders of the people and some of the elders of the priests,","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":1},{"ref":"Jeremiah 19:2","short":"Jer 19:2","text":"and go out to the Valley of the Son of Hinnom at the entry of the Potsherd Gate, and proclaim there the words that I tell you.","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":2},{"ref":"Jeremiah 19:3","short":"Jer 19:3","text":"You shall say, ‘Hear the word of the LORD, O kings of Judah and inhabitants of Jerusalem. Thus says the LORD of hosts, the God of Israel: Behold, I am bringing such disaster upon this place that the ears of everyone who hears of it will tingle.","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":3},{"ref":"Jeremiah 19:4","short":"Jer 19:4","text":"Because the people have forsaken me and have profaned this place by making offerings in it to other gods whom neither they nor their fathers nor the kings of Judah have known; and because they have filled this place with the blood of innocents,","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":4},{"ref":"Jeremiah 19:5","short":"Jer 19:5","text":"and have built the high places of Baal to burn their sons in the fire as burnt offerings to Baal, which I did not command or decree, nor did it come into my mind—","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":5},{"ref":"Jeremiah 19:6","short":"Jer 19:6","text":"therefore, behold, days are coming, declares the LORD, when this place shall no more be called Topheth, or the Valley of the Son of Hinnom, but the Valley of Slaughter.","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":6},{"ref":"Jeremiah 19:7","short":"Jer 19:7","text":"And in this place I will make void the plans of Judah and Jerusalem, and will cause their people to fall by the sword before their enemies, and by the hand of those who seek their life. I will give their dead bodies for food to the birds of the air and to the beasts of the earth.","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":7},{"ref":"Jeremiah 19:8","short":"Jer 19:8","text":"And I will make this city a horror, a thing to be hissed at. Everyone who passes by it will be horrified and will hiss because of all its wounds.","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":8},{"ref":"Jeremiah 19:9","short":"Jer 19:9","text":"And I will make them eat the flesh of their sons and their daughters, and everyone shall eat the flesh of his neighbor in the siege and in the distress, with which their enemies and those who seek their life afflict them.’","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":9},{"ref":"Jeremiah 19:10","short":"Jer 19:10","text":"“Then you shall break the flask in the sight of the men who go with you,","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":10},{"ref":"Jeremiah 19:11","short":"Jer 19:11","text":"and shall say to them, ‘Thus says the LORD of hosts: So will I break this people and this city, as one breaks a potter’s vessel, so that it can never be mended. Men shall bury in Topheth because there will be no place else to bury.","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":11},{"ref":"Jeremiah 19:12","short":"Jer 19:12","text":"Thus will I do to this place, declares the LORD, and to its inhabitants, making this city like Topheth.","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":12},{"ref":"Jeremiah 19:13","short":"Jer 19:13","text":"The houses of Jerusalem and the houses of the kings of Judah—all the houses on whose roofs offerings have been offered to all the host of heaven, and drink offerings have been poured out to other gods—shall be defiled like the place of Topheth.’”","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":13},{"ref":"Jeremiah 19:14","short":"Jer 19:14","text":"Then Jeremiah came from Topheth, where the LORD had sent him to prophesy, and he stood in the court of the LORD’s house and said to all the people:","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":14},{"ref":"Jeremiah 19:15","short":"Jer 19:15","text":"“Thus says the LORD of hosts, the God of Israel, behold, I am bringing upon this city and upon all its towns all the disaster that I have pronounced against it, because they have stiffened their neck, refusing to hear my words.”","url":"ot/jeremiah/Jeremiah_19.html","book":"Jeremiah","ch":19,"v":15},{"ref":"Jeremiah 20:1","short":"Jer 20:1","text":"Now Pashhur the priest, the son of Immer, who was chief officer in the house of the LORD, heard Jeremiah prophesying these things.","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":1},{"ref":"Jeremiah 20:2","short":"Jer 20:2","text":"Then Pashhur beat Jeremiah the prophet, and put him in the stocks that were in the upper Benjamin Gate of the house of the LORD.","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":2},{"ref":"Jeremiah 20:3","short":"Jer 20:3","text":"The next day, when Pashhur released Jeremiah from the stocks, Jeremiah said to him, “The LORD does not call your name Pashhur, but Terror on Every Side.","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":3},{"ref":"Jeremiah 20:4","short":"Jer 20:4","text":"For thus says the LORD: Behold, I will make you a terror to yourself and to all your friends. They shall fall by the sword of their enemies while you look on. And I will give all Judah into the hand of the king of Babylon. He shall carry them captive to Babylon, and shall strike them down with the sword.","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":4},{"ref":"Jeremiah 20:5","short":"Jer 20:5","text":"Moreover, I will give all the wealth of the city, all its gains, all its prized belongings, and all the treasures of the kings of Judah into the hand of their enemies, who shall plunder them and seize them and carry them to Babylon.","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":5},{"ref":"Jeremiah 20:6","short":"Jer 20:6","text":"And you, Pashhur, and all who dwell in your house, shall go into captivity. To Babylon you shall go, and there you shall die, and there you shall be buried, you and all your friends, to whom you have prophesied falsely.”","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":6},{"ref":"Jeremiah 20:7","short":"Jer 20:7","text":"O LORD, you have deceived me, and I was deceived; you are stronger than I, and you have prevailed. I have become a laughingstock all the day; everyone mocks me.","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":7},{"ref":"Jeremiah 20:8","short":"Jer 20:8","text":"For whenever I speak, I cry out, I shout, “Violence and destruction!” For the word of the LORD has become for me a reproach and derision all day long.","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":8},{"ref":"Jeremiah 20:9","short":"Jer 20:9","text":"If I say, “I will not mention him, or speak any more in his name,” there is in my heart as it were a burning fire shut up in my bones, and I am weary with holding it in, and I cannot.","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":9},{"ref":"Jeremiah 20:10","short":"Jer 20:10","text":"For I hear many whispering. Terror is on every side! “Denounce him! Let us denounce him!” say all my close friends, watching for my fall. “Perhaps he will be deceived; then we can overcome him and take our revenge on him.”","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":10},{"ref":"Jeremiah 20:11","short":"Jer 20:11","text":"But the LORD is with me as a dread warrior; therefore my persecutors will stumble; they will not overcome me. They will be greatly shamed, for they will not succeed. Their eternal dishonor will never be forgotten.","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":11},{"ref":"Jeremiah 20:12","short":"Jer 20:12","text":"O LORD of hosts, who tests the righteous, who sees the heart and the mind, let me see your vengeance upon them, for to you have I committed my cause.","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":12},{"ref":"Jeremiah 20:13","short":"Jer 20:13","text":"Sing to the LORD; praise the LORD! For he has delivered the life of the needy from the hand of evildoers.","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":13},{"ref":"Jeremiah 20:14","short":"Jer 20:14","text":"Cursed be the day on which I was born! The day when my mother bore me, let it not be blessed!","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":14},{"ref":"Jeremiah 20:15","short":"Jer 20:15","text":"Cursed be the man who brought the news to my father, “A son is born to you,” making him very glad.","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":15},{"ref":"Jeremiah 20:16","short":"Jer 20:16","text":"Let that man be like the cities that the LORD overthrew without pity; let him hear a cry in the morning and an alarm at noon,","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":16},{"ref":"Jeremiah 20:17","short":"Jer 20:17","text":"because he did not kill me in the womb; so my mother would have been my grave, and her womb forever great.","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":17},{"ref":"Jeremiah 20:18","short":"Jer 20:18","text":"Why did I come out from the womb to see toil and sorrow, and spend my days in shame?","url":"ot/jeremiah/Jeremiah_20.html","book":"Jeremiah","ch":20,"v":18},{"ref":"Jeremiah 21:1","short":"Jer 21:1","text":"This is the word that came to Jeremiah from the LORD, when King Zedekiah sent to him Pashhur the son of Malchiah and Zephaniah the priest, the son of Maaseiah, saying,","url":"ot/jeremiah/Jeremiah_21.html","book":"Jeremiah","ch":21,"v":1},{"ref":"Jeremiah 21:2","short":"Jer 21:2","text":"“Inquire of the LORD for us, for Nebuchadnezzar king of Babylon is making war against us. Perhaps the LORD will deal with us according to all his wonderful deeds and will make him withdraw from us.”","url":"ot/jeremiah/Jeremiah_21.html","book":"Jeremiah","ch":21,"v":2},{"ref":"Jeremiah 21:3","short":"Jer 21:3","text":"Then Jeremiah said to them: “Thus you shall say to Zedekiah,","url":"ot/jeremiah/Jeremiah_21.html","book":"Jeremiah","ch":21,"v":3},{"ref":"Jeremiah 21:4","short":"Jer 21:4","text":"‘Thus says the LORD, the God of Israel: Behold, I will turn back the weapons of war that are in your hands and with which you are fighting against the king of Babylon and against the Chaldeans who are besieging you outside the walls. And I will bring them together into the midst of this city.","url":"ot/jeremiah/Jeremiah_21.html","book":"Jeremiah","ch":21,"v":4},{"ref":"Jeremiah 21:5","short":"Jer 21:5","text":"I myself will fight against you with outstretched hand and strong arm, in anger and in fury and in great wrath.","url":"ot/jeremiah/Jeremiah_21.html","book":"Jeremiah","ch":21,"v":5},{"ref":"Jeremiah 21:6","short":"Jer 21:6","text":"And I will strike down the inhabitants of this city, both man and beast. They shall die of a great pestilence.","url":"ot/jeremiah/Jeremiah_21.html","book":"Jeremiah","ch":21,"v":6},{"ref":"Jeremiah 21:7","short":"Jer 21:7","text":"Afterward, declares the LORD, I will give Zedekiah king of Judah and his servants and the people in this city who survive the pestilence, sword, and famine into the hand of Nebuchadnezzar king of Babylon and into the hand of their enemies, into the hand of those who seek their lives. He shall strike them down with the edge of the sword. He shall not pity them or spare them or have compassion.’","url":"ot/jeremiah/Jeremiah_21.html","book":"Jeremiah","ch":21,"v":7},{"ref":"Jeremiah 21:8","short":"Jer 21:8","text":"“And to this people you shall say: ‘Thus says the LORD: Behold, I set before you the way of life and the way of death.","url":"ot/jeremiah/Jeremiah_21.html","book":"Jeremiah","ch":21,"v":8},{"ref":"Jeremiah 21:9","short":"Jer 21:9","text":"He who stays in this city shall die by the sword, by famine, and by pestilence, but he who goes out and surrenders to the Chaldeans who are besieging you shall live and shall have his life as a prize of war.","url":"ot/jeremiah/Jeremiah_21.html","book":"Jeremiah","ch":21,"v":9},{"ref":"Jeremiah 21:10","short":"Jer 21:10","text":"For I have set my face against this city for harm and not for good, declares the LORD: it shall be given into the hand of the king of Babylon, and he shall burn it with fire.’","url":"ot/jeremiah/Jeremiah_21.html","book":"Jeremiah","ch":21,"v":10},{"ref":"Jeremiah 21:11","short":"Jer 21:11","text":"“And to the house of the king of Judah say, ‘Hear the word of the LORD,","url":"ot/jeremiah/Jeremiah_21.html","book":"Jeremiah","ch":21,"v":11},{"ref":"Jeremiah 21:12","short":"Jer 21:12","text":"O house of David! Thus says the LORD: “‘Execute justice in the morning, and deliver from the hand of the oppressor him who has been robbed, lest my wrath go forth like fire, and burn with none to quench it, because of your evil deeds.’”","url":"ot/jeremiah/Jeremiah_21.html","book":"Jeremiah","ch":21,"v":12},{"ref":"Jeremiah 21:13","short":"Jer 21:13","text":"“Behold, I am against you, O inhabitant of the valley, O rock of the plain, declares the LORD; you who say, ‘Who shall come down against us, or who shall enter our habitations?’","url":"ot/jeremiah/Jeremiah_21.html","book":"Jeremiah","ch":21,"v":13},{"ref":"Jeremiah 21:14","short":"Jer 21:14","text":"I will punish you according to the fruit of your deeds, declares the LORD; I will kindle a fire in her forest, and it shall devour all that is around her.”","url":"ot/jeremiah/Jeremiah_21.html","book":"Jeremiah","ch":21,"v":14},{"ref":"Jeremiah 22:1","short":"Jer 22:1","text":"Thus says the LORD: “Go down to the house of the king of Judah and speak there this word,","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":1},{"ref":"Jeremiah 22:2","short":"Jer 22:2","text":"and say, ‘Hear the word of the LORD, O king of Judah, who sits on the throne of David, you, and your servants, and your people who enter these gates.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":2},{"ref":"Jeremiah 22:3","short":"Jer 22:3","text":"Thus says the LORD: Do justice and righteousness, and deliver from the hand of the oppressor him who has been robbed. And do no wrong or violence to the resident alien, the fatherless, and the widow, nor shed innocent blood in this place.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":3},{"ref":"Jeremiah 22:4","short":"Jer 22:4","text":"For if you will indeed obey this word, then there shall enter the gates of this house kings who sit on the throne of David, riding in chariots and on horses, they and their servants and their people.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":4},{"ref":"Jeremiah 22:5","short":"Jer 22:5","text":"But if you will not obey these words, I swear by myself, declares the LORD, that this house shall become a desolation.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":5},{"ref":"Jeremiah 22:6","short":"Jer 22:6","text":"For thus says the LORD concerning the house of the king of Judah: “‘You are like Gilead to me, like the summit of Lebanon, yet surely I will make you a desert, an uninhabited city.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":6},{"ref":"Jeremiah 22:7","short":"Jer 22:7","text":"I will prepare destroyers against you, each with his weapons, and they shall cut down your choicest cedars and cast them into the fire.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":7},{"ref":"Jeremiah 22:8","short":"Jer 22:8","text":"“‘And many nations will pass by this city, and every man will say to his neighbor, “Why has the LORD dealt thus with this great city?”","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":8},{"ref":"Jeremiah 22:9","short":"Jer 22:9","text":"And they will answer, “Because they have forsaken the covenant of the LORD their God and worshiped other gods and served them.”’”","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":9},{"ref":"Jeremiah 22:10","short":"Jer 22:10","text":"Weep not for him who is dead, nor grieve for him, but weep bitterly for him who goes away, for he shall return no more to see his native land.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":10},{"ref":"Jeremiah 22:11","short":"Jer 22:11","text":"For thus says the LORD concerning Shallum the son of Josiah, king of Judah, who reigned instead of Josiah his father, and who went away from this place: “He shall return here no more,","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":11},{"ref":"Jeremiah 22:12","short":"Jer 22:12","text":"but in the place where they have carried him captive, there shall he die, and he shall never see this land again.”","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":12},{"ref":"Jeremiah 22:13","short":"Jer 22:13","text":"“Woe to him who builds his house by unrighteousness, and his upper rooms by injustice, who makes his neighbor serve him for nothing and does not give him his wages,","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":13},{"ref":"Jeremiah 22:14","short":"Jer 22:14","text":"who says, ‘I will build myself a great house with spacious upper rooms,’ who cuts out windows for it, paneling it with cedar and painting it with vermilion.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":14},{"ref":"Jeremiah 22:15","short":"Jer 22:15","text":"Do you think you are a king because you compete in cedar? Did not your father eat and drink and do justice and righteousness? Then it was well with him.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":15},{"ref":"Jeremiah 22:16","short":"Jer 22:16","text":"He judged the cause of the poor and needy; then it was well. Is not this to know me? declares the LORD.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":16},{"ref":"Jeremiah 22:17","short":"Jer 22:17","text":"But you have eyes and heart only for your dishonest gain, for shedding innocent blood, and for practicing oppression and violence.”","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":17},{"ref":"Jeremiah 22:18","short":"Jer 22:18","text":"Therefore thus says the LORD concerning Jehoiakim the son of Josiah, king of Judah: “They shall not lament for him, saying, ‘Ah, my brother!’ or ‘Ah, sister!’ They shall not lament for him, saying, ‘Ah, lord!’ or ‘Ah, his majesty!’","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":18},{"ref":"Jeremiah 22:19","short":"Jer 22:19","text":"With the burial of a donkey he shall be buried, dragged and dumped beyond the gates of Jerusalem.”","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":19},{"ref":"Jeremiah 22:20","short":"Jer 22:20","text":"“Go up to Lebanon, and cry out, and lift up your voice in Bashan; cry out from Abarim, for all your lovers are destroyed.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":20},{"ref":"Jeremiah 22:21","short":"Jer 22:21","text":"I spoke to you in your prosperity, but you said, ‘I will not listen.’ This has been your way from your youth, that you have not obeyed my voice.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":21},{"ref":"Jeremiah 22:22","short":"Jer 22:22","text":"The wind shall shepherd all your shepherds, and your lovers shall go into captivity; then you will be ashamed and confounded because of all your evil.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":22},{"ref":"Jeremiah 22:23","short":"Jer 22:23","text":"O inhabitant of Lebanon, nested among the cedars, how you will be pitied when pangs come upon you, pain as of a woman in labor!”","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":23},{"ref":"Jeremiah 22:24","short":"Jer 22:24","text":"“As I live, declares the LORD, though Coniah the son of Jehoiakim, king of Judah, were the signet ring on my right hand, yet I would tear you off","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":24},{"ref":"Jeremiah 22:25","short":"Jer 22:25","text":"and give you into the hand of those who seek your life, into the hand of those of whom you are afraid, even into the hand of Nebuchadnezzar king of Babylon and into the hand of the Chaldeans.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":25},{"ref":"Jeremiah 22:26","short":"Jer 22:26","text":"I will hurl you and the mother who bore you into another country, where you were not born, and there you shall die.","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":26},{"ref":"Jeremiah 22:27","short":"Jer 22:27","text":"But to the land to which they will long to return, there they shall not return.”","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":27},{"ref":"Jeremiah 22:28","short":"Jer 22:28","text":"Is this man Coniah a despised, broken pot, a vessel no one cares for? Why are he and his children hurled and cast into a land that they do not know?","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":28},{"ref":"Jeremiah 22:29","short":"Jer 22:29","text":"O land, land, land, hear the word of the LORD!","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":29},{"ref":"Jeremiah 22:30","short":"Jer 22:30","text":"Thus says the LORD: “Write this man down as childless, a man who shall not succeed in his days, for none of his offspring shall succeed in sitting on the throne of David and ruling again in Judah.”","url":"ot/jeremiah/Jeremiah_22.html","book":"Jeremiah","ch":22,"v":30},{"ref":"Jeremiah 23:1","short":"Jer 23:1","text":"“Woe to the shepherds who destroy and scatter the sheep of my pasture!” declares the LORD.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":1},{"ref":"Jeremiah 23:2","short":"Jer 23:2","text":"Therefore thus says the LORD, the God of Israel, concerning the shepherds who care for my people: “You have scattered my flock and have driven them away, and you have not attended to them. Behold, I will attend to you for your evil deeds, declares the LORD.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":2},{"ref":"Jeremiah 23:3","short":"Jer 23:3","text":"Then I will gather the remnant of my flock out of all the countries where I have driven them, and I will bring them back to their fold, and they shall be fruitful and multiply.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":3},{"ref":"Jeremiah 23:4","short":"Jer 23:4","text":"I will set shepherds over them who will care for them, and they shall fear no more, nor be dismayed, neither shall any be missing, declares the LORD.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":4},{"ref":"Jeremiah 23:5","short":"Jer 23:5","text":"“Behold, the days are coming, declares the LORD, when I will raise up for David a righteous Branch, and he shall reign as king and deal wisely, and shall execute justice and righteousness in the land.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":5},{"ref":"Jeremiah 23:6","short":"Jer 23:6","text":"In his days Judah will be saved, and Israel will dwell securely. And this is the name by which he will be called: ‘The LORD is our righteousness.’","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":6},{"ref":"Jeremiah 23:7","short":"Jer 23:7","text":"“Therefore, behold, the days are coming, declares the LORD, when they shall no longer say, ‘As the LORD lives who brought up the people of Israel out of the land of Egypt,’","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":7},{"ref":"Jeremiah 23:8","short":"Jer 23:8","text":"but ‘As the LORD lives who brought up and led the offspring of the house of Israel out of the north country and out of all the countries where he had driven them.’ Then they shall dwell in their own land.”","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":8},{"ref":"Jeremiah 23:9","short":"Jer 23:9","text":"Concerning the prophets: My heart is broken within me; all my bones shake; I am like a drunken man, like a man overcome by wine, because of the LORD and because of his holy words.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":9},{"ref":"Jeremiah 23:10","short":"Jer 23:10","text":"For the land is full of adulterers; because of the curse the land mourns, and the pastures of the wilderness are dried up. Their course is evil, and their might is not right.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":10},{"ref":"Jeremiah 23:11","short":"Jer 23:11","text":"“Both prophet and priest are ungodly; even in my house I have found their evil, declares the LORD.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":11},{"ref":"Jeremiah 23:12","short":"Jer 23:12","text":"Therefore their way shall be to them like slippery paths in the darkness, into which they shall be driven and fall, for I will bring disaster upon them in the year of their punishment, declares the LORD.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":12},{"ref":"Jeremiah 23:13","short":"Jer 23:13","text":"In the prophets of Samaria I saw an unsavory thing: they prophesied by Baal and led my people Israel astray.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":13},{"ref":"Jeremiah 23:14","short":"Jer 23:14","text":"But in the prophets of Jerusalem I have seen a horrible thing: they commit adultery and walk in lies; they strengthen the hands of evildoers, so that no one turns from his evil; all of them have become like Sodom to me, and its inhabitants like Gomorrah.”","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":14},{"ref":"Jeremiah 23:15","short":"Jer 23:15","text":"Therefore thus says the LORD of hosts concerning the prophets: “Behold, I will feed them with bitter food and give them poisoned water to drink, for from the prophets of Jerusalem ungodliness has gone out into all the land.”","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":15},{"ref":"Jeremiah 23:16","short":"Jer 23:16","text":"Thus says the LORD of hosts: “Do not listen to the words of the prophets who prophesy to you, filling you with vain hopes. They speak visions of their own minds, not from the mouth of the LORD.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":16},{"ref":"Jeremiah 23:17","short":"Jer 23:17","text":"They say continually to those who despise the word of the LORD, ‘It shall be well with you’; and to everyone who stubbornly follows his own heart, they say, ‘No disaster shall come upon you.’”","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":17},{"ref":"Jeremiah 23:18","short":"Jer 23:18","text":"For who among them has stood in the council of the LORD to see and to hear his word, or who has paid attention to his word and listened?","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":18},{"ref":"Jeremiah 23:19","short":"Jer 23:19","text":"Behold, the storm of the LORD! Wrath has gone forth, a whirling tempest; it will burst upon the head of the wicked.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":19},{"ref":"Jeremiah 23:20","short":"Jer 23:20","text":"The anger of the LORD will not turn back until he has executed and accomplished the intents of his heart. In the latter days you will understand it clearly.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":20},{"ref":"Jeremiah 23:21","short":"Jer 23:21","text":"“I did not send the prophets, yet they ran; I did not speak to them, yet they prophesied.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":21},{"ref":"Jeremiah 23:22","short":"Jer 23:22","text":"But if they had stood in my council, then they would have proclaimed my words to my people, and they would have turned them from their evil way, and from the evil of their deeds.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":22},{"ref":"Jeremiah 23:23","short":"Jer 23:23","text":"“Am I a God at hand, declares the LORD, and not a God far away?","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":23},{"ref":"Jeremiah 23:24","short":"Jer 23:24","text":"Can a man hide himself in secret places so that I cannot see him? declares the LORD. Do I not fill heaven and earth? declares the LORD.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":24},{"ref":"Jeremiah 23:25","short":"Jer 23:25","text":"I have heard what the prophets have said who prophesy lies in my name, saying, ‘I have dreamed, I have dreamed!’","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":25},{"ref":"Jeremiah 23:26","short":"Jer 23:26","text":"How long shall there be lies in the heart of the prophets who prophesy lies, and who prophesy the deceit of their own heart,","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":26},{"ref":"Jeremiah 23:27","short":"Jer 23:27","text":"who think to make my people forget my name by their dreams that they tell one another, even as their fathers forgot my name for Baal?","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":27},{"ref":"Jeremiah 23:28","short":"Jer 23:28","text":"Let the prophet who has a dream tell the dream, but let him who has my word speak my word faithfully. What has straw in common with wheat? declares the LORD.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":28},{"ref":"Jeremiah 23:29","short":"Jer 23:29","text":"Is not my word like fire, declares the LORD, and like a hammer that breaks the rock in pieces?","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":29},{"ref":"Jeremiah 23:30","short":"Jer 23:30","text":"Therefore, behold, I am against the prophets, declares the LORD, who steal my words from one another.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":30},{"ref":"Jeremiah 23:31","short":"Jer 23:31","text":"Behold, I am against the prophets, declares the LORD, who use their tongues and declare, ‘declares the LORD.’","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":31},{"ref":"Jeremiah 23:32","short":"Jer 23:32","text":"Behold, I am against those who prophesy lying dreams, declares the LORD, and who tell them and lead my people astray by their lies and their recklessness, when I did not send them or charge them. So they do not profit this people at all, declares the LORD.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":32},{"ref":"Jeremiah 23:33","short":"Jer 23:33","text":"“When one of this people, or a prophet or a priest asks you, ‘What is the burden of the LORD?’ you shall say to them, ‘You are the burden, and I will cast you off, declares the LORD.’","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":33},{"ref":"Jeremiah 23:34","short":"Jer 23:34","text":"And as for the prophet, priest, or one of the people who says, ‘The burden of the LORD,’ I will punish that man and his household.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":34},{"ref":"Jeremiah 23:35","short":"Jer 23:35","text":"Thus shall you say, every one to his neighbor and every one to his brother, ‘What has the LORD answered?’ or ‘What has the LORD spoken?’","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":35},{"ref":"Jeremiah 23:36","short":"Jer 23:36","text":"But ‘the burden of the LORD’ you shall mention no more, for the burden is every man’s own word, and you pervert the words of the living God, the LORD of hosts, our God.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":36},{"ref":"Jeremiah 23:37","short":"Jer 23:37","text":"Thus you shall say to the prophet, ‘What has the LORD answered you?’ or ‘What has the LORD spoken?’","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":37},{"ref":"Jeremiah 23:38","short":"Jer 23:38","text":"But if you say, ‘The burden of the LORD,’ thus says the LORD, ‘Because you have said these words, “The burden of the LORD,” when I sent to you, saying, “You shall not say, ‘The burden of the LORD,’”","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":38},{"ref":"Jeremiah 23:39","short":"Jer 23:39","text":"therefore, behold, I will surely lift you up and cast you away from my presence, you and the city that I gave to you and your fathers.","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":39},{"ref":"Jeremiah 23:40","short":"Jer 23:40","text":"And I will bring upon you everlasting reproach and perpetual shame, which shall not be forgotten.’”","url":"ot/jeremiah/Jeremiah_23.html","book":"Jeremiah","ch":23,"v":40},{"ref":"Jeremiah 24:1","short":"Jer 24:1","text":"After Nebuchadnezzar king of Babylon had taken into exile from Jerusalem Jeconiah the son of Jehoiakim, king of Judah, together with the officials of Judah, the craftsmen, and the metal workers, and had brought them to Babylon, the LORD showed me this vision: behold, two baskets of figs placed before the temple of the LORD.","url":"ot/jeremiah/Jeremiah_24.html","book":"Jeremiah","ch":24,"v":1},{"ref":"Jeremiah 24:2","short":"Jer 24:2","text":"One basket had very good figs, like first-ripe figs, but the other basket had very bad figs, so bad that they could not be eaten.","url":"ot/jeremiah/Jeremiah_24.html","book":"Jeremiah","ch":24,"v":2},{"ref":"Jeremiah 24:3","short":"Jer 24:3","text":"And the LORD said to me, “What do you see, Jeremiah?” I said, “Figs, the good figs very good, and the bad figs very bad, so bad that they cannot be eaten.”","url":"ot/jeremiah/Jeremiah_24.html","book":"Jeremiah","ch":24,"v":3},{"ref":"Jeremiah 24:4","short":"Jer 24:4","text":"Then the word of the LORD came to me:","url":"ot/jeremiah/Jeremiah_24.html","book":"Jeremiah","ch":24,"v":4},{"ref":"Jeremiah 24:5","short":"Jer 24:5","text":"“Thus says the LORD, the God of Israel: Like these good figs, so I will regard as good the exiles from Judah, whom I have sent away from this place to the land of the Chaldeans.","url":"ot/jeremiah/Jeremiah_24.html","book":"Jeremiah","ch":24,"v":5},{"ref":"Jeremiah 24:6","short":"Jer 24:6","text":"I will set my eyes on them for good, and I will bring them back to this land. I will build them up, and not tear them down; I will plant them, and not pluck them up.","url":"ot/jeremiah/Jeremiah_24.html","book":"Jeremiah","ch":24,"v":6},{"ref":"Jeremiah 24:7","short":"Jer 24:7","text":"I will give them a heart to know me, that I am the LORD, and they shall be my people and I will be their God, for they shall return to me with their whole heart.","url":"ot/jeremiah/Jeremiah_24.html","book":"Jeremiah","ch":24,"v":7},{"ref":"Jeremiah 24:8","short":"Jer 24:8","text":"“But thus says the LORD: Like the bad figs that are so bad they cannot be eaten, so will I treat Zedekiah the king of Judah, his officials, the remnant of Jerusalem who remain in this land, and those who dwell in the land of Egypt.","url":"ot/jeremiah/Jeremiah_24.html","book":"Jeremiah","ch":24,"v":8},{"ref":"Jeremiah 24:9","short":"Jer 24:9","text":"I will make them a horror to all the kingdoms of the earth, to be a reproach, a byword, a taunt, and a curse in all the places where I shall drive them.","url":"ot/jeremiah/Jeremiah_24.html","book":"Jeremiah","ch":24,"v":9},{"ref":"Jeremiah 24:10","short":"Jer 24:10","text":"And I will send sword, famine, and pestilence upon them, until they shall be utterly destroyed from the land that I gave to them and their fathers.”","url":"ot/jeremiah/Jeremiah_24.html","book":"Jeremiah","ch":24,"v":10},{"ref":"Jeremiah 25:1","short":"Jer 25:1","text":"The word that came to Jeremiah concerning all the people of Judah, in the fourth year of Jehoiakim the son of Josiah, king of Judah (that was the first year of Nebuchadnezzar king of Babylon),","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":1},{"ref":"Jeremiah 25:2","short":"Jer 25:2","text":"which Jeremiah the prophet spoke to all the people of Judah and all the inhabitants of Jerusalem:","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":2},{"ref":"Jeremiah 25:3","short":"Jer 25:3","text":"“For twenty-three years, from the thirteenth year of Josiah the son of Amon, king of Judah, to this day, the word of the LORD has come to me, and I have spoken persistently to you, but you have not listened.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":3},{"ref":"Jeremiah 25:4","short":"Jer 25:4","text":"You have neither listened nor inclined your ears to hear, although the LORD persistently sent to you all his servants the prophets,","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":4},{"ref":"Jeremiah 25:5","short":"Jer 25:5","text":"saying, ‘Turn now, every one of you, from his evil way and evil deeds, and dwell upon the land that the LORD has given to you and your fathers from of old and forever.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":5},{"ref":"Jeremiah 25:6","short":"Jer 25:6","text":"Do not go after other gods to serve and worship them, or provoke me to anger with the work of your hands. Then I will do you no harm.’","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":6},{"ref":"Jeremiah 25:7","short":"Jer 25:7","text":"Yet you have not listened to me, declares the LORD, that you might provoke me to anger with the work of your hands to your own harm.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":7},{"ref":"Jeremiah 25:8","short":"Jer 25:8","text":"“Therefore thus says the LORD of hosts: Because you have not obeyed my words,","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":8},{"ref":"Jeremiah 25:9","short":"Jer 25:9","text":"behold, I will send for all the tribes of the north, declares the LORD, and for Nebuchadnezzar the king of Babylon, my servant, and I will bring them against this land and its inhabitants, and against all these surrounding nations. I will devote them to destruction, and make them a horror, a hissing, and an everlasting desolation.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":9},{"ref":"Jeremiah 25:10","short":"Jer 25:10","text":"Moreover, I will banish from them the voice of mirth and the voice of gladness, the voice of the bridegroom and the voice of the bride, the grinding of the millstones and the light of the lamp.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":10},{"ref":"Jeremiah 25:11","short":"Jer 25:11","text":"This whole land shall become a ruin and a waste, and these nations shall serve the king of Babylon seventy years.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":11},{"ref":"Jeremiah 25:12","short":"Jer 25:12","text":"Then after seventy years are completed, I will punish the king of Babylon and that nation, the land of the Chaldeans, for their iniquity, declares the LORD, making the land an everlasting waste.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":12},{"ref":"Jeremiah 25:13","short":"Jer 25:13","text":"I will bring upon that land all the words that I have uttered against it, everything written in this book, which Jeremiah prophesied against all the nations.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":13},{"ref":"Jeremiah 25:14","short":"Jer 25:14","text":"For many nations and great kings shall make slaves even of them, and I will recompense them according to their deeds and the work of their hands.”","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":14},{"ref":"Jeremiah 25:15","short":"Jer 25:15","text":"Thus the LORD, the God of Israel, said to me: “Take from my hand this cup of the wine of wrath, and make all the nations to whom I send you drink it.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":15},{"ref":"Jeremiah 25:16","short":"Jer 25:16","text":"They shall drink and stagger and be crazed because of the sword that I am sending among them.”","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":16},{"ref":"Jeremiah 25:17","short":"Jer 25:17","text":"So I took the cup from the LORD’s hand, and made all the nations to whom the LORD sent me drink it:","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":17},{"ref":"Jeremiah 25:18","short":"Jer 25:18","text":"Jerusalem and the cities of Judah, its kings and officials, to make them a desolation and a waste, a hissing and a curse, as at this day;","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":18},{"ref":"Jeremiah 25:19","short":"Jer 25:19","text":"Pharaoh king of Egypt, his servants, his officials, all his people,","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":19},{"ref":"Jeremiah 25:20","short":"Jer 25:20","text":"and all the mixed tribes among them; all the kings of the land of Uz and all the kings of the land of the Philistines (Ashkelon, Gaza, Ekron, and the remnant of Ashdod);","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":20},{"ref":"Jeremiah 25:21","short":"Jer 25:21","text":"Edom, Moab, and the sons of Ammon;","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":21},{"ref":"Jeremiah 25:22","short":"Jer 25:22","text":"all the kings of Tyre, all the kings of Sidon, and the kings of the coastland across the sea;","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":22},{"ref":"Jeremiah 25:23","short":"Jer 25:23","text":"Dedan, Tema, Buz, and all who cut the corners of their hair;","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":23},{"ref":"Jeremiah 25:24","short":"Jer 25:24","text":"all the kings of Arabia and all the kings of the mixed tribes who dwell in the desert;","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":24},{"ref":"Jeremiah 25:25","short":"Jer 25:25","text":"all the kings of Zimri, all the kings of Elam, and all the kings of Media;","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":25},{"ref":"Jeremiah 25:26","short":"Jer 25:26","text":"all the kings of the north, far and near, one after another, and all the kingdoms of the world that are on the face of the earth. And after them the king of Babylon shall drink.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":26},{"ref":"Jeremiah 25:27","short":"Jer 25:27","text":"“Then you shall say to them, ‘Thus says the LORD of hosts, the God of Israel: Drink, be drunk and vomit, fall and rise no more, because of the sword that I am sending among you.’","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":27},{"ref":"Jeremiah 25:28","short":"Jer 25:28","text":"“And if they refuse to accept the cup from your hand to drink, then you shall say to them, ‘Thus says the LORD of hosts: You must drink!","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":28},{"ref":"Jeremiah 25:29","short":"Jer 25:29","text":"For behold, I begin to work disaster at the city that is called by my name, and shall you go unpunished? You shall not go unpunished, for I am summoning a sword against all the inhabitants of the earth, declares the LORD of hosts.’","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":29},{"ref":"Jeremiah 25:30","short":"Jer 25:30","text":"“You, therefore, shall prophesy against them all these words, and say to them: “‘The LORD will roar from on high, and from his holy habitation utter his voice; he will roar mightily against his fold, and shout, like those who tread grapes, against all the inhabitants of the earth.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":30},{"ref":"Jeremiah 25:31","short":"Jer 25:31","text":"The clamor will resound to the ends of the earth, for the LORD has an indictment against the nations; he is entering into judgment with all flesh, and the wicked he will put to the sword, declares the LORD.’","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":31},{"ref":"Jeremiah 25:32","short":"Jer 25:32","text":"“Thus says the LORD of hosts: Behold, disaster is going forth from nation to nation, and a great tempest is stirring from the farthest parts of the earth!","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":32},{"ref":"Jeremiah 25:33","short":"Jer 25:33","text":"“And those pierced by the LORD on that day shall extend from one end of the earth to the other. They shall not be lamented, or gathered, or buried; they shall be dung on the surface of the ground.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":33},{"ref":"Jeremiah 25:34","short":"Jer 25:34","text":"“Wail, you shepherds, and cry out, and roll in ashes, you lords of the flock, for the days of your slaughter and dispersion have come, and you shall fall like a choice vessel.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":34},{"ref":"Jeremiah 25:35","short":"Jer 25:35","text":"No refuge will remain for the shepherds, nor escape for the lords of the flock.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":35},{"ref":"Jeremiah 25:36","short":"Jer 25:36","text":"A voice—the cry of the shepherds, and the wail of the lords of the flock! For the LORD is laying waste their pasture,","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":36},{"ref":"Jeremiah 25:37","short":"Jer 25:37","text":"and the peaceful folds are devastated because of the fierce anger of the LORD.","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":37},{"ref":"Jeremiah 25:38","short":"Jer 25:38","text":"Like a lion he has left his lair, for their land has become a waste because of the sword of the oppressor, and because of his fierce anger.”","url":"ot/jeremiah/Jeremiah_25.html","book":"Jeremiah","ch":25,"v":38},{"ref":"Jeremiah 26:1","short":"Jer 26:1","text":"In the beginning of the reign of Jehoiakim the son of Josiah, king of Judah, this word came from the LORD:","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":1},{"ref":"Jeremiah 26:2","short":"Jer 26:2","text":"“Thus says the LORD: Stand in the court of the LORD’s house, and speak to all the cities of Judah that come to worship in the house of the LORD all the words that I command you to speak to them; do not hold back a word.","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":2},{"ref":"Jeremiah 26:3","short":"Jer 26:3","text":"It may be they will listen, and every one turn from his evil way, that I may relent of the disaster that I intend to do to them because of their evil deeds.","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":3},{"ref":"Jeremiah 26:4","short":"Jer 26:4","text":"You shall say to them, ‘Thus says the LORD: If you will not listen to me, to walk in my law that I have set before you,","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":4},{"ref":"Jeremiah 26:5","short":"Jer 26:5","text":"and to listen to the words of my servants the prophets whom I send to you urgently, though you have not listened,","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":5},{"ref":"Jeremiah 26:6","short":"Jer 26:6","text":"then I will make this house like Shiloh, and I will make this city a curse for all the nations of the earth.’”","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":6},{"ref":"Jeremiah 26:7","short":"Jer 26:7","text":"The priests and the prophets and all the people heard Jeremiah speaking these words in the house of the LORD.","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":7},{"ref":"Jeremiah 26:8","short":"Jer 26:8","text":"And when Jeremiah had finished speaking all that the LORD had commanded him to speak to all the people, then the priests and the prophets and all the people laid hold of him, saying, “You shall die!","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":8},{"ref":"Jeremiah 26:9","short":"Jer 26:9","text":"Why have you prophesied in the name of the LORD, saying, ‘This house shall be like Shiloh, and this city shall be desolate, without inhabitant’?” And all the people gathered around Jeremiah in the house of the LORD.","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":9},{"ref":"Jeremiah 26:10","short":"Jer 26:10","text":"When the officials of Judah heard these things, they came up from the king’s house to the house of the LORD and took their seat in the entry of the New Gate of the house of the LORD.","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":10},{"ref":"Jeremiah 26:11","short":"Jer 26:11","text":"Then the priests and the prophets said to the officials and to all the people, “This man deserves the sentence of death, because he has prophesied against this city, as you have heard with your own ears.”","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":11},{"ref":"Jeremiah 26:12","short":"Jer 26:12","text":"Then Jeremiah spoke to all the officials and all the people, saying, “The LORD sent me to prophesy against this house and this city all the words you have heard.","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":12},{"ref":"Jeremiah 26:13","short":"Jer 26:13","text":"Now therefore mend your ways and your deeds, and obey the voice of the LORD your God, and the LORD will relent of the disaster that he has pronounced against you.","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":13},{"ref":"Jeremiah 26:14","short":"Jer 26:14","text":"But as for me, behold, I am in your hands. Do with me as seems good and right to you.","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":14},{"ref":"Jeremiah 26:15","short":"Jer 26:15","text":"Only know for certain that if you put me to death, you will bring innocent blood upon yourselves and upon this city and its inhabitants, for in truth the LORD sent me to you to speak all these words in your ears.”","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":15},{"ref":"Jeremiah 26:16","short":"Jer 26:16","text":"Then the officials and all the people said to the priests and the prophets, “This man does not deserve the sentence of death, for he has spoken to us in the name of the LORD our God.”","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":16},{"ref":"Jeremiah 26:17","short":"Jer 26:17","text":"And certain of the elders of the land arose and spoke to all the assembled people, saying,","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":17},{"ref":"Jeremiah 26:18","short":"Jer 26:18","text":"“Micah of Moresheth prophesied in the days of Hezekiah king of Judah, and said to all the people of Judah: ‘Thus says the LORD of hosts, “‘Zion shall be plowed as a field; Jerusalem shall become a heap of ruins, and the mountain of the house a wooded height.’","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":18},{"ref":"Jeremiah 26:19","short":"Jer 26:19","text":"Did Hezekiah king of Judah and all Judah put him to death? Did he not fear the LORD and entreat the favor of the LORD, and did not the LORD relent of the disaster that he had pronounced against them? But we are about to bring great disaster upon ourselves.”","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":19},{"ref":"Jeremiah 26:20","short":"Jer 26:20","text":"There was another man who prophesied in the name of the LORD, Uriah the son of Shemaiah from Kiriath-jearim. He prophesied against this city and against this land in words like those of Jeremiah.","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":20},{"ref":"Jeremiah 26:21","short":"Jer 26:21","text":"And when King Jehoiakim, with all his warriors and all the officials, heard his words, the king sought to put him to death. But when Uriah heard of it, he was afraid and fled and escaped to Egypt.","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":21},{"ref":"Jeremiah 26:22","short":"Jer 26:22","text":"Then King Jehoiakim sent to Egypt certain men, Elnathan the son of Achbor and others with him,","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":22},{"ref":"Jeremiah 26:23","short":"Jer 26:23","text":"and they took Uriah from Egypt and brought him to King Jehoiakim, who struck him down with the sword and dumped his dead body into the burial place of the common people.","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":23},{"ref":"Jeremiah 26:24","short":"Jer 26:24","text":"But the hand of Ahikam the son of Shaphan was with Jeremiah so that he was not given over to the people to be put to death.","url":"ot/jeremiah/Jeremiah_26.html","book":"Jeremiah","ch":26,"v":24},{"ref":"Jeremiah 27:1","short":"Jer 27:1","text":"In the beginning of the reign of Zedekiah the son of Josiah, king of Judah, this word came to Jeremiah from the LORD.","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":1},{"ref":"Jeremiah 27:2","short":"Jer 27:2","text":"Thus the LORD said to me: “Make yourself straps and yoke-bars, and put them on your neck.","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":2},{"ref":"Jeremiah 27:3","short":"Jer 27:3","text":"Send word to the king of Edom, the king of Moab, the king of the sons of Ammon, the king of Tyre, and the king of Sidon by the hand of the envoys who have come to Jerusalem to Zedekiah king of Judah.","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":3},{"ref":"Jeremiah 27:4","short":"Jer 27:4","text":"Give them this charge for their masters: ‘Thus says the LORD of hosts, the God of Israel: This is what you shall say to your masters:","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":4},{"ref":"Jeremiah 27:5","short":"Jer 27:5","text":"“It is I who by my great power and my outstretched arm have made the earth, with the men and animals that are on the earth, and I give it to whomever it seems right to me.","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":5},{"ref":"Jeremiah 27:6","short":"Jer 27:6","text":"Now I have given all these lands into the hand of Nebuchadnezzar, the king of Babylon, my servant, and I have given him also the beasts of the field to serve him.","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":6},{"ref":"Jeremiah 27:7","short":"Jer 27:7","text":"All the nations shall serve him and his son and his grandson, until the time of his own land comes. Then many nations and great kings shall make him their slave.","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":7},{"ref":"Jeremiah 27:8","short":"Jer 27:8","text":"“‘“But if any nation or kingdom will not serve this Nebuchadnezzar king of Babylon, and put its neck under the yoke of the king of Babylon, I will punish that nation with the sword, with famine, and with pestilence, declares the LORD, until I have consumed it by his hand.","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":8},{"ref":"Jeremiah 27:9","short":"Jer 27:9","text":"So do not listen to your prophets, your diviners, your dreamers, your fortune-tellers, or your sorcerers, who are saying to you, ‘You shall not serve the king of Babylon.’","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":9},{"ref":"Jeremiah 27:10","short":"Jer 27:10","text":"For it is a lie that they are prophesying to you, with the result that you will be removed far from your land, and I will drive you out, and you will perish.","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":10},{"ref":"Jeremiah 27:11","short":"Jer 27:11","text":"But any nation that will bring its neck under the yoke of the king of Babylon and serve him, I will leave on its own land, to work it and dwell there, declares the LORD.”’”","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":11},{"ref":"Jeremiah 27:12","short":"Jer 27:12","text":"To Zedekiah king of Judah I spoke in like manner: “Bring your necks under the yoke of the king of Babylon, and serve him and his people and live.","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":12},{"ref":"Jeremiah 27:13","short":"Jer 27:13","text":"Why will you and your people die by the sword, by famine, and by pestilence, as the LORD has spoken concerning any nation that will not serve the king of Babylon?","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":13},{"ref":"Jeremiah 27:14","short":"Jer 27:14","text":"Do not listen to the words of the prophets who are saying to you, ‘You shall not serve the king of Babylon,’ for it is a lie that they are prophesying to you.","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":14},{"ref":"Jeremiah 27:15","short":"Jer 27:15","text":"I have not sent them, declares the LORD, but they are prophesying falsely in my name, with the result that I will drive you out and you will perish, you and the prophets who are prophesying to you.”","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":15},{"ref":"Jeremiah 27:16","short":"Jer 27:16","text":"Then I spoke to the priests and to all this people, saying, “Thus says the LORD: Do not listen to the words of your prophets who are prophesying to you, saying, ‘Behold, the vessels of the LORD’s house will now shortly be brought back from Babylon,’ for it is a lie that they are prophesying to you.","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":16},{"ref":"Jeremiah 27:17","short":"Jer 27:17","text":"Do not listen to them; serve the king of Babylon and live. Why should this city become a desolation?","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":17},{"ref":"Jeremiah 27:18","short":"Jer 27:18","text":"If they are prophets, and if the word of the LORD is with them, then let them intercede with the LORD of hosts, that the vessels that are left in the house of the LORD, in the house of the king of Judah, and in Jerusalem may not go to Babylon.","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":18},{"ref":"Jeremiah 27:19","short":"Jer 27:19","text":"For thus says the LORD of hosts concerning the pillars, the sea, the stands, and the rest of the vessels that are left in this city,","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":19},{"ref":"Jeremiah 27:20","short":"Jer 27:20","text":"which Nebuchadnezzar king of Babylon did not take away, when he took into exile from Jerusalem to Babylon Jeconiah the son of Jehoiakim, king of Judah, and all the nobles of Judah and Jerusalem—","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":20},{"ref":"Jeremiah 27:21","short":"Jer 27:21","text":"thus says the LORD of hosts, the God of Israel, concerning the vessels that are left in the house of the LORD, in the house of the king of Judah, and in Jerusalem:","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":21},{"ref":"Jeremiah 27:22","short":"Jer 27:22","text":"They shall be carried to Babylon and remain there until the day when I visit them, declares the LORD. Then I will bring them back and restore them to this place.”","url":"ot/jeremiah/Jeremiah_27.html","book":"Jeremiah","ch":27,"v":22},{"ref":"Jeremiah 28:1","short":"Jer 28:1","text":"In that same year, at the beginning of the reign of Zedekiah king of Judah, in the fifth month of the fourth year, Hananiah the son of Azzur, the prophet from Gibeon, spoke to me in the house of the LORD, in the presence of the priests and all the people, saying,","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":1},{"ref":"Jeremiah 28:2","short":"Jer 28:2","text":"“Thus says the LORD of hosts, the God of Israel: I have broken the yoke of the king of Babylon.","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":2},{"ref":"Jeremiah 28:3","short":"Jer 28:3","text":"Within two years I will bring back to this place all the vessels of the LORD’s house, which Nebuchadnezzar king of Babylon took away from this place and carried to Babylon.","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":3},{"ref":"Jeremiah 28:4","short":"Jer 28:4","text":"I will also bring back to this place Jeconiah the son of Jehoiakim, king of Judah, and all the exiles from Judah who went to Babylon, declares the LORD, for I will break the yoke of the king of Babylon.”","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":4},{"ref":"Jeremiah 28:5","short":"Jer 28:5","text":"Then the prophet Jeremiah spoke to Hananiah the prophet in the presence of the priests and all the people who were standing in the house of the LORD,","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":5},{"ref":"Jeremiah 28:6","short":"Jer 28:6","text":"and the prophet Jeremiah said, “Amen! May the LORD do so; may the LORD make the words that you have prophesied come true, and bring back to this place from Babylon the vessels of the house of the LORD, and all the exiles.","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":6},{"ref":"Jeremiah 28:7","short":"Jer 28:7","text":"Yet hear now this word that I speak in your hearing and in the hearing of all the people.","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":7},{"ref":"Jeremiah 28:8","short":"Jer 28:8","text":"The prophets who preceded you and me from ancient times prophesied war, famine, and pestilence against many countries and great kingdoms.","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":8},{"ref":"Jeremiah 28:9","short":"Jer 28:9","text":"As for the prophet who prophesies peace, when the word of that prophet comes to pass, then it will be known that the LORD has truly sent the prophet.”","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":9},{"ref":"Jeremiah 28:10","short":"Jer 28:10","text":"Then the prophet Hananiah took the yoke-bars from the neck of Jeremiah the prophet and broke them.","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":10},{"ref":"Jeremiah 28:11","short":"Jer 28:11","text":"And Hananiah spoke in the presence of all the people, saying, “Thus says the LORD: Even so will I break the yoke of Nebuchadnezzar king of Babylon from the neck of all the nations within two years.” But Jeremiah the prophet went his way.","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":11},{"ref":"Jeremiah 28:12","short":"Jer 28:12","text":"Sometime after the prophet Hananiah had broken the yoke-bars from off the neck of Jeremiah the prophet, the word of the LORD came to Jeremiah:","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":12},{"ref":"Jeremiah 28:13","short":"Jer 28:13","text":"“Go, tell Hananiah, ‘Thus says the LORD: You have broken wooden bars, but you have made in their place bars of iron.","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":13},{"ref":"Jeremiah 28:14","short":"Jer 28:14","text":"For thus says the LORD of hosts, the God of Israel: I have put upon the neck of all these nations an iron yoke to serve Nebuchadnezzar king of Babylon, and they shall serve him, for I have given to him even the beasts of the field.’”","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":14},{"ref":"Jeremiah 28:15","short":"Jer 28:15","text":"And Jeremiah the prophet said to the prophet Hananiah, “Listen, Hananiah, the LORD has not sent you, and you have made this people trust in a lie.","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":15},{"ref":"Jeremiah 28:16","short":"Jer 28:16","text":"Therefore thus says the LORD: ‘Behold, I will remove you from the face of the earth. This year you shall die, because you have uttered rebellion against the LORD.’”","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":16},{"ref":"Jeremiah 28:17","short":"Jer 28:17","text":"In that same year, in the seventh month, the prophet Hananiah died.","url":"ot/jeremiah/Jeremiah_28.html","book":"Jeremiah","ch":28,"v":17},{"ref":"Jeremiah 29:1","short":"Jer 29:1","text":"These are the words of the letter that Jeremiah the prophet sent from Jerusalem to the surviving elders of the exiles, and to the priests, the prophets, and all the people, whom Nebuchadnezzar had taken into exile from Jerusalem to Babylon.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":1},{"ref":"Jeremiah 29:2","short":"Jer 29:2","text":"This was after King Jeconiah and the queen mother, the eunuchs, the officials of Judah and Jerusalem, the craftsmen, and the metal workers had departed from Jerusalem.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":2},{"ref":"Jeremiah 29:3","short":"Jer 29:3","text":"The letter was sent by the hand of Elasah the son of Shaphan and Gemariah the son of Hilkiah, whom Zedekiah king of Judah sent to Babylon to Nebuchadnezzar king of Babylon. It said:","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":3},{"ref":"Jeremiah 29:4","short":"Jer 29:4","text":"“Thus says the LORD of hosts, the God of Israel, to all the exiles whom I have sent into exile from Jerusalem to Babylon:","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":4},{"ref":"Jeremiah 29:5","short":"Jer 29:5","text":"Build houses and live in them; plant gardens and eat their produce.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":5},{"ref":"Jeremiah 29:6","short":"Jer 29:6","text":"Take wives and have sons and daughters; take wives for your sons, and give your daughters in marriage, that they may bear sons and daughters; multiply there, and do not decrease.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":6},{"ref":"Jeremiah 29:7","short":"Jer 29:7","text":"But seek the welfare of the city where I have sent you into exile, and pray to the LORD on its behalf, for in its welfare you will find your welfare.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":7},{"ref":"Jeremiah 29:8","short":"Jer 29:8","text":"For thus says the LORD of hosts, the God of Israel: Do not let your prophets and your diviners who are among you deceive you, and do not listen to the dreams that they dream,","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":8},{"ref":"Jeremiah 29:9","short":"Jer 29:9","text":"for it is a lie that they are prophesying to you in my name; I did not send them, declares the LORD.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":9},{"ref":"Jeremiah 29:10","short":"Jer 29:10","text":"“For thus says the LORD: When seventy years are completed for Babylon, I will visit you, and I will fulfill to you my promise and bring you back to this place.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":10},{"ref":"Jeremiah 29:11","short":"Jer 29:11","text":"For I know the plans I have for you, declares the LORD, plans for welfare and not for evil, to give you a future and a hope.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":11},{"ref":"Jeremiah 29:12","short":"Jer 29:12","text":"Then you will call upon me and come and pray to me, and I will hear you.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":12},{"ref":"Jeremiah 29:13","short":"Jer 29:13","text":"You will seek me and find me, when you seek me with all your heart.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":13},{"ref":"Jeremiah 29:14","short":"Jer 29:14","text":"I will be found by you, declares the LORD, and I will restore your fortunes and gather you from all the nations and all the places where I have driven you, declares the LORD, and I will bring you back to the place from which I sent you into exile.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":14},{"ref":"Jeremiah 29:15","short":"Jer 29:15","text":"“Because you have said, ‘The LORD has raised up prophets for us in Babylon,’","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":15},{"ref":"Jeremiah 29:16","short":"Jer 29:16","text":"thus says the LORD concerning the king who sits on the throne of David, and concerning all the people who dwell in this city, your kinsmen who did not go out with you into exile:","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":16},{"ref":"Jeremiah 29:17","short":"Jer 29:17","text":"‘Thus says the LORD of hosts, behold, I am sending on them sword, famine, and pestilence, and I will make them like vile figs that are so rotten they cannot be eaten.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":17},{"ref":"Jeremiah 29:18","short":"Jer 29:18","text":"I will pursue them with sword, famine, and pestilence, and will make them a horror to all the kingdoms of the earth, to be a curse, a terror, a hissing, and a reproach among all the nations where I have driven them,","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":18},{"ref":"Jeremiah 29:19","short":"Jer 29:19","text":"because they did not pay attention to my words, declares the LORD, that I persistently sent to you by my servants the prophets, but you would not listen, declares the LORD.’","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":19},{"ref":"Jeremiah 29:20","short":"Jer 29:20","text":"Hear the word of the LORD, all you exiles whom I sent away from Jerusalem to Babylon:","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":20},{"ref":"Jeremiah 29:21","short":"Jer 29:21","text":"‘Thus says the LORD of hosts, the God of Israel, concerning Ahab the son of Kolaiah and Zedekiah the son of Maaseiah, who are prophesying a lie to you in my name: Behold, I will deliver them into the hand of Nebuchadnezzar king of Babylon, and he shall strike them down before your eyes.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":21},{"ref":"Jeremiah 29:22","short":"Jer 29:22","text":"Because of them this curse shall be used by all the exiles from Judah in Babylon: “The LORD make you like Zedekiah and Ahab, whom the king of Babylon roasted in the fire,”","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":22},{"ref":"Jeremiah 29:23","short":"Jer 29:23","text":"because they have done an outrageous thing in Israel, they have committed adultery with their neighbors’ wives, and they have spoken in my name lying words that I did not command them. I am the one who knows, and I am witness, declares the LORD.’”","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":23},{"ref":"Jeremiah 29:24","short":"Jer 29:24","text":"To Shemaiah of Nehelam you shall say:","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":24},{"ref":"Jeremiah 29:25","short":"Jer 29:25","text":"“Thus says the LORD of hosts, the God of Israel: You have sent letters in your name to all the people who are in Jerusalem, and to Zephaniah the son of Maaseiah the priest, and to all the priests, saying,","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":25},{"ref":"Jeremiah 29:26","short":"Jer 29:26","text":"‘The LORD has made you priest instead of Jehoiada the priest, to have charge in the house of the LORD over every madman who prophesies, to put him in the stocks and neck irons.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":26},{"ref":"Jeremiah 29:27","short":"Jer 29:27","text":"Now why have you not rebuked Jeremiah of Anathoth who is prophesying to you?","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":27},{"ref":"Jeremiah 29:28","short":"Jer 29:28","text":"For he has sent to us in Babylon, saying, “Your exile will be long; build houses and live in them, and plant gardens and eat their produce.”’”","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":28},{"ref":"Jeremiah 29:29","short":"Jer 29:29","text":"Zephaniah the priest read this letter in the hearing of Jeremiah the prophet.","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":29},{"ref":"Jeremiah 29:30","short":"Jer 29:30","text":"Then the word of the LORD came to Jeremiah:","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":30},{"ref":"Jeremiah 29:31","short":"Jer 29:31","text":"“Send to all the exiles, saying, ‘Thus says the LORD concerning Shemaiah of Nehelam: Because Shemaiah had prophesied to you when I did not send him, and has made you trust in a lie,","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":31},{"ref":"Jeremiah 29:32","short":"Jer 29:32","text":"therefore thus says the LORD: Behold, I will punish Shemaiah of Nehelam and his descendants. He shall not have anyone living among this people, and he shall not see the good that I will do to my people, declares the LORD, for he has spoken rebellion against the LORD.’”","url":"ot/jeremiah/Jeremiah_29.html","book":"Jeremiah","ch":29,"v":32},{"ref":"Jeremiah 30:1","short":"Jer 30:1","text":"The word that came to Jeremiah from the LORD:","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":1},{"ref":"Jeremiah 30:2","short":"Jer 30:2","text":"“Thus says the LORD, the God of Israel: Write in a book all the words that I have spoken to you.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":2},{"ref":"Jeremiah 30:3","short":"Jer 30:3","text":"For behold, days are coming, declares the LORD, when I will restore the fortunes of my people, Israel and Judah, says the LORD, and I will bring them back to the land that I gave to their fathers, and they shall take possession of it.”","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":3},{"ref":"Jeremiah 30:4","short":"Jer 30:4","text":"These are the words that the LORD spoke concerning Israel and Judah:","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":4},{"ref":"Jeremiah 30:5","short":"Jer 30:5","text":"“Thus says the LORD: We have heard a cry of panic, of terror, and no peace.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":5},{"ref":"Jeremiah 30:6","short":"Jer 30:6","text":"Ask now, and see, can a man bear a child? Why then do I see every man with his hands on his stomach like a woman in labor? Why has every face turned pale?","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":6},{"ref":"Jeremiah 30:7","short":"Jer 30:7","text":"Alas! That day is so great there is none like it; it is a time of distress for Jacob; yet he shall be saved out of it.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":7},{"ref":"Jeremiah 30:8","short":"Jer 30:8","text":"“And it shall come to pass in that day, declares the LORD of hosts, that I will break his yoke from off your neck, and I will burst your bonds, and foreigners shall no more make a servant of him.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":8},{"ref":"Jeremiah 30:9","short":"Jer 30:9","text":"But they shall serve the LORD their God and David their king, whom I will raise up for them.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":9},{"ref":"Jeremiah 30:10","short":"Jer 30:10","text":"“Then fear not, O Jacob my servant, declares the LORD, nor be dismayed, O Israel; for behold, I will save you from far away, and your offspring from the land of their captivity. Jacob shall return and have quiet and ease, and none shall make him afraid.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":10},{"ref":"Jeremiah 30:11","short":"Jer 30:11","text":"For I am with you to save you, declares the LORD; I will make a full end of all the nations among whom I scattered you, but of you I will not make a full end. I will discipline you in just measure, and I will by no means leave you unpunished.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":11},{"ref":"Jeremiah 30:12","short":"Jer 30:12","text":"“For thus says the LORD: Your hurt is incurable, and your wound is grievous.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":12},{"ref":"Jeremiah 30:13","short":"Jer 30:13","text":"There is none to uphold your cause, no medicine for your wound, no healing for you.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":13},{"ref":"Jeremiah 30:14","short":"Jer 30:14","text":"All your lovers have forgotten you; they care nothing for you; for I have dealt you the blow of an enemy, the punishment of a merciless foe, because your guilt is great, because your sins are flagrant.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":14},{"ref":"Jeremiah 30:15","short":"Jer 30:15","text":"Why do you cry out over your hurt? Your pain is incurable. Because your guilt is great, because your sins are flagrant, I have done these things to you.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":15},{"ref":"Jeremiah 30:16","short":"Jer 30:16","text":"Therefore all who devour you shall be devoured, and all your foes, every one of them, shall go into captivity; those who plunder you shall be plundered, and all who prey on you I will make a prey.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":16},{"ref":"Jeremiah 30:17","short":"Jer 30:17","text":"For I will restore health to you, and your wounds I will heal, declares the LORD, because they have called you an outcast: ‘It is Zion, for whom no one cares!’","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":17},{"ref":"Jeremiah 30:18","short":"Jer 30:18","text":"“Thus says the LORD: Behold, I will restore the fortunes of the tents of Jacob and have compassion on his dwellings; the city shall be rebuilt on its mound, and the palace shall stand where it used to be.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":18},{"ref":"Jeremiah 30:19","short":"Jer 30:19","text":"Out of them shall come songs of thanksgiving, and the voices of those who celebrate. I will multiply them, and they shall not be few; I will make them honored, and they shall not be small.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":19},{"ref":"Jeremiah 30:20","short":"Jer 30:20","text":"Their children shall be as they were of old, and their congregation shall be established before me, and I will punish all who oppress them.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":20},{"ref":"Jeremiah 30:21","short":"Jer 30:21","text":"Their prince shall be one of themselves; their ruler shall come out from their midst; I will make him draw near, and he shall approach me, for who would dare of himself to approach me? declares the LORD.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":21},{"ref":"Jeremiah 30:22","short":"Jer 30:22","text":"And you shall be my people, and I will be your God.”","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":22},{"ref":"Jeremiah 30:23","short":"Jer 30:23","text":"Behold the storm of the LORD! Wrath has gone forth, a whirling tempest; it will burst upon the head of the wicked.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":23},{"ref":"Jeremiah 30:24","short":"Jer 30:24","text":"The fierce anger of the LORD will not turn back until he has executed and accomplished the intentions of his mind. In the latter days you will understand this.","url":"ot/jeremiah/Jeremiah_30.html","book":"Jeremiah","ch":30,"v":24},{"ref":"Jeremiah 31:1","short":"Jer 31:1","text":"“At that time, declares the LORD, I will be the God of all the clans of Israel, and they shall be my people.”","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":1},{"ref":"Jeremiah 31:2","short":"Jer 31:2","text":"Thus says the LORD: “The people who survived the sword found grace in the wilderness; when Israel sought for rest,","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":2},{"ref":"Jeremiah 31:3","short":"Jer 31:3","text":"the LORD appeared to him from far away. I have loved you with an everlasting love; therefore I have continued my faithfulness to you.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":3},{"ref":"Jeremiah 31:4","short":"Jer 31:4","text":"Again I will build you, and you shall be built, O virgin Israel! Again you shall adorn yourself with tambourines and shall go forth in the dance of the merrymakers.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":4},{"ref":"Jeremiah 31:5","short":"Jer 31:5","text":"Again you shall plant vineyards on the mountains of Samaria; the planters shall plant and shall enjoy the fruit.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":5},{"ref":"Jeremiah 31:6","short":"Jer 31:6","text":"For there shall be a day when watchmen will call in the hill country of Ephraim: ‘Arise, and let us go up to Zion, to the LORD our God.’”","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":6},{"ref":"Jeremiah 31:7","short":"Jer 31:7","text":"For thus says the LORD: “Sing aloud with gladness for Jacob, and raise shouts for the chief of the nations; proclaim, give praise, and say, ‘O LORD, save your people, the remnant of Israel.’","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":7},{"ref":"Jeremiah 31:8","short":"Jer 31:8","text":"Behold, I will bring them from the north country and gather them from the farthest parts of the earth, among them the blind and the lame, the pregnant woman and she who is in labor, together; a great company, they shall return here.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":8},{"ref":"Jeremiah 31:9","short":"Jer 31:9","text":"With weeping they shall come, and with pleas for mercy I will lead them back, I will make them walk by brooks of water, in a straight path in which they shall not stumble, for I am a father to Israel, and Ephraim is my firstborn.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":9},{"ref":"Jeremiah 31:10","short":"Jer 31:10","text":"“Hear the word of the LORD, O nations, and declare it in the coastlands far away; say, ‘He who scattered Israel will gather him, and will keep him as a shepherd keeps his flock.’","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":10},{"ref":"Jeremiah 31:11","short":"Jer 31:11","text":"For the LORD has ransomed Jacob and has redeemed him from hands too strong for him.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":11},{"ref":"Jeremiah 31:12","short":"Jer 31:12","text":"They shall come and sing aloud on the height of Zion, and they shall be radiant over the goodness of the LORD, over the grain, the wine, and the oil, and over the young of the flock and the herd; their life shall be like a watered garden, and they shall languish no more.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":12},{"ref":"Jeremiah 31:13","short":"Jer 31:13","text":"Then shall the young women rejoice in the dance, and the young men and the old shall be merry. I will turn their mourning into joy; I will comfort them, and give them gladness for sorrow.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":13},{"ref":"Jeremiah 31:14","short":"Jer 31:14","text":"I will feast the soul of the priests with abundance, and my people shall be satisfied with my goodness, declares the LORD.”","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":14},{"ref":"Jeremiah 31:15","short":"Jer 31:15","text":"Thus says the LORD: “A voice is heard in Ramah, lamentation and bitter weeping. Rachel is weeping for her children; she refuses to be comforted for her children, because they are no more.”","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":15},{"ref":"Jeremiah 31:16","short":"Jer 31:16","text":"Thus says the LORD: “Keep your voice from weeping, and your eyes from tears, for there is a reward for your work, declares the LORD, and they shall come back from the land of the enemy.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":16},{"ref":"Jeremiah 31:17","short":"Jer 31:17","text":"There is hope for your future, declares the LORD, and your children shall come back to their own country.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":17},{"ref":"Jeremiah 31:18","short":"Jer 31:18","text":"I have heard Ephraim grieving, ‘You have disciplined me, and I was disciplined, like an untrained calf; bring me back that I may be restored, for you are the LORD my God.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":18},{"ref":"Jeremiah 31:19","short":"Jer 31:19","text":"For after I had turned away, I relented, and after I was instructed, I struck my thigh; I was ashamed, and I was confounded, because I bore the disgrace of my youth.’","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":19},{"ref":"Jeremiah 31:20","short":"Jer 31:20","text":"Is Ephraim my dear son? Is he my darling child? For as often as I speak against him, I do remember him still. Therefore my heart yearns for him; I will surely have mercy on him, declares the LORD.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":20},{"ref":"Jeremiah 31:21","short":"Jer 31:21","text":"“Set up road markers for yourself; make yourself guideposts; consider well the highway, the road by which you went. Return, O virgin Israel, return to these your cities.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":21},{"ref":"Jeremiah 31:22","short":"Jer 31:22","text":"How long will you waver, O faithless daughter? For the LORD has created a new thing on the earth: a woman encircles a man.”","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":22},{"ref":"Jeremiah 31:23","short":"Jer 31:23","text":"Thus says the LORD of hosts, the God of Israel: “Once more they shall use these words in the land of Judah and in its cities, when I restore their fortunes: “‘The LORD bless you, O habitation of righteousness, O holy hill!’","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":23},{"ref":"Jeremiah 31:24","short":"Jer 31:24","text":"And Judah and all its cities shall dwell there together, and the farmers and those who wander with their flocks.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":24},{"ref":"Jeremiah 31:25","short":"Jer 31:25","text":"For I will satisfy the weary soul, and every languishing soul I will replenish.”","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":25},{"ref":"Jeremiah 31:26","short":"Jer 31:26","text":"At this I awoke and looked, and my sleep was pleasant to me.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":26},{"ref":"Jeremiah 31:27","short":"Jer 31:27","text":"“Behold, the days are coming, declares the LORD, when I will sow the house of Israel and the house of Judah with the seed of man and the seed of beast.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":27},{"ref":"Jeremiah 31:28","short":"Jer 31:28","text":"And it shall come to pass that as I have watched over them to pluck up and break down, to overthrow, destroy, and bring harm, so I will watch over them to build and to plant, declares the LORD.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":28},{"ref":"Jeremiah 31:29","short":"Jer 31:29","text":"In those days they shall no longer say: “‘The fathers have eaten sour grapes, and the children’s teeth are set on edge.’","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":29},{"ref":"Jeremiah 31:30","short":"Jer 31:30","text":"But everyone shall die for his own iniquity. Each man who eats sour grapes, his teeth shall be set on edge.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":30},{"ref":"Jeremiah 31:31","short":"Jer 31:31","text":"“Behold, the days are coming, declares the LORD, when I will make a new covenant with the house of Israel and the house of Judah,","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":31},{"ref":"Jeremiah 31:32","short":"Jer 31:32","text":"not like the covenant that I made with their fathers on the day when I took them by the hand to bring them out of the land of Egypt, my covenant that they broke, though I was their husband, declares the LORD.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":32},{"ref":"Jeremiah 31:33","short":"Jer 31:33","text":"For this is the covenant that I will make with the house of Israel after those days, declares the LORD: I will put my law within them, and I will write it on their hearts. And I will be their God, and they shall be my people.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":33},{"ref":"Jeremiah 31:34","short":"Jer 31:34","text":"And no longer shall each one teach his neighbor and each his brother, saying, ‘Know the LORD,’ for they shall all know me, from the least of them to the greatest, declares the LORD. For I will forgive their iniquity, and I will remember their sin no more.”","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":34},{"ref":"Jeremiah 31:35","short":"Jer 31:35","text":"Thus says the LORD, who gives the sun for light by day and the fixed order of the moon and the stars for light by night, who stirs up the sea so that its waves roar— the LORD of hosts is his name:","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":35},{"ref":"Jeremiah 31:36","short":"Jer 31:36","text":"“If this fixed order departs from before me, declares the LORD, then shall the offspring of Israel cease from being a nation before me forever.”","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":36},{"ref":"Jeremiah 31:37","short":"Jer 31:37","text":"Thus says the LORD: “If the heavens above can be measured, and the foundations of the earth below can be explored, then I will cast off all the offspring of Israel for all that they have done, declares the LORD.”","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":37},{"ref":"Jeremiah 31:38","short":"Jer 31:38","text":"“Behold, the days are coming, declares the LORD, when the city shall be rebuilt for the LORD from the Tower of Hananel to the Corner Gate.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":38},{"ref":"Jeremiah 31:39","short":"Jer 31:39","text":"And the measuring line shall go out farther, straight to the hill Gareb, and shall then turn to Goah.","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":39},{"ref":"Jeremiah 31:40","short":"Jer 31:40","text":"The whole valley of the dead bodies and the ashes, and all the fields as far as the brook Kidron, to the corner of the Horse Gate toward the east, shall be sacred to the LORD. It shall not be plucked up or overthrown anymore forever.”","url":"ot/jeremiah/Jeremiah_31.html","book":"Jeremiah","ch":31,"v":40},{"ref":"Jeremiah 32:1","short":"Jer 32:1","text":"The word that came to Jeremiah from the LORD in the tenth year of Zedekiah king of Judah, which was the eighteenth year of Nebuchadnezzar.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":1},{"ref":"Jeremiah 32:2","short":"Jer 32:2","text":"At that time the army of the king of Babylon was besieging Jerusalem, and Jeremiah the prophet was shut up in the court of the guard that was in the palace of the king of Judah.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":2},{"ref":"Jeremiah 32:3","short":"Jer 32:3","text":"For Zedekiah king of Judah had imprisoned him, saying, “Why do you prophesy and say, ‘Thus says the LORD: Behold, I am giving this city into the hand of the king of Babylon, and he shall capture it;","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":3},{"ref":"Jeremiah 32:4","short":"Jer 32:4","text":"Zedekiah king of Judah shall not escape out of the hand of the Chaldeans, but shall surely be given into the hand of the king of Babylon, and shall speak with him face to face and see him eye to eye.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":4},{"ref":"Jeremiah 32:5","short":"Jer 32:5","text":"And he shall take Zedekiah to Babylon, and there he shall remain until I visit him, declares the LORD. Though you fight against the Chaldeans, you shall not succeed’?”","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":5},{"ref":"Jeremiah 32:6","short":"Jer 32:6","text":"Jeremiah said, “The word of the LORD came to me:","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":6},{"ref":"Jeremiah 32:7","short":"Jer 32:7","text":"Behold, Hanamel the son of Shallum your uncle will come to you and say, ‘Buy my field that is at Anathoth, for the right of redemption by purchase is yours.’","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":7},{"ref":"Jeremiah 32:8","short":"Jer 32:8","text":"Then Hanamel my cousin came to me in the court of the guard, in accordance with the word of the LORD, and said to me, ‘Buy my field that is at Anathoth in the land of Benjamin, for the right of possession and redemption is yours; buy it for yourself.’ Then I knew that this was the word of the LORD.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":8},{"ref":"Jeremiah 32:9","short":"Jer 32:9","text":"“And I bought the field at Anathoth from Hanamel my cousin, and weighed out the money to him, seventeen shekels of silver.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":9},{"ref":"Jeremiah 32:10","short":"Jer 32:10","text":"I signed the deed, sealed it, got witnesses, and weighed the money on scales.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":10},{"ref":"Jeremiah 32:11","short":"Jer 32:11","text":"Then I took the sealed deed of purchase, containing the terms and conditions and the open copy.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":11},{"ref":"Jeremiah 32:12","short":"Jer 32:12","text":"And I gave the deed of purchase to Baruch the son of Neriah son of Mahseiah, in the presence of Hanamel my cousin, in the presence of the witnesses who signed the deed of purchase, and in the presence of all the Judeans who were sitting in the court of the guard.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":12},{"ref":"Jeremiah 32:13","short":"Jer 32:13","text":"I charged Baruch in their presence, saying,","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":13},{"ref":"Jeremiah 32:14","short":"Jer 32:14","text":"‘Thus says the LORD of hosts, the God of Israel: Take these deeds, both this sealed deed of purchase and this open deed, and put them in an earthenware vessel, that they may last for a long time.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":14},{"ref":"Jeremiah 32:15","short":"Jer 32:15","text":"For thus says the LORD of hosts, the God of Israel: Houses and fields and vineyards shall again be bought in this land.’","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":15},{"ref":"Jeremiah 32:16","short":"Jer 32:16","text":"“After I had given the deed of purchase to Baruch the son of Neriah, I prayed to the LORD, saying:","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":16},{"ref":"Jeremiah 32:17","short":"Jer 32:17","text":"‘Ah, Lord GOD! It is you who have made the heavens and the earth by your great power and by your outstretched arm! Nothing is too hard for you.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":17},{"ref":"Jeremiah 32:18","short":"Jer 32:18","text":"You show steadfast love to thousands, but you repay the guilt of fathers to their children after them, O great and mighty God, whose name is the LORD of hosts,","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":18},{"ref":"Jeremiah 32:19","short":"Jer 32:19","text":"great in counsel and mighty in deed, whose eyes are open to all the ways of the children of man, rewarding each one according to his ways and according to the fruit of his deeds.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":19},{"ref":"Jeremiah 32:20","short":"Jer 32:20","text":"You have shown signs and wonders in the land of Egypt, and to this day in Israel and among all mankind, and have made a name for yourself, as at this day.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":20},{"ref":"Jeremiah 32:21","short":"Jer 32:21","text":"You brought your people Israel out of the land of Egypt with signs and wonders, with a strong hand and outstretched arm, and with great terror.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":21},{"ref":"Jeremiah 32:22","short":"Jer 32:22","text":"And you gave them this land, which you swore to their fathers to give them, a land flowing with milk and honey.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":22},{"ref":"Jeremiah 32:23","short":"Jer 32:23","text":"And they entered and took possession of it. But they did not obey your voice or walk in your law. They did nothing of all you commanded them to do. Therefore you have made all this disaster come upon them.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":23},{"ref":"Jeremiah 32:24","short":"Jer 32:24","text":"Behold, the siege mounds have come up to the city to take it, and because of sword and famine and pestilence the city is given into the hands of the Chaldeans who are fighting against it. What you spoke has come to pass, and behold, you see it.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":24},{"ref":"Jeremiah 32:25","short":"Jer 32:25","text":"Yet you, O Lord GOD, have said to me, “Buy the field for money and get witnesses”—though the city is given into the hands of the Chaldeans.’”","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":25},{"ref":"Jeremiah 32:26","short":"Jer 32:26","text":"The word of the LORD came to Jeremiah:","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":26},{"ref":"Jeremiah 32:27","short":"Jer 32:27","text":"“Behold, I am the LORD, the God of all flesh. Is anything too hard for me?","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":27},{"ref":"Jeremiah 32:28","short":"Jer 32:28","text":"Therefore, thus says the LORD: Behold, I am giving this city into the hands of the Chaldeans and into the hand of Nebuchadnezzar king of Babylon, and he shall capture it.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":28},{"ref":"Jeremiah 32:29","short":"Jer 32:29","text":"The Chaldeans who are fighting against this city shall come and set this city on fire and burn it, with the houses on whose roofs offerings have been made to Baal and drink offerings have been poured out to other gods, to provoke me to anger.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":29},{"ref":"Jeremiah 32:30","short":"Jer 32:30","text":"For the children of Israel and the children of Judah have done nothing but evil in my sight from their youth. The children of Israel have done nothing but provoke me to anger by the work of their hands, declares the LORD.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":30},{"ref":"Jeremiah 32:31","short":"Jer 32:31","text":"This city has aroused my anger and wrath, from the day it was built to this day, so that I will remove it from my sight","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":31},{"ref":"Jeremiah 32:32","short":"Jer 32:32","text":"because of all the evil of the children of Israel and the children of Judah that they did to provoke me to anger—their kings and their officials, their priests and their prophets, the men of Judah and the inhabitants of Jerusalem.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":32},{"ref":"Jeremiah 32:33","short":"Jer 32:33","text":"They have turned to me their back and not their face. And though I have taught them persistently, they have not listened to receive instruction.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":33},{"ref":"Jeremiah 32:34","short":"Jer 32:34","text":"They set up their abominations in the house that is called by my name, to defile it.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":34},{"ref":"Jeremiah 32:35","short":"Jer 32:35","text":"They built the high places of Baal in the Valley of the Son of Hinnom, to offer up their sons and daughters to Molech, though I did not command them, nor did it enter into my mind, that they should do this abomination, to cause Judah to sin.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":35},{"ref":"Jeremiah 32:36","short":"Jer 32:36","text":"“Now therefore thus says the LORD, the God of Israel, concerning this city of which you say, ‘It is given into the hand of the king of Babylon by sword, by famine, and by pestilence’:","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":36},{"ref":"Jeremiah 32:37","short":"Jer 32:37","text":"Behold, I will gather them from all the countries to which I drove them in my anger and my wrath and in great indignation. I will bring them back to this place, and I will make them dwell in safety.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":37},{"ref":"Jeremiah 32:38","short":"Jer 32:38","text":"And they shall be my people, and I will be their God.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":38},{"ref":"Jeremiah 32:39","short":"Jer 32:39","text":"I will give them one heart and one way, that they may fear me forever, for their own good and the good of their children after them.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":39},{"ref":"Jeremiah 32:40","short":"Jer 32:40","text":"I will make with them an everlasting covenant, that I will not turn away from doing good to them. And I will put the fear of me in their hearts, that they may not turn from me.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":40},{"ref":"Jeremiah 32:41","short":"Jer 32:41","text":"I will rejoice in doing them good, and I will plant them in this land in faithfulness, with all my heart and all my soul.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":41},{"ref":"Jeremiah 32:42","short":"Jer 32:42","text":"“For thus says the LORD: Just as I have brought all this great disaster upon this people, so I will bring upon them all the good that I promise them.","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":42},{"ref":"Jeremiah 32:43","short":"Jer 32:43","text":"Fields shall be bought in this land of which you are saying, ‘It is a desolation, without man or beast; it is given into the hand of the Chaldeans.’","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":43},{"ref":"Jeremiah 32:44","short":"Jer 32:44","text":"Fields shall be bought for money, and deeds shall be signed and sealed and witnessed, in the land of Benjamin, in the places about Jerusalem, and in the cities of Judah, in the cities of the hill country, in the cities of the Shephelah, and in the cities of the Negeb; for I will restore their fortunes, declares the LORD.”","url":"ot/jeremiah/Jeremiah_32.html","book":"Jeremiah","ch":32,"v":44},{"ref":"Jeremiah 33:1","short":"Jer 33:1","text":"The word of the LORD came to Jeremiah a second time, while he was still shut up in the court of the guard:","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":1},{"ref":"Jeremiah 33:2","short":"Jer 33:2","text":"“Thus says the LORD who made the earth, the LORD who formed it to establish it—the LORD is his name:","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":2},{"ref":"Jeremiah 33:3","short":"Jer 33:3","text":"Call to me and I will answer you, and will tell you great and hidden things that you have not known.","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":3},{"ref":"Jeremiah 33:4","short":"Jer 33:4","text":"For thus says the LORD, the God of Israel, concerning the houses of this city and the houses of the kings of Judah that were torn down to make a defense against the siege mounds and against the sword:","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":4},{"ref":"Jeremiah 33:5","short":"Jer 33:5","text":"They are coming in to fight against the Chaldeans and to fill them with the dead bodies of men whom I shall strike down in my anger and my wrath, for I have hidden my face from this city because of all their evil.","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":5},{"ref":"Jeremiah 33:6","short":"Jer 33:6","text":"Behold, I will bring to it health and healing, and I will heal them and reveal to them abundance of prosperity and security.","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":6},{"ref":"Jeremiah 33:7","short":"Jer 33:7","text":"I will restore the fortunes of Judah and the fortunes of Israel, and rebuild them as they were at first.","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":7},{"ref":"Jeremiah 33:8","short":"Jer 33:8","text":"I will cleanse them from all the guilt of their sin against me, and I will forgive all the guilt of their sin and rebellion against me.","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":8},{"ref":"Jeremiah 33:9","short":"Jer 33:9","text":"And this city shall be to me a name of joy, a praise and a glory before all the nations of the earth who shall hear of all the good that I do for them. They shall fear and tremble because of all the good and all the prosperity I provide for it.","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":9},{"ref":"Jeremiah 33:10","short":"Jer 33:10","text":"“Thus says the LORD: In this place of which you say, ‘It is a waste without man or beast,’ in the cities of Judah and the streets of Jerusalem that are desolate, without man or inhabitant or beast, there shall be heard again","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":10},{"ref":"Jeremiah 33:11","short":"Jer 33:11","text":"the voice of mirth and the voice of gladness, the voice of the bridegroom and the voice of the bride, the voices of those who sing, as they bring thank offerings to the house of the LORD: “‘Give thanks to the LORD of hosts, for the LORD is good, for his steadfast love endures forever!’ For I will restore the fortunes of the land as at first, says the LORD.","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":11},{"ref":"Jeremiah 33:12","short":"Jer 33:12","text":"“Thus says the LORD of hosts: In this place that is waste, without man or beast, and in all of its cities, there shall again be habitations of shepherds resting their flocks.","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":12},{"ref":"Jeremiah 33:13","short":"Jer 33:13","text":"In the cities of the hill country, in the cities of the Shephelah, and in the cities of the Negeb, in the land of Benjamin, the places about Jerusalem, and in the cities of Judah, flocks shall again pass under the hands of the one who counts them, says the LORD.","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":13},{"ref":"Jeremiah 33:14","short":"Jer 33:14","text":"“Behold, the days are coming, declares the LORD, when I will fulfill the promise I made to the house of Israel and the house of Judah.","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":14},{"ref":"Jeremiah 33:15","short":"Jer 33:15","text":"In those days and at that time I will cause a righteous Branch to spring up for David, and he shall execute justice and righteousness in the land.","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":15},{"ref":"Jeremiah 33:16","short":"Jer 33:16","text":"In those days Judah will be saved, and Jerusalem will dwell securely. And this is the name by which it will be called: ‘The LORD is our righteousness.’","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":16},{"ref":"Jeremiah 33:17","short":"Jer 33:17","text":"“For thus says the LORD: David shall never lack a man to sit on the throne of the house of Israel,","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":17},{"ref":"Jeremiah 33:18","short":"Jer 33:18","text":"and the Levitical priests shall never lack a man in my presence to offer burnt offerings, to burn grain offerings, and to make sacrifices forever.”","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":18},{"ref":"Jeremiah 33:19","short":"Jer 33:19","text":"The word of the LORD came to Jeremiah:","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":19},{"ref":"Jeremiah 33:20","short":"Jer 33:20","text":"“Thus says the LORD: If you can break my covenant with the day and my covenant with the night, so that day and night will not come at their appointed time,","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":20},{"ref":"Jeremiah 33:21","short":"Jer 33:21","text":"then also my covenant with David my servant may be broken, so that he shall not have a son to reign on his throne, and my covenant with the Levitical priests my ministers.","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":21},{"ref":"Jeremiah 33:22","short":"Jer 33:22","text":"As the host of heaven cannot be numbered and the sands of the sea cannot be measured, so I will multiply the offspring of David my servant, and the Levitical priests who minister to me.”","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":22},{"ref":"Jeremiah 33:23","short":"Jer 33:23","text":"The word of the LORD came to Jeremiah:","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":23},{"ref":"Jeremiah 33:24","short":"Jer 33:24","text":"“Have you not observed that these people are saying, ‘The LORD has rejected the two clans that he chose’? Thus they have despised my people so that they are no longer a nation in their sight.","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":24},{"ref":"Jeremiah 33:25","short":"Jer 33:25","text":"Thus says the LORD: If I have not established my covenant with day and night and the fixed order of heaven and earth,","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":25},{"ref":"Jeremiah 33:26","short":"Jer 33:26","text":"then I will reject the offspring of Jacob and David my servant and will not choose one of his offspring to rule over the offspring of Abraham, Isaac, and Jacob. For I will restore their fortunes and will have mercy on them.”","url":"ot/jeremiah/Jeremiah_33.html","book":"Jeremiah","ch":33,"v":26},{"ref":"Jeremiah 34:1","short":"Jer 34:1","text":"The word that came to Jeremiah from the LORD, when Nebuchadnezzar king of Babylon and all his army and all the kingdoms of the earth under his dominion and all the peoples were fighting against Jerusalem and all of its cities:","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":1},{"ref":"Jeremiah 34:2","short":"Jer 34:2","text":"“Thus says the LORD, the God of Israel: Go and speak to Zedekiah king of Judah and say to him, ‘Thus says the LORD: Behold, I am giving this city into the hand of the king of Babylon, and he shall burn it with fire.","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":2},{"ref":"Jeremiah 34:3","short":"Jer 34:3","text":"You shall not escape from his hand but shall surely be captured and delivered into his hand. You shall see the king of Babylon eye to eye and speak with him face to face. And you shall go to Babylon.’","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":3},{"ref":"Jeremiah 34:4","short":"Jer 34:4","text":"Yet hear the word of the LORD, O Zedekiah king of Judah! Thus says the LORD concerning you: ‘You shall not die by the sword.","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":4},{"ref":"Jeremiah 34:5","short":"Jer 34:5","text":"You shall die in peace. And as spices were burned for your fathers, the former kings who were before you, so people shall burn spices for you and lament for you, saying, “Alas, lord!”’ For I have spoken the word, declares the LORD.”","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":5},{"ref":"Jeremiah 34:6","short":"Jer 34:6","text":"Then Jeremiah the prophet spoke all these words to Zedekiah king of Judah, in Jerusalem,","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":6},{"ref":"Jeremiah 34:7","short":"Jer 34:7","text":"when the army of the king of Babylon was fighting against Jerusalem and against all the cities of Judah that were left, Lachish and Azekah, for these were the only fortified cities of Judah that remained.","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":7},{"ref":"Jeremiah 34:8","short":"Jer 34:8","text":"The word that came to Jeremiah from the LORD, after King Zedekiah had made a covenant with all the people in Jerusalem to make a proclamation of liberty to them,","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":8},{"ref":"Jeremiah 34:9","short":"Jer 34:9","text":"that everyone should set free his Hebrew slaves, male and female, so that no one should enslave a Jew, his brother.","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":9},{"ref":"Jeremiah 34:10","short":"Jer 34:10","text":"And they obeyed, all the officials and all the people who had entered into the covenant that everyone would set free his slave, male or female, so that they would not be enslaved again. They obeyed and set them free.","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":10},{"ref":"Jeremiah 34:11","short":"Jer 34:11","text":"But afterward they turned around and took back the male and female slaves they had set free, and brought them into subjection as slaves.","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":11},{"ref":"Jeremiah 34:12","short":"Jer 34:12","text":"The word of the LORD came to Jeremiah from the LORD:","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":12},{"ref":"Jeremiah 34:13","short":"Jer 34:13","text":"“Thus says the LORD, the God of Israel: I myself made a covenant with your fathers when I brought them out of the land of Egypt, out of the house of slavery, saying,","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":13},{"ref":"Jeremiah 34:14","short":"Jer 34:14","text":"‘At the end of seven years each of you must set free the fellow Hebrew who has been sold to you and has served you six years; you must set him free from your service.’ But your fathers did not listen to me or incline their ears to me.","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":14},{"ref":"Jeremiah 34:15","short":"Jer 34:15","text":"You recently repented and did what was right in my eyes by proclaiming liberty, each to his neighbor, and you made a covenant before me in the house that is called by my name,","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":15},{"ref":"Jeremiah 34:16","short":"Jer 34:16","text":"but then you turned around and profaned my name when each of you took back his male and female slaves, whom you had set free according to their desire, and you brought them into subjection to be your slaves.","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":16},{"ref":"Jeremiah 34:17","short":"Jer 34:17","text":"“Therefore, thus says the LORD: You have not obeyed me by proclaiming liberty, every one to his brother and to his neighbor; behold, I proclaim to you liberty to the sword, to pestilence, and to famine, declares the LORD. I will make you a horror to all the kingdoms of the earth.","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":17},{"ref":"Jeremiah 34:18","short":"Jer 34:18","text":"And the men who transgressed my covenant and did not keep the terms of the covenant that they made before me, I will make them like the calf that they cut in two and passed between its parts—","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":18},{"ref":"Jeremiah 34:19","short":"Jer 34:19","text":"the officials of Judah, the officials of Jerusalem, the eunuchs, the priests, and all the people of the land who passed between the parts of the calf.","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":19},{"ref":"Jeremiah 34:20","short":"Jer 34:20","text":"And I will give them into the hand of their enemies and into the hand of those who seek their lives. Their dead bodies shall be food for the birds of the air and the beasts of the earth.","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":20},{"ref":"Jeremiah 34:21","short":"Jer 34:21","text":"And Zedekiah king of Judah and his officials I will give into the hand of their enemies and into the hand of those who seek their lives, into the hand of the army of the king of Babylon which has withdrawn from you.","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":21},{"ref":"Jeremiah 34:22","short":"Jer 34:22","text":"Behold, I will command, declares the LORD, and will bring them back to this city. And they will fight against it and take it and burn it with fire. I will make the cities of Judah a desolation without inhabitant.”","url":"ot/jeremiah/Jeremiah_34.html","book":"Jeremiah","ch":34,"v":22},{"ref":"Jeremiah 35:1","short":"Jer 35:1","text":"The word that came to Jeremiah from the LORD in the days of Jehoiakim the son of Josiah, king of Judah:","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":1},{"ref":"Jeremiah 35:2","short":"Jer 35:2","text":"“Go to the house of the Rechabites and speak with them and bring them to the house of the LORD, into one of the chambers; then offer them wine to drink.”","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":2},{"ref":"Jeremiah 35:3","short":"Jer 35:3","text":"So I took Jaazaniah the son of Jeremiah, son of Habazziniah and his brothers and all his sons and the whole house of the Rechabites.","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":3},{"ref":"Jeremiah 35:4","short":"Jer 35:4","text":"I brought them to the house of the LORD into the chamber of the sons of Hanan the son of Igdaliah, the man of God, which was near the chamber of the officials, above the chamber of Maaseiah the son of Shallum, keeper of the threshold.","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":4},{"ref":"Jeremiah 35:5","short":"Jer 35:5","text":"Then I set before the Rechabites pitchers full of wine, and cups, and I said to them, “Drink wine.”","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":5},{"ref":"Jeremiah 35:6","short":"Jer 35:6","text":"But they answered, “We will drink no wine, for Jonadab the son of Rechab, our father, commanded us, ‘You shall not drink wine, neither you nor your sons forever.","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":6},{"ref":"Jeremiah 35:7","short":"Jer 35:7","text":"You shall not build a house; you shall not sow seed; you shall not plant or have a vineyard; but you shall live in tents all your days, that you may live many days in the land where you sojourn.’","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":7},{"ref":"Jeremiah 35:8","short":"Jer 35:8","text":"We have obeyed the voice of Jonadab the son of Rechab, our father, in all that he commanded us, to drink no wine all our days, ourselves, our wives, our sons, or our daughters,","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":8},{"ref":"Jeremiah 35:9","short":"Jer 35:9","text":"and not to build houses to dwell in. We have no vineyard or field or seed,","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":9},{"ref":"Jeremiah 35:10","short":"Jer 35:10","text":"but we have lived in tents and have obeyed and done all that Jonadab our father commanded us.","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":10},{"ref":"Jeremiah 35:11","short":"Jer 35:11","text":"But when Nebuchadnezzar king of Babylon came up against the land, we said, ‘Come, and let us go to Jerusalem for fear of the army of the Chaldeans and the army of the Syrians.’ So we are living in Jerusalem.”","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":11},{"ref":"Jeremiah 35:12","short":"Jer 35:12","text":"Then the word of the LORD came to Jeremiah:","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":12},{"ref":"Jeremiah 35:13","short":"Jer 35:13","text":"“Thus says the LORD of hosts, the God of Israel: Go and say to the people of Judah and the inhabitants of Jerusalem, Will you not receive instruction and listen to my words? declares the LORD.","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":13},{"ref":"Jeremiah 35:14","short":"Jer 35:14","text":"The command that Jonadab the son of Rechab gave to his sons, to drink no wine, has been kept, and they drink none to this day, for they have obeyed their father’s command. I have spoken to you persistently, but you have not listened to me.","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":14},{"ref":"Jeremiah 35:15","short":"Jer 35:15","text":"I have sent to you all my servants the prophets, sending them persistently, saying, ‘Turn now every one of you from his evil way, and amend your deeds, and do not go after other gods to serve them, and then you shall dwell in the land that I gave to you and your fathers.’ But you did not incline your ear or listen to me.","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":15},{"ref":"Jeremiah 35:16","short":"Jer 35:16","text":"The sons of Jonadab the son of Rechab have kept the command that their father gave them, but this people has not obeyed me.","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":16},{"ref":"Jeremiah 35:17","short":"Jer 35:17","text":"Therefore, thus says the LORD, the God of hosts, the God of Israel: Behold, I am bringing upon Judah and all the inhabitants of Jerusalem all the disaster that I have pronounced against them, because I have spoken to them and they have not listened, I have called to them and they have not answered.”","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":17},{"ref":"Jeremiah 35:18","short":"Jer 35:18","text":"But to the house of the Rechabites Jeremiah said, “Thus says the LORD of hosts, the God of Israel: Because you have obeyed the command of Jonadab your father and kept all his precepts and done all that he commanded you,","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":18},{"ref":"Jeremiah 35:19","short":"Jer 35:19","text":"therefore thus says the LORD of hosts, the God of Israel: Jonadab the son of Rechab shall never lack a man to stand before me.”","url":"ot/jeremiah/Jeremiah_35.html","book":"Jeremiah","ch":35,"v":19},{"ref":"Jeremiah 36:1","short":"Jer 36:1","text":"In the fourth year of Jehoiakim the son of Josiah, king of Judah, this word came to Jeremiah from the LORD:","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":1},{"ref":"Jeremiah 36:2","short":"Jer 36:2","text":"“Take a scroll and write on it all the words that I have spoken to you against Israel and Judah and all the nations, from the day I spoke to you, from the days of Josiah until today.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":2},{"ref":"Jeremiah 36:3","short":"Jer 36:3","text":"It may be that the house of Judah will hear all the disaster that I intend to do to them, so that every one may turn from his evil way, and that I may forgive their iniquity and their sin.”","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":3},{"ref":"Jeremiah 36:4","short":"Jer 36:4","text":"Then Jeremiah called Baruch the son of Neriah, and Baruch wrote on a scroll at the dictation of Jeremiah all the words of the LORD that he had spoken to him.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":4},{"ref":"Jeremiah 36:5","short":"Jer 36:5","text":"And Jeremiah ordered Baruch, saying, “I am banned from going to the house of the LORD,","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":5},{"ref":"Jeremiah 36:6","short":"Jer 36:6","text":"so you are to go, and on a day of fasting in the hearing of all the people in the LORD’s house you shall read the words of the LORD from the scroll that you have written at my dictation. You shall read them also in the hearing of all the men of Judah who come out of their cities.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":6},{"ref":"Jeremiah 36:7","short":"Jer 36:7","text":"It may be that their plea for mercy will come before the LORD, and that every one will turn from his evil way, for great is the anger and wrath that the LORD has pronounced against this people.”","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":7},{"ref":"Jeremiah 36:8","short":"Jer 36:8","text":"And Baruch the son of Neriah did all that Jeremiah the prophet ordered him about reading from the scroll the words of the LORD in the LORD’s house.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":8},{"ref":"Jeremiah 36:9","short":"Jer 36:9","text":"In the fifth year of Jehoiakim the son of Josiah, king of Judah, in the ninth month, all the people in Jerusalem and all the people who came from the cities of Judah to Jerusalem proclaimed a fast before the LORD.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":9},{"ref":"Jeremiah 36:10","short":"Jer 36:10","text":"Then, in the hearing of all the people, Baruch read the words of Jeremiah from the scroll, in the house of the LORD, in the chamber of Gemariah the son of Shaphan the secretary, which was in the upper court, at the entry of the New Gate of the LORD’s house.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":10},{"ref":"Jeremiah 36:11","short":"Jer 36:11","text":"When Micaiah the son of Gemariah, son of Shaphan, heard all the words of the LORD from the scroll,","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":11},{"ref":"Jeremiah 36:12","short":"Jer 36:12","text":"he went down to the king’s house, into the secretary’s chamber, and all the officials were sitting there: Elishama the secretary, Delaiah the son of Shemaiah, Elnathan the son of Achbor, Gemariah the son of Shaphan, Zedekiah the son of Hananiah, and all the officials.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":12},{"ref":"Jeremiah 36:13","short":"Jer 36:13","text":"And Micaiah told them all the words that he had heard, when Baruch read the scroll in the hearing of the people.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":13},{"ref":"Jeremiah 36:14","short":"Jer 36:14","text":"Then all the officials sent Jehudi the son of Nethaniah, son of Shelemiah, son of Cushi, to say to Baruch, “Take in your hand the scroll that you read in the hearing of the people, and come.” So Baruch the son of Neriah took the scroll in his hand and came to them.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":14},{"ref":"Jeremiah 36:15","short":"Jer 36:15","text":"And they said to him, “Sit down and read it.” So Baruch read it to them.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":15},{"ref":"Jeremiah 36:16","short":"Jer 36:16","text":"When they heard all the words, they turned one to another in fear. And they said to Baruch, “We must report all these words to the king.”","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":16},{"ref":"Jeremiah 36:17","short":"Jer 36:17","text":"Then they asked Baruch, “Tell us, please, how did you write all these words? Was it at his dictation?”","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":17},{"ref":"Jeremiah 36:18","short":"Jer 36:18","text":"Baruch answered them, “He dictated all these words to me, while I wrote them with ink on the scroll.”","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":18},{"ref":"Jeremiah 36:19","short":"Jer 36:19","text":"Then the officials said to Baruch, “Go and hide, you and Jeremiah, and let no one know where you are.”","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":19},{"ref":"Jeremiah 36:20","short":"Jer 36:20","text":"So they went into the court to the king, having put the scroll in the chamber of Elishama the secretary, and they reported all the words to the king.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":20},{"ref":"Jeremiah 36:21","short":"Jer 36:21","text":"Then the king sent Jehudi to get the scroll, and he took it from the chamber of Elishama the secretary. And Jehudi read it to the king and all the officials who stood beside the king.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":21},{"ref":"Jeremiah 36:22","short":"Jer 36:22","text":"It was the ninth month, and the king was sitting in the winter house, and there was a fire burning in the fire pot before him.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":22},{"ref":"Jeremiah 36:23","short":"Jer 36:23","text":"As Jehudi read three or four columns, the king would cut them off with a knife and throw them into the fire in the fire pot, until the entire scroll was consumed in the fire that was in the fire pot.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":23},{"ref":"Jeremiah 36:24","short":"Jer 36:24","text":"Yet neither the king nor any of his servants who heard all these words was afraid, nor did they tear their garments.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":24},{"ref":"Jeremiah 36:25","short":"Jer 36:25","text":"Even when Elnathan and Delaiah and Gemariah urged the king not to burn the scroll, he would not listen to them.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":25},{"ref":"Jeremiah 36:26","short":"Jer 36:26","text":"And the king commanded Jerahmeel the king’s son and Seraiah the son of Azriel and Shelemiah the son of Abdeel to seize Baruch the secretary and Jeremiah the prophet, but the LORD hid them.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":26},{"ref":"Jeremiah 36:27","short":"Jer 36:27","text":"Now after the king had burned the scroll with the words that Baruch wrote at Jeremiah’s dictation, the word of the LORD came to Jeremiah:","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":27},{"ref":"Jeremiah 36:28","short":"Jer 36:28","text":"“Take another scroll and write on it all the former words that were in the first scroll, which Jehoiakim the king of Judah has burned.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":28},{"ref":"Jeremiah 36:29","short":"Jer 36:29","text":"And concerning Jehoiakim king of Judah you shall say, ‘Thus says the LORD, You have burned this scroll, saying, “Why have you written in it that the king of Babylon will certainly come and destroy this land, and will cut off from it man and beast?”","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":29},{"ref":"Jeremiah 36:30","short":"Jer 36:30","text":"Therefore thus says the LORD concerning Jehoiakim king of Judah: He shall have none to sit on the throne of David, and his dead body shall be cast out to the heat by day and the frost by night.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":30},{"ref":"Jeremiah 36:31","short":"Jer 36:31","text":"And I will punish him and his offspring and his servants for their iniquity. I will bring upon them and upon the inhabitants of Jerusalem and upon the people of Judah all the disaster that I have pronounced against them, but they would not hear.’”","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":31},{"ref":"Jeremiah 36:32","short":"Jer 36:32","text":"Then Jeremiah took another scroll and gave it to Baruch the scribe, the son of Neriah, who wrote on it at the dictation of Jeremiah all the words of the scroll that Jehoiakim king of Judah had burned in the fire. And many similar words were added to them.","url":"ot/jeremiah/Jeremiah_36.html","book":"Jeremiah","ch":36,"v":32},{"ref":"Jeremiah 37:1","short":"Jer 37:1","text":"Zedekiah the son of Josiah, whom Nebuchadnezzar king of Babylon made king in the land of Judah, reigned instead of Coniah the son of Jehoiakim.","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":1},{"ref":"Jeremiah 37:2","short":"Jer 37:2","text":"But neither he nor his servants nor the people of the land listened to the words of the LORD that he spoke through Jeremiah the prophet.","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":2},{"ref":"Jeremiah 37:3","short":"Jer 37:3","text":"King Zedekiah sent Jehucal the son of Shelemiah, and Zephaniah the priest, the son of Maaseiah, to Jeremiah the prophet, saying, “Please pray for us to the LORD our God.”","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":3},{"ref":"Jeremiah 37:4","short":"Jer 37:4","text":"Now Jeremiah was still going in and out among the people, for he had not yet been put in prison.","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":4},{"ref":"Jeremiah 37:5","short":"Jer 37:5","text":"The army of Pharaoh had come out of Egypt. And when the Chaldeans who were besieging Jerusalem heard news about them, they withdrew from Jerusalem.","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":5},{"ref":"Jeremiah 37:6","short":"Jer 37:6","text":"Then the word of the LORD came to Jeremiah the prophet:","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":6},{"ref":"Jeremiah 37:7","short":"Jer 37:7","text":"“Thus says the LORD, God of Israel: Thus shall you say to the king of Judah who sent you to me to inquire of me, ‘Behold, Pharaoh’s army that came to help you is about to return to Egypt, to its own land.","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":7},{"ref":"Jeremiah 37:8","short":"Jer 37:8","text":"And the Chaldeans shall come back and fight against this city. They shall capture it and burn it with fire.","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":8},{"ref":"Jeremiah 37:9","short":"Jer 37:9","text":"Thus says the LORD, Do not deceive yourselves, saying, “The Chaldeans will surely go away from us,” for they will not go away.","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":9},{"ref":"Jeremiah 37:10","short":"Jer 37:10","text":"For even if you should defeat the whole army of Chaldeans who are fighting against you, and there remained of them only wounded men, every man in his tent, they would rise up and burn this city with fire.’”","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":10},{"ref":"Jeremiah 37:11","short":"Jer 37:11","text":"Now when the Chaldean army had withdrawn from Jerusalem at the approach of Pharaoh’s army,","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":11},{"ref":"Jeremiah 37:12","short":"Jer 37:12","text":"Jeremiah set out from Jerusalem to go to the land of Benjamin to receive his portion there among the people.","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":12},{"ref":"Jeremiah 37:13","short":"Jer 37:13","text":"When he was at the Benjamin Gate, a sentry there named Irijah the son of Shelemiah, son of Hananiah, seized Jeremiah the prophet, saying, “You are deserting to the Chaldeans.”","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":13},{"ref":"Jeremiah 37:14","short":"Jer 37:14","text":"And Jeremiah said, “It is a lie; I am not deserting to the Chaldeans.” But Irijah would not listen to him, and seized Jeremiah and brought him to the officials.","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":14},{"ref":"Jeremiah 37:15","short":"Jer 37:15","text":"And the officials were enraged at Jeremiah, and they beat him and imprisoned him in the house of Jonathan the secretary, for it had been made a prison.","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":15},{"ref":"Jeremiah 37:16","short":"Jer 37:16","text":"When Jeremiah had come to the dungeon cells and remained there many days,","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":16},{"ref":"Jeremiah 37:17","short":"Jer 37:17","text":"King Zedekiah sent for him and received him. The king questioned him secretly in his house and said, “Is there any word from the LORD?” Jeremiah said, “There is.” Then he said, “You shall be delivered into the hand of the king of Babylon.”","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":17},{"ref":"Jeremiah 37:18","short":"Jer 37:18","text":"Jeremiah also said to King Zedekiah, “What wrong have I done to you or your servants or this people, that you have put me in prison?","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":18},{"ref":"Jeremiah 37:19","short":"Jer 37:19","text":"Where are your prophets who prophesied to you, saying, ‘The king of Babylon will not come against you and against this land’?","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":19},{"ref":"Jeremiah 37:20","short":"Jer 37:20","text":"Now hear, please, O my lord the king: let my humble plea come before you and do not send me back to the house of Jonathan the secretary, lest I die there.”","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":20},{"ref":"Jeremiah 37:21","short":"Jer 37:21","text":"So King Zedekiah gave orders, and they committed Jeremiah to the court of the guard. And a loaf of bread was given him daily from the bakers’ street, until all the bread of the city was gone. So Jeremiah remained in the court of the guard.","url":"ot/jeremiah/Jeremiah_37.html","book":"Jeremiah","ch":37,"v":21},{"ref":"Jeremiah 38:1","short":"Jer 38:1","text":"Now Shephatiah the son of Mattan, Gedaliah the son of Pashhur, Jucal the son of Shelemiah, and Pashhur the son of Malchiah heard the words that Jeremiah was saying to all the people:","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":1},{"ref":"Jeremiah 38:2","short":"Jer 38:2","text":"“Thus says the LORD: He who stays in this city shall die by the sword, by famine, and by pestilence, but he who goes out to the Chaldeans shall live. He shall have his life as a prize of war, and live.","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":2},{"ref":"Jeremiah 38:3","short":"Jer 38:3","text":"Thus says the LORD: This city shall surely be given into the hand of the army of the king of Babylon and be taken.”","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":3},{"ref":"Jeremiah 38:4","short":"Jer 38:4","text":"Then the officials said to the king, “Let this man be put to death, for he is weakening the hands of the soldiers who are left in this city, and the hands of all the people, by speaking such words to them. For this man is not seeking the welfare of this people, but their harm.”","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":4},{"ref":"Jeremiah 38:5","short":"Jer 38:5","text":"King Zedekiah said, “Behold, he is in your hands, for the king can do nothing against you.”","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":5},{"ref":"Jeremiah 38:6","short":"Jer 38:6","text":"So they took Jeremiah and cast him into the cistern of Malchiah, the king’s son, which was in the court of the guard, letting Jeremiah down by ropes. And there was no water in the cistern, but only mud, and Jeremiah sank in the mud.","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":6},{"ref":"Jeremiah 38:7","short":"Jer 38:7","text":"When Ebed-melech the Ethiopian, a eunuch who was in the king’s house, heard that they had put Jeremiah into the cistern—the king was sitting in the Benjamin Gate—","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":7},{"ref":"Jeremiah 38:8","short":"Jer 38:8","text":"Ebed-melech went from the king’s house and said to the king,","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":8},{"ref":"Jeremiah 38:9","short":"Jer 38:9","text":"“My lord the king, these men have done evil in all that they did to Jeremiah the prophet by casting him into the cistern, and he will die there of hunger, for there is no bread left in the city.”","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":9},{"ref":"Jeremiah 38:10","short":"Jer 38:10","text":"Then the king commanded Ebed-melech the Ethiopian, “Take thirty men with you from here, and lift Jeremiah the prophet out of the cistern before he dies.”","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":10},{"ref":"Jeremiah 38:11","short":"Jer 38:11","text":"So Ebed-melech took the men with him and went to the house of the king, to a wardrobe in the storehouse, and took from there old rags and worn-out clothes, which he let down to Jeremiah in the cistern by ropes.","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":11},{"ref":"Jeremiah 38:12","short":"Jer 38:12","text":"Then Ebed-melech the Ethiopian said to Jeremiah, “Put the rags and clothes between your armpits and the ropes.” Jeremiah did so.","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":12},{"ref":"Jeremiah 38:13","short":"Jer 38:13","text":"Then they drew Jeremiah up with ropes and lifted him out of the cistern. And Jeremiah remained in the court of the guard.","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":13},{"ref":"Jeremiah 38:14","short":"Jer 38:14","text":"King Zedekiah sent for Jeremiah the prophet and received him at the third entrance of the temple of the LORD. The king said to Jeremiah, “I will ask you a question; hide nothing from me.”","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":14},{"ref":"Jeremiah 38:15","short":"Jer 38:15","text":"Jeremiah said to Zedekiah, “If I tell you, will you not surely put me to death? And if I give you counsel, you will not listen to me.”","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":15},{"ref":"Jeremiah 38:16","short":"Jer 38:16","text":"Then King Zedekiah swore secretly to Jeremiah, “As the LORD lives, who made our souls, I will not put you to death or deliver you into the hand of these men who seek your life.”","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":16},{"ref":"Jeremiah 38:17","short":"Jer 38:17","text":"Then Jeremiah said to Zedekiah, “Thus says the LORD, the God of hosts, the God of Israel: If you will surrender to the officials of the king of Babylon, then your life shall be spared, and this city shall not be burned with fire, and you and your house shall live.","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":17},{"ref":"Jeremiah 38:18","short":"Jer 38:18","text":"But if you do not surrender to the officials of the king of Babylon, then this city shall be given into the hand of the Chaldeans, and they shall burn it with fire, and you shall not escape from their hand.”","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":18},{"ref":"Jeremiah 38:19","short":"Jer 38:19","text":"King Zedekiah said to Jeremiah, “I am afraid of the Judeans who have deserted to the Chaldeans, lest I be handed over to them and they deal cruelly with me.”","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":19},{"ref":"Jeremiah 38:20","short":"Jer 38:20","text":"Jeremiah said, “You shall not be given to them. Obey now the voice of the LORD in what I say to you, and it shall be well with you, and your life shall be spared.","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":20},{"ref":"Jeremiah 38:21","short":"Jer 38:21","text":"But if you refuse to surrender, this is the vision which the LORD has shown to me:","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":21},{"ref":"Jeremiah 38:22","short":"Jer 38:22","text":"Behold, all the women left in the house of the king of Judah were being led out to the officials of the king of Babylon and were saying, “‘Your trusted friends have deceived you and prevailed against you; now that your feet are sunk in the mud, they turn away from you.’","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":22},{"ref":"Jeremiah 38:23","short":"Jer 38:23","text":"All your wives and your sons shall be led out to the Chaldeans, and you yourself shall not escape from their hand, but shall be seized by the king of Babylon, and this city shall be burned with fire.”","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":23},{"ref":"Jeremiah 38:24","short":"Jer 38:24","text":"Then Zedekiah said to Jeremiah, “Let no one know of these words, and you shall not die.","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":24},{"ref":"Jeremiah 38:25","short":"Jer 38:25","text":"If the officials hear that I have spoken with you and come to you and say to you, ‘Tell us what you said to the king and what the king said to you; hide nothing from us and we will not put you to death,’","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":25},{"ref":"Jeremiah 38:26","short":"Jer 38:26","text":"then you shall say to them, ‘I made a humble plea to the king that he would not send me back to the house of Jonathan to die there.’”","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":26},{"ref":"Jeremiah 38:27","short":"Jer 38:27","text":"Then all the officials came to Jeremiah and asked him, and he answered them as the king had instructed him. So they stopped speaking with him, for the conversation had not been overheard.","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":27},{"ref":"Jeremiah 38:28","short":"Jer 38:28","text":"And Jeremiah remained in the court of the guard until the day that Jerusalem was taken.","url":"ot/jeremiah/Jeremiah_38.html","book":"Jeremiah","ch":38,"v":28},{"ref":"Jeremiah 39:1","short":"Jer 39:1","text":"In the ninth year of Zedekiah king of Judah, in the tenth month, Nebuchadnezzar king of Babylon and all his army came against Jerusalem and besieged it.","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":1},{"ref":"Jeremiah 39:2","short":"Jer 39:2","text":"In the eleventh year of Zedekiah, in the fourth month, on the ninth day of the month, a breach was made in the city.","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":2},{"ref":"Jeremiah 39:3","short":"Jer 39:3","text":"Then all the officials of the king of Babylon came and sat in the middle gate: Nergal-sar-ezer of Samgar, Nebu-sar-sekim the Rab-saris, Nergal-sar-ezer the Rab-mag, with all the rest of the officers of the king of Babylon.","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":3},{"ref":"Jeremiah 39:4","short":"Jer 39:4","text":"When Zedekiah king of Judah and all the soldiers saw them, they fled, going out of the city at night by way of the king’s garden through the gate between the two walls; and they went toward the Arabah.","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":4},{"ref":"Jeremiah 39:5","short":"Jer 39:5","text":"But the army of the Chaldeans pursued them and overtook Zedekiah in the plains of Jericho. And when they had taken him, they brought him up to Nebuchadnezzar king of Babylon, at Riblah, in the land of Hamath; and he passed sentence on him.","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":5},{"ref":"Jeremiah 39:6","short":"Jer 39:6","text":"The king of Babylon slaughtered the sons of Zedekiah at Riblah before his eyes, and the king of Babylon slaughtered all the nobles of Judah.","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":6},{"ref":"Jeremiah 39:7","short":"Jer 39:7","text":"He put out the eyes of Zedekiah and bound him in chains to take him to Babylon.","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":7},{"ref":"Jeremiah 39:8","short":"Jer 39:8","text":"The Chaldeans burned the king’s house and the house of the people, and broke down the walls of Jerusalem.","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":8},{"ref":"Jeremiah 39:9","short":"Jer 39:9","text":"Then Nebuzaradan, the captain of the guard, carried into exile to Babylon the rest of the people who were left in the city, those who had deserted to him, and the people who remained.","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":9},{"ref":"Jeremiah 39:10","short":"Jer 39:10","text":"Nebuzaradan, the captain of the guard, left in the land of Judah some of the poor people who owned nothing, and gave them vineyards and fields at the same time.","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":10},{"ref":"Jeremiah 39:11","short":"Jer 39:11","text":"Nebuchadnezzar king of Babylon gave command concerning Jeremiah through Nebuzaradan, the captain of the guard, saying,","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":11},{"ref":"Jeremiah 39:12","short":"Jer 39:12","text":"“Take him, look after him well, and do him no harm, but deal with him as he tells you.”","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":12},{"ref":"Jeremiah 39:13","short":"Jer 39:13","text":"So Nebuzaradan the captain of the guard, Nebushazban the Rab-saris, Nergal-sar-ezer the Rab-mag, and all the chief officers of the king of Babylon","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":13},{"ref":"Jeremiah 39:14","short":"Jer 39:14","text":"sent and took Jeremiah from the court of the guard. They entrusted him to Gedaliah the son of Ahikam, son of Shaphan, that he should take him home. So he lived among the people.","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":14},{"ref":"Jeremiah 39:15","short":"Jer 39:15","text":"The word of the LORD came to Jeremiah while he was shut up in the court of the guard:","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":15},{"ref":"Jeremiah 39:16","short":"Jer 39:16","text":"“Go, and say to Ebed-melech the Ethiopian, ‘Thus says the LORD of hosts, the God of Israel: Behold, I will fulfill my words against this city for harm and not for good, and they shall be accomplished before you on that day.","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":16},{"ref":"Jeremiah 39:17","short":"Jer 39:17","text":"But I will deliver you on that day, declares the LORD, and you shall not be given into the hand of the men of whom you are afraid.","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":17},{"ref":"Jeremiah 39:18","short":"Jer 39:18","text":"For I will surely save you, and you shall not fall by the sword, but you shall have your life as a prize of war, because you have put your trust in me, declares the LORD.’”","url":"ot/jeremiah/Jeremiah_39.html","book":"Jeremiah","ch":39,"v":18},{"ref":"Jeremiah 40:1","short":"Jer 40:1","text":"The word that came to Jeremiah from the LORD after Nebuzaradan the captain of the guard had let him go from Ramah, when he took him bound in chains along with all the captives of Jerusalem and Judah who were being exiled to Babylon.","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":1},{"ref":"Jeremiah 40:2","short":"Jer 40:2","text":"The captain of the guard took Jeremiah and said to him, “The LORD your God pronounced this disaster against this place.","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":2},{"ref":"Jeremiah 40:3","short":"Jer 40:3","text":"The LORD has brought it about, and has done as he said. Because you sinned against the LORD and did not obey his voice, this thing has come upon you.","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":3},{"ref":"Jeremiah 40:4","short":"Jer 40:4","text":"Now, behold, I release you today from the chains on your hands. If it seems good to you to come with me to Babylon, come, and I will look after you well, but if it seems wrong to you to come with me to Babylon, do not come. See, the whole land is before you; go wherever you think it good and right to go.","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":4},{"ref":"Jeremiah 40:5","short":"Jer 40:5","text":"If you remain, then return to Gedaliah the son of Ahikam, son of Shaphan, whom the king of Babylon appointed governor of the cities of Judah, and dwell with him among the people. Or go wherever you think it right to go.” So the captain of the guard gave him an allowance of food and a present, and let him go.","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":5},{"ref":"Jeremiah 40:6","short":"Jer 40:6","text":"Then Jeremiah went to Gedaliah the son of Ahikam, at Mizpah, and lived with him among the people who were left in the land.","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":6},{"ref":"Jeremiah 40:7","short":"Jer 40:7","text":"When all the captains of the forces in the open country and their men heard that the king of Babylon had appointed Gedaliah the son of Ahikam governor in the land and had committed to him men, women, and children, those of the poorest of the land who had not been taken into exile to Babylon,","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":7},{"ref":"Jeremiah 40:8","short":"Jer 40:8","text":"they went to Gedaliah at Mizpah—Ishmael the son of Nethaniah, Johanan the son of Kareah, Seraiah the son of Tanhumeth, the sons of Ephai the Netophathite, Jezaniah the son of the Maacathite, they and their men.","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":8},{"ref":"Jeremiah 40:9","short":"Jer 40:9","text":"Gedaliah the son of Ahikam, son of Shaphan, swore to them and their men, saying, “Do not be afraid to serve the Chaldeans. Dwell in the land and serve the king of Babylon, and it shall be well with you.","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":9},{"ref":"Jeremiah 40:10","short":"Jer 40:10","text":"As for me, I will dwell at Mizpah, to represent you before the Chaldeans who will come to us. But as for you, gather wine and summer fruits and oil, and store them in your vessels, and dwell in your cities that you have taken.”","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":10},{"ref":"Jeremiah 40:11","short":"Jer 40:11","text":"Likewise, when all the Judeans who were in Moab and among the Ammonites and in Edom and in other lands heard that the king of Babylon had left a remnant in Judah and had appointed Gedaliah the son of Ahikam, son of Shaphan, as governor over them,","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":11},{"ref":"Jeremiah 40:12","short":"Jer 40:12","text":"then all the Judeans returned from all the places to which they had been driven and came to the land of Judah, to Gedaliah at Mizpah. And they gathered wine and summer fruits in great abundance.","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":12},{"ref":"Jeremiah 40:13","short":"Jer 40:13","text":"Now Johanan the son of Kareah and all the leaders of the forces in the open country came to Gedaliah at Mizpah","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":13},{"ref":"Jeremiah 40:14","short":"Jer 40:14","text":"and said to him, “Do you know that Baalis the king of the Ammonites has sent Ishmael the son of Nethaniah to take your life?” But Gedaliah the son of Ahikam would not believe them.","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":14},{"ref":"Jeremiah 40:15","short":"Jer 40:15","text":"Then Johanan the son of Kareah spoke secretly to Gedaliah at Mizpah, “Please let me go and strike down Ishmael the son of Nethaniah, and no one will know it. Why should he take your life, so that all the Judeans who are gathered about you would be scattered, and the remnant of Judah would perish?”","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":15},{"ref":"Jeremiah 40:16","short":"Jer 40:16","text":"But Gedaliah the son of Ahikam said to Johanan the son of Kareah, “You shall not do this thing, for you are speaking falsely of Ishmael.”","url":"ot/jeremiah/Jeremiah_40.html","book":"Jeremiah","ch":40,"v":16},{"ref":"Jeremiah 41:1","short":"Jer 41:1","text":"In the seventh month, Ishmael the son of Nethaniah, son of Elishama, of the royal family, one of the chief officers of the king, came with ten men to Gedaliah the son of Ahikam, at Mizpah. As they ate bread together there at Mizpah,","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":1},{"ref":"Jeremiah 41:2","short":"Jer 41:2","text":"Ishmael the son of Nethaniah and the ten men with him rose up and struck down Gedaliah the son of Ahikam, son of Shaphan, with the sword, and killed him, whom the king of Babylon had appointed governor in the land.","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":2},{"ref":"Jeremiah 41:3","short":"Jer 41:3","text":"Ishmael also struck down all the Judeans who were with Gedaliah at Mizpah, and the Chaldean soldiers who happened to be there.","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":3},{"ref":"Jeremiah 41:4","short":"Jer 41:4","text":"On the day after the murder of Gedaliah, before anyone knew of it,","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":4},{"ref":"Jeremiah 41:5","short":"Jer 41:5","text":"eighty men arrived from Shechem and Shiloh and Samaria, with their beards shaved and their clothes torn, and their bodies gashed, bringing grain offerings and incense to present at the temple of the LORD.","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":5},{"ref":"Jeremiah 41:6","short":"Jer 41:6","text":"And Ishmael the son of Nethaniah came out from Mizpah to meet them, weeping as he came. As he met them, he said to them, “Come in to Gedaliah the son of Ahikam.”","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":6},{"ref":"Jeremiah 41:7","short":"Jer 41:7","text":"When they came into the city, Ishmael the son of Nethaniah and the men with him slaughtered them and cast them into a cistern.","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":7},{"ref":"Jeremiah 41:8","short":"Jer 41:8","text":"But there were ten men among them who said to Ishmael, “Do not put us to death, for we have stores of wheat, barley, oil, and honey hidden in the fields.” So he refrained and did not put them to death with their companions.","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":8},{"ref":"Jeremiah 41:9","short":"Jer 41:9","text":"Now the cistern into which Ishmael had thrown all the bodies of the men whom he had struck down along with Gedaliah was the large cistern that King Asa had made for defense against Baasha king of Israel; Ishmael the son of Nethaniah filled it with the slain.","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":9},{"ref":"Jeremiah 41:10","short":"Jer 41:10","text":"Then Ishmael took captive all the rest of the people who were in Mizpah, the king’s daughters and all the people who were left at Mizpah, whom Nebuzaradan, the captain of the guard, had committed to Gedaliah the son of Ahikam. Ishmael the son of Nethaniah took them captive and set out to cross over to the Ammonites.","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":10},{"ref":"Jeremiah 41:11","short":"Jer 41:11","text":"But when Johanan the son of Kareah and all the leaders of the forces with him heard of all the evil that Ishmael the son of Nethaniah had done,","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":11},{"ref":"Jeremiah 41:12","short":"Jer 41:12","text":"they took all their men and went to fight against Ishmael the son of Nethaniah. They came upon him at the great pool that is in Gibeon.","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":12},{"ref":"Jeremiah 41:13","short":"Jer 41:13","text":"And when all the people who were with Ishmael saw Johanan the son of Kareah and all the leaders of the forces with him, they rejoiced.","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":13},{"ref":"Jeremiah 41:14","short":"Jer 41:14","text":"So all the people whom Ishmael had carried away captive from Mizpah turned around and came back, and went to Johanan the son of Kareah.","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":14},{"ref":"Jeremiah 41:15","short":"Jer 41:15","text":"But Ishmael the son of Nethaniah escaped from Johanan with eight men, and went to the Ammonites.","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":15},{"ref":"Jeremiah 41:16","short":"Jer 41:16","text":"Then Johanan the son of Kareah and all the leaders of the forces with him took from Mizpah all the rest of the people whom he had recovered from Ishmael the son of Nethaniah, after he had struck down Gedaliah the son of Ahikam—soldiers, women, children, and eunuchs, whom Johanan brought back from Gibeon.","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":16},{"ref":"Jeremiah 41:17","short":"Jer 41:17","text":"And they went and stayed at Geruth Chimham near Bethlehem, intending to go to Egypt","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":17},{"ref":"Jeremiah 41:18","short":"Jer 41:18","text":"because of the Chaldeans. For they were afraid of them, because Ishmael the son of Nethaniah had struck down Gedaliah the son of Ahikam, whom the king of Babylon had made governor over the land.","url":"ot/jeremiah/Jeremiah_41.html","book":"Jeremiah","ch":41,"v":18},{"ref":"Jeremiah 42:1","short":"Jer 42:1","text":"Then all the commanders of the forces, and Johanan the son of Kareah and Jezaniah the son of Hoshaiah, and all the people from the least to the greatest, came near","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":1},{"ref":"Jeremiah 42:2","short":"Jer 42:2","text":"and said to Jeremiah the prophet, “Let our plea for mercy come before you, and pray to the LORD your God for us, for all this remnant—because we are left with but a few, as your eyes see us—","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":2},{"ref":"Jeremiah 42:3","short":"Jer 42:3","text":"that the LORD your God may show us the way we should go, and the thing that we should do.”","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":3},{"ref":"Jeremiah 42:4","short":"Jer 42:4","text":"Jeremiah the prophet said to them, “I have heard you. Behold, I will pray to the LORD your God according to your request, and whatever the LORD answers you I will tell you. I will keep nothing back from you.”","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":4},{"ref":"Jeremiah 42:5","short":"Jer 42:5","text":"Then they said to Jeremiah, “May the LORD be a true and faithful witness against us if we do not act according to all the word with which the LORD your God sends you to us.","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":5},{"ref":"Jeremiah 42:6","short":"Jer 42:6","text":"Whether it is good or bad, we will obey the voice of the LORD our God to whom we are sending you, that it may be well with us when we obey the voice of the LORD our God.”","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":6},{"ref":"Jeremiah 42:7","short":"Jer 42:7","text":"At the end of ten days the word of the LORD came to Jeremiah.","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":7},{"ref":"Jeremiah 42:8","short":"Jer 42:8","text":"Then he summoned Johanan the son of Kareah and all the commanders of the forces who were with him, and all the people from the least to the greatest,","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":8},{"ref":"Jeremiah 42:9","short":"Jer 42:9","text":"and said to them, “Thus says the LORD, the God of Israel, to whom you sent me to present your plea for mercy before him:","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":9},{"ref":"Jeremiah 42:10","short":"Jer 42:10","text":"If you will remain in this land, then I will build you up and not pull you down; I will plant you, and not pluck you up; for I relent of the disaster that I did to you.","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":10},{"ref":"Jeremiah 42:11","short":"Jer 42:11","text":"Do not fear the king of Babylon, of whom you are afraid. Do not fear him, declares the LORD, for I am with you, to save you and to deliver you from his hand.","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":11},{"ref":"Jeremiah 42:12","short":"Jer 42:12","text":"I will grant you mercy, that he may have mercy on you and let you remain in your own land.","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":12},{"ref":"Jeremiah 42:13","short":"Jer 42:13","text":"But if you say, ‘We will not remain in this land,’ disobeying the voice of the LORD your God","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":13},{"ref":"Jeremiah 42:14","short":"Jer 42:14","text":"and saying, ‘No, we will go to the land of Egypt, where we shall not see war or hear the sound of the trumpet or be hungry for bread, and we will dwell there,’","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":14},{"ref":"Jeremiah 42:15","short":"Jer 42:15","text":"then hear the word of the LORD, O remnant of Judah. Thus says the LORD of hosts, the God of Israel: If you set your faces to enter Egypt and go to live there,","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":15},{"ref":"Jeremiah 42:16","short":"Jer 42:16","text":"then the sword that you fear shall overtake you there in the land of Egypt, and the famine of which you are afraid shall follow close after you to Egypt, and there you shall die.","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":16},{"ref":"Jeremiah 42:17","short":"Jer 42:17","text":"All the men who set their faces to go to Egypt to live there shall die by the sword, by famine, and by pestilence. They shall have no remnant or survivor from the disaster that I will bring upon them.","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":17},{"ref":"Jeremiah 42:18","short":"Jer 42:18","text":"“For thus says the LORD of hosts, the God of Israel: As my anger and my wrath were poured out on the inhabitants of Jerusalem, so my wrath will be poured out on you when you go to Egypt. You shall become an execration, a horror, a curse, and a taunt. You shall see this place no more.","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":18},{"ref":"Jeremiah 42:19","short":"Jer 42:19","text":"The LORD has said to you, O remnant of Judah, ‘Do not go to Egypt.’ Know for a certainty that I have warned you this day","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":19},{"ref":"Jeremiah 42:20","short":"Jer 42:20","text":"that you have gone astray at the cost of your lives. For you sent me to the LORD your God, saying, ‘Pray for us to the LORD our God, and whatever the LORD our God says, declare to us and we will do it.’","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":20},{"ref":"Jeremiah 42:21","short":"Jer 42:21","text":"And I have this day declared it to you, but you have not obeyed the voice of the LORD your God in anything that he sent me to tell you.","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":21},{"ref":"Jeremiah 42:22","short":"Jer 42:22","text":"Now therefore know for a certainty that you shall die by the sword, by famine, and by pestilence in the place where you desire to go to live.”","url":"ot/jeremiah/Jeremiah_42.html","book":"Jeremiah","ch":42,"v":22},{"ref":"Jeremiah 43:1","short":"Jer 43:1","text":"When Jeremiah finished speaking to all the people all these words of the LORD their God, with which the LORD their God had sent him to them,","url":"ot/jeremiah/Jeremiah_43.html","book":"Jeremiah","ch":43,"v":1},{"ref":"Jeremiah 43:2","short":"Jer 43:2","text":"Azariah the son of Hoshaiah and Johanan the son of Kareah and all the insolent men said to Jeremiah, “You are telling a lie. The LORD our God did not send you to say, ‘Do not go to Egypt to live there,’","url":"ot/jeremiah/Jeremiah_43.html","book":"Jeremiah","ch":43,"v":2},{"ref":"Jeremiah 43:3","short":"Jer 43:3","text":"but Baruch the son of Neriah has set you against us, to deliver us into the hand of the Chaldeans, that they may kill us or take us into exile in Babylon.”","url":"ot/jeremiah/Jeremiah_43.html","book":"Jeremiah","ch":43,"v":3},{"ref":"Jeremiah 43:4","short":"Jer 43:4","text":"So Johanan the son of Kareah and all the commanders of the forces and all the people did not obey the voice of the LORD, to remain in the land of Judah.","url":"ot/jeremiah/Jeremiah_43.html","book":"Jeremiah","ch":43,"v":4},{"ref":"Jeremiah 43:5","short":"Jer 43:5","text":"But Johanan the son of Kareah and all the commanders of the forces took all the remnant of Judah who had returned to live in the land of Judah from all the nations to which they had been driven—","url":"ot/jeremiah/Jeremiah_43.html","book":"Jeremiah","ch":43,"v":5},{"ref":"Jeremiah 43:6","short":"Jer 43:6","text":"the men, the women, the children, the princesses, and every person whom Nebuzaradan the captain of the guard had left with Gedaliah the son of Ahikam, son of Shaphan; also Jeremiah the prophet and Baruch the son of Neriah.","url":"ot/jeremiah/Jeremiah_43.html","book":"Jeremiah","ch":43,"v":6},{"ref":"Jeremiah 43:7","short":"Jer 43:7","text":"And they came into the land of Egypt, for they did not obey the voice of the LORD. And they arrived at Tahpanhes.","url":"ot/jeremiah/Jeremiah_43.html","book":"Jeremiah","ch":43,"v":7},{"ref":"Jeremiah 43:8","short":"Jer 43:8","text":"Then the word of the LORD came to Jeremiah in Tahpanhes:","url":"ot/jeremiah/Jeremiah_43.html","book":"Jeremiah","ch":43,"v":8},{"ref":"Jeremiah 43:9","short":"Jer 43:9","text":"“Take in your hands large stones and hide them in the mortar in the pavement that is at the entrance to Pharaoh’s palace in Tahpanhes, in the sight of the men of Judah,","url":"ot/jeremiah/Jeremiah_43.html","book":"Jeremiah","ch":43,"v":9},{"ref":"Jeremiah 43:10","short":"Jer 43:10","text":"and say to them, ‘Thus says the LORD of hosts, the God of Israel: Behold, I will send and take Nebuchadnezzar the king of Babylon, my servant, and I will set his throne above these stones that I have hidden, and he will spread his royal canopy over them.","url":"ot/jeremiah/Jeremiah_43.html","book":"Jeremiah","ch":43,"v":10},{"ref":"Jeremiah 43:11","short":"Jer 43:11","text":"He shall come and strike the land of Egypt, giving over to the pestilence those who are doomed to the pestilence, to captivity those who are doomed to captivity, and to the sword those who are doomed to the sword.","url":"ot/jeremiah/Jeremiah_43.html","book":"Jeremiah","ch":43,"v":11},{"ref":"Jeremiah 43:12","short":"Jer 43:12","text":"I shall kindle a fire in the temples of the gods of Egypt, and he shall burn them and carry them away captive. And he shall clean the land of Egypt as a shepherd cleans his cloak of vermin, and he shall go away from there in peace.","url":"ot/jeremiah/Jeremiah_43.html","book":"Jeremiah","ch":43,"v":12},{"ref":"Jeremiah 43:13","short":"Jer 43:13","text":"He shall break the obelisks of Heliopolis, which is in the land of Egypt, and the temples of the gods of Egypt he shall burn with fire.’”","url":"ot/jeremiah/Jeremiah_43.html","book":"Jeremiah","ch":43,"v":13},{"ref":"Jeremiah 44:1","short":"Jer 44:1","text":"The word that came to Jeremiah concerning all the Judeans who lived in the land of Egypt, at Migdol, at Tahpanhes, at Memphis, and in the land of Pathros,","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":1},{"ref":"Jeremiah 44:2","short":"Jer 44:2","text":"“Thus says the LORD of hosts, the God of Israel: You have seen all the disaster that I brought upon Jerusalem and upon all the cities of Judah. Behold, this day they are a desolation, and no one dwells in them,","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":2},{"ref":"Jeremiah 44:3","short":"Jer 44:3","text":"because of the evil that they committed, provoking me to anger, in that they went to make offerings and serve other gods that they knew not, neither they, nor you, nor your fathers.","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":3},{"ref":"Jeremiah 44:4","short":"Jer 44:4","text":"Yet I persistently sent to you all my servants the prophets, saying, ‘Oh, do not do this abomination that I hate!’","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":4},{"ref":"Jeremiah 44:5","short":"Jer 44:5","text":"But they did not listen or incline their ear, to turn from their evil and make no offerings to other gods.","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":5},{"ref":"Jeremiah 44:6","short":"Jer 44:6","text":"Therefore my wrath and my anger were poured out and kindled in the cities of Judah and in the streets of Jerusalem, and they became a waste and a desolation, as at this day.","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":6},{"ref":"Jeremiah 44:7","short":"Jer 44:7","text":"And now thus says the LORD God of hosts, the God of Israel: Why do you commit this great evil against yourselves, to cut off from you man and woman, infant and child, from the midst of Judah, leaving you no remnant?","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":7},{"ref":"Jeremiah 44:8","short":"Jer 44:8","text":"Why do you provoke me to anger with the works of your hands, making offerings to other gods in the land of Egypt where you have come to live, so that you may be cut off and become a curse and a taunt among all the nations of the earth?","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":8},{"ref":"Jeremiah 44:9","short":"Jer 44:9","text":"Have you forgotten the evil of your fathers, the evil of the kings of Judah, the evil of their wives, your own evil, and the evil of your wives, which they committed in the land of Judah and in the streets of Jerusalem?","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":9},{"ref":"Jeremiah 44:10","short":"Jer 44:10","text":"They have not humbled themselves even to this day, nor have they feared, nor walked in my law and my statutes that I set before you and before your fathers.","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":10},{"ref":"Jeremiah 44:11","short":"Jer 44:11","text":"“Therefore thus says the LORD of hosts, the God of Israel: Behold, I will set my face against you for harm, to cut off all Judah.","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":11},{"ref":"Jeremiah 44:12","short":"Jer 44:12","text":"I will take the remnant of Judah who have set their faces to come to the land of Egypt to live, and they shall all be consumed. In the land of Egypt they shall fall; by the sword and by famine they shall be consumed. From the least to the greatest, they shall die by the sword and by famine, and they shall become an oath, a horror, a curse, and a taunt.","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":12},{"ref":"Jeremiah 44:13","short":"Jer 44:13","text":"I will punish those who dwell in the land of Egypt, as I have punished Jerusalem, with the sword, with famine, and with pestilence,","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":13},{"ref":"Jeremiah 44:14","short":"Jer 44:14","text":"so that none of the remnant of Judah who have come to live in the land of Egypt shall escape or survive or return to the land of Judah, to which they desire to return to dwell there. For they shall not return, except some fugitives.”","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":14},{"ref":"Jeremiah 44:15","short":"Jer 44:15","text":"Then all the men who knew that their wives had made offerings to other gods, and all the women who stood by, a great assembly, all the people who lived in Pathros in the land of Egypt, answered Jeremiah:","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":15},{"ref":"Jeremiah 44:16","short":"Jer 44:16","text":"“As for the word that you have spoken to us in the name of the LORD, we will not listen to you.","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":16},{"ref":"Jeremiah 44:17","short":"Jer 44:17","text":"But we will do everything that we have vowed, make offerings to the queen of heaven and pour out drink offerings to her, as we did, both we and our fathers, our kings and our officials, in the cities of Judah and in the streets of Jerusalem. For then we had plenty of food, and prospered, and saw no disaster.","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":17},{"ref":"Jeremiah 44:18","short":"Jer 44:18","text":"But since we left off making offerings to the queen of heaven and pouring out drink offerings to her, we have lacked everything and have been consumed by the sword and by famine.”","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":18},{"ref":"Jeremiah 44:19","short":"Jer 44:19","text":"And the women said, “When we made offerings to the queen of heaven and poured out drink offerings to her, was it without our husbands’ approval that we made cakes for her bearing her image and poured out drink offerings to her?”","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":19},{"ref":"Jeremiah 44:20","short":"Jer 44:20","text":"Then Jeremiah said to all the people, men and women, all the people who had given him this answer:","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":20},{"ref":"Jeremiah 44:21","short":"Jer 44:21","text":"“As for the offerings that you offered in the cities of Judah and in the streets of Jerusalem, you and your fathers, your kings and your officials, and the people of the land, did not the LORD remember them? Did it not come into his mind?","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":21},{"ref":"Jeremiah 44:22","short":"Jer 44:22","text":"The LORD could no longer bear your evil deeds and the abominations that you committed. Therefore your land has become a desolation and a waste and a curse, without inhabitant, as it is this day.","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":22},{"ref":"Jeremiah 44:23","short":"Jer 44:23","text":"It is because you made offerings and because you sinned against the LORD and did not obey the voice of the LORD or walk in his law and in his statutes and in his testimonies that this disaster has happened to you, as at this day.”","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":23},{"ref":"Jeremiah 44:24","short":"Jer 44:24","text":"Jeremiah said to all the people and all the women, “Hear the word of the LORD, all you of Judah who are in the land of Egypt.","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":24},{"ref":"Jeremiah 44:25","short":"Jer 44:25","text":"Thus says the LORD of hosts, the God of Israel: You and your wives have declared with your mouths, and have fulfilled it with your hands, saying, ‘We will surely perform our vows that we have made, to make offerings to the queen of heaven and to pour out drink offerings to her.’ Then confirm your vows and perform your vows!","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":25},{"ref":"Jeremiah 44:26","short":"Jer 44:26","text":"Therefore hear the word of the LORD, all you of Judah who dwell in the land of Egypt: Behold, I have sworn by my great name, says the LORD, that my name shall no more be invoked by the mouth of any man of Judah in all the land of Egypt, saying, ‘As the Lord GOD lives.’","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":26},{"ref":"Jeremiah 44:27","short":"Jer 44:27","text":"Behold, I am watching over them for disaster and not for good. All the men of Judah who are in the land of Egypt shall be consumed by the sword and by famine, until there is an end of them.","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":27},{"ref":"Jeremiah 44:28","short":"Jer 44:28","text":"And those who escape the sword shall return from the land of Egypt to the land of Judah, few in number; and all the remnant of Judah, who came to the land of Egypt to live, shall know whose word will stand, mine or theirs.","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":28},{"ref":"Jeremiah 44:29","short":"Jer 44:29","text":"This shall be the sign to you, declares the LORD, that I will punish you in this place, in order that you may know that my words will surely stand against you for harm:","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":29},{"ref":"Jeremiah 44:30","short":"Jer 44:30","text":"Thus says the LORD, Behold, I will give Pharaoh Hophra king of Egypt into the hand of his enemies and into the hand of those who seek his life, as I gave Zedekiah king of Judah into the hand of Nebuchadnezzar king of Babylon, who was his enemy and sought his life.”","url":"ot/jeremiah/Jeremiah_44.html","book":"Jeremiah","ch":44,"v":30},{"ref":"Jeremiah 45:1","short":"Jer 45:1","text":"The word that Jeremiah the prophet spoke to Baruch the son of Neriah, when he wrote these words in a book at the dictation of Jeremiah, in the fourth year of Jehoiakim the son of Josiah, king of Judah:","url":"ot/jeremiah/Jeremiah_45.html","book":"Jeremiah","ch":45,"v":1},{"ref":"Jeremiah 45:2","short":"Jer 45:2","text":"“Thus says the LORD, the God of Israel, to you, O Baruch:","url":"ot/jeremiah/Jeremiah_45.html","book":"Jeremiah","ch":45,"v":2},{"ref":"Jeremiah 45:3","short":"Jer 45:3","text":"You said, ‘Woe is me! For the LORD has added sorrow to my pain. I am weary with my groaning, and I find no rest.’","url":"ot/jeremiah/Jeremiah_45.html","book":"Jeremiah","ch":45,"v":3},{"ref":"Jeremiah 45:4","short":"Jer 45:4","text":"Thus shall you say to him, Thus says the LORD: Behold, what I have built I am breaking down, and what I have planted I am plucking up—that is, the whole land.","url":"ot/jeremiah/Jeremiah_45.html","book":"Jeremiah","ch":45,"v":4},{"ref":"Jeremiah 45:5","short":"Jer 45:5","text":"And do you seek great things for yourself? Seek them not, for behold, I am bringing disaster upon all flesh, declares the LORD. But I will give you your life as a prize of war in all places to which you may go.”","url":"ot/jeremiah/Jeremiah_45.html","book":"Jeremiah","ch":45,"v":5},{"ref":"Jeremiah 46:1","short":"Jer 46:1","text":"The word of the LORD that came to Jeremiah the prophet concerning the nations.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":1},{"ref":"Jeremiah 46:2","short":"Jer 46:2","text":"About Egypt. Concerning the army of Pharaoh Neco, king of Egypt, which was by the river Euphrates at Carchemish and which Nebuchadnezzar king of Babylon defeated in the fourth year of Jehoiakim the son of Josiah, king of Judah:","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":2},{"ref":"Jeremiah 46:3","short":"Jer 46:3","text":"“Prepare buckler and shield, and advance for battle!","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":3},{"ref":"Jeremiah 46:4","short":"Jer 46:4","text":"Harness the horses; mount, O horsemen! Take your stations with your helmets, polish your spears, put on your armor!","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":4},{"ref":"Jeremiah 46:5","short":"Jer 46:5","text":"Why have I seen it? They are dismayed and have turned backward. Their warriors are beaten down and have fled in haste; they look not back— terror on every side! declares the LORD.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":5},{"ref":"Jeremiah 46:6","short":"Jer 46:6","text":"“The swift cannot flee away, nor the warrior escape; in the north by the river Euphrates they have stumbled and fallen.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":6},{"ref":"Jeremiah 46:7","short":"Jer 46:7","text":"“Who is this, rising like the Nile, like rivers whose waters surge?","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":7},{"ref":"Jeremiah 46:8","short":"Jer 46:8","text":"Egypt rises like the Nile, like rivers whose waters surge. He said, ‘I will rise, I will cover the earth, I will destroy cities and their inhabitants.’","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":8},{"ref":"Jeremiah 46:9","short":"Jer 46:9","text":"Advance, O horses, and rage, O chariots! Let the warriors go out: men of Cush and Put who handle the shield, men of Lud, skilled in handling the bow.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":9},{"ref":"Jeremiah 46:10","short":"Jer 46:10","text":"That day is the day of the Lord GOD of hosts, a day of vengeance, to avenge himself on his foes. The sword shall devour and be sated and drink its fill of their blood. For the Lord GOD of hosts holds a sacrifice in the north country by the river Euphrates.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":10},{"ref":"Jeremiah 46:11","short":"Jer 46:11","text":"Go up to Gilead, and take balm, O virgin daughter of Egypt! In vain you have used many medicines; there is no healing for you.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":11},{"ref":"Jeremiah 46:12","short":"Jer 46:12","text":"The nations have heard of your shame, and the earth is full of your cry; for warrior has stumbled against warrior; they have both fallen together.”","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":12},{"ref":"Jeremiah 46:13","short":"Jer 46:13","text":"The word that the LORD spoke to Jeremiah the prophet about the coming of Nebuchadnezzar king of Babylon to strike the land of Egypt:","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":13},{"ref":"Jeremiah 46:14","short":"Jer 46:14","text":"“Declare in Egypt, and proclaim in Migdol; proclaim in Memphis and Tahpanhes; say, ‘Stand ready and be prepared, for the sword shall devour around you.’","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":14},{"ref":"Jeremiah 46:15","short":"Jer 46:15","text":"Why are your mighty ones face down? They do not stand because the LORD thrust them down.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":15},{"ref":"Jeremiah 46:16","short":"Jer 46:16","text":"He made many stumble, and they fell, and they said one to another, ‘Arise, and let us go back to our own people and to the land of our birth, because of the sword of the oppressor.’","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":16},{"ref":"Jeremiah 46:17","short":"Jer 46:17","text":"Call the name of Pharaoh, king of Egypt, ‘Noisy one who lets the hour go by.’","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":17},{"ref":"Jeremiah 46:18","short":"Jer 46:18","text":"“As I live, declares the King, whose name is the LORD of hosts, like Tabor among the mountains and like Carmel by the sea, shall one come.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":18},{"ref":"Jeremiah 46:19","short":"Jer 46:19","text":"Prepare yourselves baggage for exile, O inhabitants of Egypt! For Memphis shall become a waste, a ruin, without inhabitant.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":19},{"ref":"Jeremiah 46:20","short":"Jer 46:20","text":"“A beautiful heifer is Egypt, but a biting fly from the north has come upon her.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":20},{"ref":"Jeremiah 46:21","short":"Jer 46:21","text":"Even her hired soldiers in her midst are like fattened calves; yes, they have turned and fled together; they did not stand, for the day of their calamity has come upon them, the time of their punishment.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":21},{"ref":"Jeremiah 46:22","short":"Jer 46:22","text":"“She makes a sound like a serpent gliding away; for her enemies march in force and come against her with axes like those who fell trees.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":22},{"ref":"Jeremiah 46:23","short":"Jer 46:23","text":"They shall cut down her forest, declares the LORD, though it is impenetrable, because they are more numerous than locusts; they are without number.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":23},{"ref":"Jeremiah 46:24","short":"Jer 46:24","text":"The daughter of Egypt shall be put to shame; she shall be delivered into the hand of a people from the north.”","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":24},{"ref":"Jeremiah 46:25","short":"Jer 46:25","text":"The LORD of hosts, the God of Israel, said: “Behold, I am bringing punishment upon Amon of Thebes, and Pharaoh and Egypt and her gods and her kings, upon Pharaoh and those who trust in him.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":25},{"ref":"Jeremiah 46:26","short":"Jer 46:26","text":"I will deliver them into the hand of those who seek their life, into the hand of Nebuchadnezzar king of Babylon and his officers. Afterward Egypt shall be inhabited as in the days of old, declares the LORD.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":26},{"ref":"Jeremiah 46:27","short":"Jer 46:27","text":"“But fear not, O Jacob my servant, nor be dismayed, O Israel, for behold, I will save you from far away, and your offspring from the land of their captivity. Jacob shall return and have quiet and ease, and none shall make him afraid.","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":27},{"ref":"Jeremiah 46:28","short":"Jer 46:28","text":"Fear not, O Jacob my servant, declares the LORD, for I am with you. I will make a full end of all the nations to which I have driven you, but of you I will not make a full end. I will discipline you in just measure, and I will by no means leave you unpunished.”","url":"ot/jeremiah/Jeremiah_46.html","book":"Jeremiah","ch":46,"v":28},{"ref":"Jeremiah 47:1","short":"Jer 47:1","text":"The word of the LORD that came to Jeremiah the prophet concerning the Philistines, before Pharaoh struck down Gaza.","url":"ot/jeremiah/Jeremiah_47.html","book":"Jeremiah","ch":47,"v":1},{"ref":"Jeremiah 47:2","short":"Jer 47:2","text":"“Thus says the LORD: Behold, waters are rising out of the north, and shall become an overflowing torrent; they shall overflow the land and all that fills it, the city and those who dwell in it. Men shall cry out, and every inhabitant of the land shall wail.","url":"ot/jeremiah/Jeremiah_47.html","book":"Jeremiah","ch":47,"v":2},{"ref":"Jeremiah 47:3","short":"Jer 47:3","text":"At the noise of the stamping of the hoofs of his stallions, at the rushing of his chariots, at the rumbling of their wheels, the fathers look not back to their children, so feeble are their hands,","url":"ot/jeremiah/Jeremiah_47.html","book":"Jeremiah","ch":47,"v":3},{"ref":"Jeremiah 47:4","short":"Jer 47:4","text":"because of the day that is coming to destroy all the Philistines, to cut off from Tyre and Sidon every helper that remains. For the LORD is destroying the Philistines, the remnant of the coastland of Caphtor.","url":"ot/jeremiah/Jeremiah_47.html","book":"Jeremiah","ch":47,"v":4},{"ref":"Jeremiah 47:5","short":"Jer 47:5","text":"Baldness has come upon Gaza; Ashkelon has perished. O remnant of their valley, how long will you gash yourselves?","url":"ot/jeremiah/Jeremiah_47.html","book":"Jeremiah","ch":47,"v":5},{"ref":"Jeremiah 47:6","short":"Jer 47:6","text":"Ah, sword of the LORD! How long till you are quiet? Put yourself into your scabbard; rest and be still!","url":"ot/jeremiah/Jeremiah_47.html","book":"Jeremiah","ch":47,"v":6},{"ref":"Jeremiah 47:7","short":"Jer 47:7","text":"How can it be quiet when the LORD has given it a charge? Against Ashkelon and against the seashore he has appointed it.”","url":"ot/jeremiah/Jeremiah_47.html","book":"Jeremiah","ch":47,"v":7},{"ref":"Jeremiah 49:1","short":"Jer 49:1","text":"Concerning the Ammonites. Thus says the LORD: “Has Israel no sons? Has he no heir? Why then has Milcom dispossessed Gad, and his people settled in its cities?","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":1},{"ref":"Jeremiah 49:2","short":"Jer 49:2","text":"Therefore, behold, the days are coming, declares the LORD, when I will cause the battle cry to be heard against Rabbah of the Ammonites; it shall become a desolate mound, and its villages shall be burned with fire; then Israel shall dispossess those who dispossessed him, says the LORD.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":2},{"ref":"Jeremiah 49:3","short":"Jer 49:3","text":"“Wail, O Heshbon, for Ai is laid waste! Cry out, O daughters of Rabbah! Put on sackcloth, lament, and run to and fro among the hedges! For Milcom shall go into exile, with his priests and his officials.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":3},{"ref":"Jeremiah 49:4","short":"Jer 49:4","text":"Why do you boast of your valleys, O faithless daughter, who trusted in her treasures, saying, ‘Who will come against me?’","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":4},{"ref":"Jeremiah 49:5","short":"Jer 49:5","text":"Behold, I will bring terror upon you, declares the Lord GOD of hosts, from all who are around you, and you shall be driven out, every man straight before him, with none to gather the fugitives.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":5},{"ref":"Jeremiah 49:6","short":"Jer 49:6","text":"“But afterward I will restore the fortunes of the Ammonites, declares the LORD.”","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":6},{"ref":"Jeremiah 49:7","short":"Jer 49:7","text":"Concerning Edom. Thus says the LORD of hosts: “Is wisdom no more in Teman? Has counsel perished from the prudent? Has their wisdom vanished?","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":7},{"ref":"Jeremiah 49:8","short":"Jer 49:8","text":"Flee, turn back, dwell in the depths, O inhabitants of Dedan! For I will bring the calamity of Esau upon him, the time when I punish him.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":8},{"ref":"Jeremiah 49:9","short":"Jer 49:9","text":"If grape gatherers came to you, would they not leave gleanings? If thieves came by night, would they not destroy only enough for themselves?","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":9},{"ref":"Jeremiah 49:10","short":"Jer 49:10","text":"But I have stripped Esau bare; I have uncovered his hiding places, and he is not able to conceal himself. His children are destroyed, and his brothers, and his neighbors; and he is no more.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":10},{"ref":"Jeremiah 49:11","short":"Jer 49:11","text":"Leave your fatherless children; I will keep them alive; and let your widows trust in me.”","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":11},{"ref":"Jeremiah 49:12","short":"Jer 49:12","text":"For thus says the LORD: “If those who did not deserve to drink the cup must drink it, will you go unpunished? You shall not go unpunished, but you must drink.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":12},{"ref":"Jeremiah 49:13","short":"Jer 49:13","text":"For I have sworn by myself, declares the LORD, that Bozrah shall become a horror, a taunt, a waste, and a curse, and all her cities shall be perpetual wastes.”","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":13},{"ref":"Jeremiah 49:14","short":"Jer 49:14","text":"I have heard a message from the LORD, and an envoy has been sent among the nations: “Gather yourselves together and come against her, and rise up for battle!","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":14},{"ref":"Jeremiah 49:15","short":"Jer 49:15","text":"For behold, I will make you small among the nations, despised among mankind.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":15},{"ref":"Jeremiah 49:16","short":"Jer 49:16","text":"The horror you inspire has deceived you, and the pride of your heart, you who live in the clefts of the rock, who hold the height of the hill. Though you make your nest as high as the eagle’s, I will bring you down from there, declares the LORD.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":16},{"ref":"Jeremiah 49:17","short":"Jer 49:17","text":"“Edom shall become a horror. Everyone who passes by it will be horrified and will hiss because of all its disasters.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":17},{"ref":"Jeremiah 49:18","short":"Jer 49:18","text":"As when Sodom and Gomorrah and their neighboring cities were overthrown, says the LORD, no man shall dwell there, no man shall sojourn in her.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":18},{"ref":"Jeremiah 49:19","short":"Jer 49:19","text":"Behold, like a lion coming up from the jungle of the Jordan against a perennial pasture, I will suddenly make him run away from her. And I will appoint over her whomever I choose. For who is like me? Who will summon me? What shepherd can stand before me?","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":19},{"ref":"Jeremiah 49:20","short":"Jer 49:20","text":"Therefore hear the plan that the LORD has made against Edom and the purposes that he has formed against the inhabitants of Teman: Even the little ones of the flock shall be dragged away. Surely their fold shall be appalled at their fate.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":20},{"ref":"Jeremiah 49:21","short":"Jer 49:21","text":"At the sound of their fall the earth shall tremble; the sound of their cry shall be heard at the Red Sea.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":21},{"ref":"Jeremiah 49:22","short":"Jer 49:22","text":"Behold, one shall mount up and fly swiftly like an eagle and spread his wings against Bozrah, and the heart of the warriors of Edom shall be in that day like the heart of a woman in her birth pains.”","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":22},{"ref":"Jeremiah 49:23","short":"Jer 49:23","text":"Concerning Damascus: “Hamath and Arpad are confounded, for they have heard bad news; they melt in fear, they are troubled like the sea that cannot be quiet.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":23},{"ref":"Jeremiah 49:24","short":"Jer 49:24","text":"Damascus has become feeble, she turned to flee, and panic seized her; anguish and sorrows have taken hold of her, as of a woman in labor.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":24},{"ref":"Jeremiah 49:25","short":"Jer 49:25","text":"How is the famous city not forsaken, the city of my joy?","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":25},{"ref":"Jeremiah 49:26","short":"Jer 49:26","text":"Therefore her young men shall fall in her squares, and all her soldiers shall be destroyed in that day, declares the LORD of hosts.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":26},{"ref":"Jeremiah 49:27","short":"Jer 49:27","text":"And I will kindle a fire in the wall of Damascus, and it shall devour the strongholds of Ben-hadad.”","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":27},{"ref":"Jeremiah 49:28","short":"Jer 49:28","text":"Concerning Kedar and the kingdoms of Hazor that Nebuchadnezzar king of Babylon struck down. Thus says the LORD: “Rise up, advance against Kedar! Destroy the people of the east!","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":28},{"ref":"Jeremiah 49:29","short":"Jer 49:29","text":"Their tents and their flocks shall be taken, their curtains and all their goods; their camels shall be led away from them, and men shall cry to them: ‘Terror on every side!’","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":29},{"ref":"Jeremiah 49:30","short":"Jer 49:30","text":"Flee, wander far away, dwell in the depths, O inhabitants of Hazor! declares the LORD. For Nebuchadnezzar king of Babylon has made a plan against you and formed a purpose against you.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":30},{"ref":"Jeremiah 49:31","short":"Jer 49:31","text":"“Rise up, advance against a nation at ease, that dwells securely, declares the LORD, that has no gates or bars, that dwells alone.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":31},{"ref":"Jeremiah 49:32","short":"Jer 49:32","text":"Their camels shall become plunder, their herds of livestock a spoil. I will scatter to every wind those who cut the corners of their hair, and I will bring their calamity from every side of them, declares the LORD.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":32},{"ref":"Jeremiah 49:33","short":"Jer 49:33","text":"Hazor shall become a haunt of jackals, an everlasting waste; no man shall dwell there; no man shall sojourn in her.”","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":33},{"ref":"Jeremiah 49:34","short":"Jer 49:34","text":"The word of the LORD that came to Jeremiah the prophet concerning Elam, in the beginning of the reign of Zedekiah king of Judah.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":34},{"ref":"Jeremiah 49:35","short":"Jer 49:35","text":"Thus says the LORD of hosts: “Behold, I will break the bow of Elam, the mainstay of their might.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":35},{"ref":"Jeremiah 49:36","short":"Jer 49:36","text":"And I will bring upon Elam the four winds from the four quarters of heaven. And I will scatter them to all those winds, and there shall be no nation to which those driven out of Elam shall not come.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":36},{"ref":"Jeremiah 49:37","short":"Jer 49:37","text":"I will terrify Elam before their enemies and before those who seek their life. I will bring disaster upon them, my fierce anger, declares the LORD. I will send the sword after them, until I have consumed them,","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":37},{"ref":"Jeremiah 49:38","short":"Jer 49:38","text":"and I will set my throne in Elam and destroy their king and officials, declares the LORD.","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":38},{"ref":"Jeremiah 49:39","short":"Jer 49:39","text":"“But in the latter days I will restore the fortunes of Elam, declares the LORD.”","url":"ot/jeremiah/Jeremiah_49.html","book":"Jeremiah","ch":49,"v":39},{"ref":"Jeremiah 50:1","short":"Jer 50:1","text":"The word that the LORD spoke concerning Babylon, concerning the land of the Chaldeans, by Jeremiah the prophet:","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":1},{"ref":"Jeremiah 50:2","short":"Jer 50:2","text":"“Declare among the nations and proclaim, set up a banner and proclaim, conceal it not, and say: ‘Babylon is taken, Bel is put to shame, Merodach is dismayed. Her images are put to shame, her idols are dismayed.’","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":2},{"ref":"Jeremiah 50:3","short":"Jer 50:3","text":"“For out of the north a nation has come up against her, which shall make her land a desolation, and none shall dwell in it; both man and beast shall flee away.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":3},{"ref":"Jeremiah 50:4","short":"Jer 50:4","text":"“In those days and in that time, declares the LORD, the people of Israel and the people of Judah shall come together, weeping as they come, and they shall seek the LORD their God.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":4},{"ref":"Jeremiah 50:5","short":"Jer 50:5","text":"They shall ask the way to Zion, with faces turned toward it, saying, ‘Come, let us join ourselves to the LORD in an everlasting covenant that will never be forgotten.’","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":5},{"ref":"Jeremiah 50:6","short":"Jer 50:6","text":"“My people have been lost sheep. Their shepherds have led them astray, turning them away on the mountains. From mountain to hill they have gone. They have forgotten their fold.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":6},{"ref":"Jeremiah 50:7","short":"Jer 50:7","text":"All who found them have devoured them, and their enemies have said, ‘We are not guilty, for they have sinned against the LORD, their habitation of righteousness, the LORD, the hope of their fathers.’","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":7},{"ref":"Jeremiah 50:8","short":"Jer 50:8","text":"“Flee from the midst of Babylon, and go out of the land of the Chaldeans, and be as male goats before the flock.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":8},{"ref":"Jeremiah 50:9","short":"Jer 50:9","text":"For behold, I am stirring up and bringing against Babylon a gathering of great nations, from the north country. And they shall array themselves against her. From there she shall be taken. Their arrows are like a skilled warrior who does not return empty-handed.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":9},{"ref":"Jeremiah 50:10","short":"Jer 50:10","text":"Chaldea shall be plundered; all who plunder her shall be sated, declares the LORD.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":10},{"ref":"Jeremiah 50:11","short":"Jer 50:11","text":"“Though you rejoice, though you exult, O plunderers of my heritage, though you frolic like a heifer in the pasture, and neigh like stallions,","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":11},{"ref":"Jeremiah 50:12","short":"Jer 50:12","text":"your mother shall be utterly shamed, and she who bore you shall be disgraced. Behold, she shall be the last of the nations, a wilderness, a dry land, and a desert.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":12},{"ref":"Jeremiah 50:13","short":"Jer 50:13","text":"Because of the wrath of the LORD she shall not be inhabited but shall be an utter desolation; everyone who passes by Babylon shall be appalled, and hiss because of all her wounds.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":13},{"ref":"Jeremiah 50:14","short":"Jer 50:14","text":"Set yourselves in array against Babylon all around, all you who bend the bow; shoot at her, spare no arrows, for she has sinned against the LORD.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":14},{"ref":"Jeremiah 50:15","short":"Jer 50:15","text":"Raise a shout against her all around; she has surrendered; her bulwarks have fallen; her walls are thrown down. For this is the vengeance of the LORD: take vengeance on her; do to her as she has done.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":15},{"ref":"Jeremiah 50:16","short":"Jer 50:16","text":"Cut off from Babylon the sower, and the one who handles the sickle in time of harvest; because of the sword of the oppressor, every one shall turn to his own people, and every one shall flee to his own land.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":16},{"ref":"Jeremiah 50:17","short":"Jer 50:17","text":"“Israel is a hunted sheep driven away by lions. First the king of Assyria devoured him, and now at last Nebuchadnezzar king of Babylon has gnawed his bones.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":17},{"ref":"Jeremiah 50:18","short":"Jer 50:18","text":"Therefore, thus says the LORD of hosts, the God of Israel: Behold, I am bringing punishment on the king of Babylon and his land, as I punished the king of Assyria.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":18},{"ref":"Jeremiah 50:19","short":"Jer 50:19","text":"I will restore Israel to his pasture, and he shall feed on Carmel and in Bashan, and his desire shall be satisfied on the hills of Ephraim and in Gilead.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":19},{"ref":"Jeremiah 50:20","short":"Jer 50:20","text":"In those days and in that time, declares the LORD, iniquity shall be sought in Israel, and there shall be none, and sin in Judah, and none shall be found, for I will pardon those whom I leave as a remnant.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":20},{"ref":"Jeremiah 50:21","short":"Jer 50:21","text":"“Go up against the land of Merathaim, and against the inhabitants of Pekod. Kill, and devote them to destruction, declares the LORD, and do all that I have commanded you.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":21},{"ref":"Jeremiah 50:22","short":"Jer 50:22","text":"The noise of battle is in the land, and great destruction!","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":22},{"ref":"Jeremiah 50:23","short":"Jer 50:23","text":"How the hammer of the whole earth is cut down and broken! How Babylon has become a horror among the nations!","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":23},{"ref":"Jeremiah 50:24","short":"Jer 50:24","text":"I set a snare for you and you were taken, O Babylon, and you did not know it; you were found and caught, because you opposed the LORD.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":24},{"ref":"Jeremiah 50:25","short":"Jer 50:25","text":"The LORD has opened his armory and brought out the weapons of his wrath, for the Lord GOD of hosts has a work to do in the land of the Chaldeans.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":25},{"ref":"Jeremiah 50:26","short":"Jer 50:26","text":"Come against her from every quarter; open her granaries; pile her up like heaps of grain, and devote her to destruction; let nothing be left of her.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":26},{"ref":"Jeremiah 50:27","short":"Jer 50:27","text":"Kill all her bulls; let them go down to the slaughter. Woe to them, for their day has come, the time of their punishment.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":27},{"ref":"Jeremiah 50:28","short":"Jer 50:28","text":"“A voice! They flee and escape from the land of Babylon, to declare in Zion the vengeance of the LORD our God, vengeance for his temple.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":28},{"ref":"Jeremiah 50:29","short":"Jer 50:29","text":"“Summon archers against Babylon, all those who bend the bow. Encamp around her; let no one escape. Repay her according to her deeds; do to her according to all that she has done. For she has proudly defied the LORD, the Holy One of Israel.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":29},{"ref":"Jeremiah 50:30","short":"Jer 50:30","text":"Therefore her young men shall fall in her squares, and all her soldiers shall be destroyed on that day, declares the LORD.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":30},{"ref":"Jeremiah 50:31","short":"Jer 50:31","text":"“Behold, I am against you, O proud one, declares the Lord GOD of hosts, for your day has come, the time when I will punish you.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":31},{"ref":"Jeremiah 50:32","short":"Jer 50:32","text":"The proud one shall stumble and fall, with none to raise him up, and I will kindle a fire in his cities, and it will devour all that is around him.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":32},{"ref":"Jeremiah 50:33","short":"Jer 50:33","text":"“Thus says the LORD of hosts: The people of Israel are oppressed, and the people of Judah with them. All who took them captive have held them fast; they refuse to let them go.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":33},{"ref":"Jeremiah 50:34","short":"Jer 50:34","text":"Their Redeemer is strong; the LORD of hosts is his name. He will surely plead their cause, that he may give rest to the earth, but unrest to the inhabitants of Babylon.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":34},{"ref":"Jeremiah 50:35","short":"Jer 50:35","text":"“A sword against the Chaldeans, declares the LORD, and against the inhabitants of Babylon, and against her officials and her wise men!","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":35},{"ref":"Jeremiah 50:36","short":"Jer 50:36","text":"A sword against the diviners, that they may become fools! A sword against her warriors, that they may be destroyed!","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":36},{"ref":"Jeremiah 50:37","short":"Jer 50:37","text":"A sword against her horses and against her chariots, and against all the foreign troops in her midst, that they may become women! A sword against all her treasures, that they may be plundered!","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":37},{"ref":"Jeremiah 50:38","short":"Jer 50:38","text":"A drought against her waters, that they may be dried up! For it is a land of images, and they are mad over idols.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":38},{"ref":"Jeremiah 50:39","short":"Jer 50:39","text":"“Therefore wild beasts shall dwell with hyenas in Babylon, and ostriches shall dwell in her. She shall never again have people, nor be inhabited for all generations.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":39},{"ref":"Jeremiah 50:40","short":"Jer 50:40","text":"As when God overthrew Sodom and Gomorrah and their neighboring cities, declares the LORD, so no man shall dwell there, and no son of man shall sojourn in her.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":40},{"ref":"Jeremiah 50:41","short":"Jer 50:41","text":"“Behold, a people comes from the north; a mighty nation and many kings are stirring from the farthest parts of the earth.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":41},{"ref":"Jeremiah 50:42","short":"Jer 50:42","text":"They lay hold of bow and spear; they are cruel and have no mercy. The sound of them is like the roaring of the sea; they ride on horses, arrayed as a man for battle against you, O daughter of Babylon!","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":42},{"ref":"Jeremiah 50:43","short":"Jer 50:43","text":"“The king of Babylon heard the report of them, and his hands fell helpless; anguish seized him, pain as of a woman in labor.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":43},{"ref":"Jeremiah 50:44","short":"Jer 50:44","text":"“Behold, like a lion coming up from the thicket of the Jordan against a perennial pasture, I will suddenly make them run away from her, and I will appoint over her whomever I choose. For who is like me? Who will summon me? What shepherd can stand before me?","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":44},{"ref":"Jeremiah 50:45","short":"Jer 50:45","text":"Therefore hear the plan that the LORD has made against Babylon, and the purposes that he has formed against the land of the Chaldeans: Surely the little ones of their flock shall be dragged away; surely their fold shall be appalled at their fate.","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":45},{"ref":"Jeremiah 50:46","short":"Jer 50:46","text":"At the sound of the capture of Babylon the earth shall tremble, and her cry shall be heard among the nations.”","url":"ot/jeremiah/Jeremiah_50.html","book":"Jeremiah","ch":50,"v":46},{"ref":"Jeremiah 51:1","short":"Jer 51:1","text":"Thus says the LORD: “Behold, I will stir up the spirit of a destroyer against Babylon, against the inhabitants of Leb-kamai,","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":1},{"ref":"Jeremiah 51:2","short":"Jer 51:2","text":"and I will send to Babylon winnowers, and they shall winnow her, and they shall empty her land, when they come against her from every side on the day of trouble.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":2},{"ref":"Jeremiah 51:3","short":"Jer 51:3","text":"Let not the archer bend his bow, and let him not stand up in his armor. Spare not her young men; devote to destruction all her army.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":3},{"ref":"Jeremiah 51:4","short":"Jer 51:4","text":"They shall fall down slain in the land of the Chaldeans, and wounded in her streets.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":4},{"ref":"Jeremiah 51:5","short":"Jer 51:5","text":"For Israel and Judah have not been forsaken by their God, the LORD of hosts, but the land of the Chaldeans is full of guilt against the Holy One of Israel.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":5},{"ref":"Jeremiah 51:6","short":"Jer 51:6","text":"“Flee from the midst of Babylon; let every one save his life! Be not cut off in her punishment, for this is the time of the LORD’s vengeance, the repayment he is rendering her.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":6},{"ref":"Jeremiah 51:7","short":"Jer 51:7","text":"Babylon was a golden cup in the LORD’s hand, making all the earth drunken; the nations drank of her wine; therefore the nations went mad.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":7},{"ref":"Jeremiah 51:8","short":"Jer 51:8","text":"Suddenly Babylon has fallen and been broken; wail for her! Take balm for her pain; perhaps she may be healed.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":8},{"ref":"Jeremiah 51:9","short":"Jer 51:9","text":"We would have healed Babylon, but she was not healed. Forsake her, and let us go each to his own country, for her judgment has reached up to heaven and has been lifted up even to the skies.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":9},{"ref":"Jeremiah 51:10","short":"Jer 51:10","text":"The LORD has brought about our vindication; come, let us declare in Zion the work of the LORD our God.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":10},{"ref":"Jeremiah 51:11","short":"Jer 51:11","text":"“Sharpen the arrows! Take up the shields! The LORD has stirred up the spirit of the kings of the Medes, because his purpose concerning Babylon is to destroy it, for that is the vengeance of the LORD, the vengeance for his temple.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":11},{"ref":"Jeremiah 51:12","short":"Jer 51:12","text":"“Set up a standard against the walls of Babylon; make the watch strong; set up watchmen; prepare the ambushes; for the LORD has both planned and done what he spoke concerning the inhabitants of Babylon.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":12},{"ref":"Jeremiah 51:13","short":"Jer 51:13","text":"O you who dwell by many waters, rich in treasures, your end has come; the thread of your life is cut.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":13},{"ref":"Jeremiah 51:14","short":"Jer 51:14","text":"The LORD of hosts has sworn by himself: Surely I will fill you with men, as many as locusts, and they shall raise the shout of victory over you.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":14},{"ref":"Jeremiah 51:15","short":"Jer 51:15","text":"“It is he who made the earth by his power, who established the world by his wisdom, and by his understanding stretched out the heavens.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":15},{"ref":"Jeremiah 51:16","short":"Jer 51:16","text":"When he utters his voice there is a tumult of waters in the heavens, and he makes the mist rise from the ends of the earth. He makes lightning for the rain, and he brings forth the wind from his storehouses.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":16},{"ref":"Jeremiah 51:17","short":"Jer 51:17","text":"Every man is stupid and without knowledge; every goldsmith is put to shame by his idols, for his images are false, and there is no breath in them.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":17},{"ref":"Jeremiah 51:18","short":"Jer 51:18","text":"They are worthless, a work of delusion; at the time of their punishment they shall perish.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":18},{"ref":"Jeremiah 51:19","short":"Jer 51:19","text":"Not like these is he who is the portion of Jacob, for he is the one who formed all things, and Israel is the tribe of his inheritance; the LORD of hosts is his name.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":19},{"ref":"Jeremiah 51:20","short":"Jer 51:20","text":"“You are my hammer and weapon of war: with you I break nations in pieces; with you I destroy kingdoms;","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":20},{"ref":"Jeremiah 51:21","short":"Jer 51:21","text":"with you I break in pieces the horse and his rider; with you I break in pieces the chariot and the charioteer;","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":21},{"ref":"Jeremiah 51:22","short":"Jer 51:22","text":"with you I break in pieces man and woman; with you I break in pieces the old man and the youth; with you I break in pieces the young man and the young woman;","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":22},{"ref":"Jeremiah 51:23","short":"Jer 51:23","text":"with you I break in pieces the shepherd and his flock; with you I break in pieces the farmer and his team; with you I break in pieces governors and commanders.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":23},{"ref":"Jeremiah 51:24","short":"Jer 51:24","text":"“I will repay Babylon and all the inhabitants of Chaldea before your very eyes for all the evil that they have done in Zion, declares the LORD.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":24},{"ref":"Jeremiah 51:25","short":"Jer 51:25","text":"“Behold, I am against you, O destroying mountain, declares the LORD, which destroys the whole earth; I will stretch out my hand against you, and roll you down from the crags, and make you a burnt mountain.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":25},{"ref":"Jeremiah 51:26","short":"Jer 51:26","text":"No stone shall be taken from you for a corner and no stone for a foundation, but you shall be a perpetual waste, declares the LORD.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":26},{"ref":"Jeremiah 51:27","short":"Jer 51:27","text":"“Set up a standard on the earth; blow the trumpet among the nations; prepare the nations for war against her; summon against her the kingdoms, Ararat, Minni, and Ashkenaz; appoint a marshal against her; bring up horses like bristling locusts.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":27},{"ref":"Jeremiah 51:28","short":"Jer 51:28","text":"Prepare the nations for war against her, the kings of the Medes, with their governors and deputies, and every land under their dominion.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":28},{"ref":"Jeremiah 51:29","short":"Jer 51:29","text":"The land trembles and writhes in pain, for the LORD’s purposes against Babylon stand, to make the land of Babylon a desolation, without inhabitant.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":29},{"ref":"Jeremiah 51:30","short":"Jer 51:30","text":"The warriors of Babylon have ceased fighting; they remain in their strongholds; their strength has failed; they have become women; her dwellings are on fire; her bars are broken.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":30},{"ref":"Jeremiah 51:31","short":"Jer 51:31","text":"One runner runs to meet another, and one messenger to meet another, to tell the king of Babylon that his city is taken on every side;","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":31},{"ref":"Jeremiah 51:32","short":"Jer 51:32","text":"the fords have been seized, the marshes are burned with fire, and the soldiers are in panic.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":32},{"ref":"Jeremiah 51:33","short":"Jer 51:33","text":"For thus says the LORD of hosts, the God of Israel: The daughter of Babylon is like a threshing floor at the time when it is trodden; yet a little while and the time of her harvest will come.”","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":33},{"ref":"Jeremiah 51:34","short":"Jer 51:34","text":"“Nebuchadnezzar the king of Babylon has devoured me; he has crushed me; he has made me an empty vessel; he has swallowed me like a monster; he has filled his stomach with my delicacies; he has rinsed me out.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":34},{"ref":"Jeremiah 51:35","short":"Jer 51:35","text":"The violence done to me and to my kinsmen be upon Babylon,” let the inhabitant of Zion say. “My blood be upon the inhabitants of Chaldea,” let Jerusalem say.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":35},{"ref":"Jeremiah 51:36","short":"Jer 51:36","text":"Therefore thus says the LORD: “Behold, I will plead your cause and take vengeance for you. I will dry up her sea and make her fountain dry,","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":36},{"ref":"Jeremiah 51:37","short":"Jer 51:37","text":"and Babylon shall become a heap of ruins, the haunt of jackals, a horror and a hissing, without inhabitant.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":37},{"ref":"Jeremiah 51:38","short":"Jer 51:38","text":"“They shall roar together like lions; they shall growl like lions’ cubs.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":38},{"ref":"Jeremiah 51:39","short":"Jer 51:39","text":"While they are inflamed I will prepare them a feast and make them drunk, that they may become merry, then sleep a perpetual sleep and not wake, declares the LORD.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":39},{"ref":"Jeremiah 51:40","short":"Jer 51:40","text":"I will bring them down like lambs to the slaughter, like rams and male goats.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":40},{"ref":"Jeremiah 51:41","short":"Jer 51:41","text":"“How Babylon is taken, the praise of the whole earth seized! How Babylon has become a horror among the nations!","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":41},{"ref":"Jeremiah 51:42","short":"Jer 51:42","text":"The sea has come up on Babylon; she is covered with its tumultuous waves.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":42},{"ref":"Jeremiah 51:43","short":"Jer 51:43","text":"Her cities have become a horror, a land of drought and a desert, a land in which no one dwells, and through which no son of man passes.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":43},{"ref":"Jeremiah 51:44","short":"Jer 51:44","text":"And I will punish Bel in Babylon, and take out of his mouth what he has swallowed. The nations shall no longer flow to him; the wall of Babylon has fallen.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":44},{"ref":"Jeremiah 51:45","short":"Jer 51:45","text":"“Go out of the midst of her, my people! Let every one save his life from the fierce anger of the LORD!","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":45},{"ref":"Jeremiah 51:46","short":"Jer 51:46","text":"Let not your heart faint, and be not fearful at the report heard in the land, when a report comes in one year and afterward a report in another year, and violence is in the land, and ruler is against ruler.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":46},{"ref":"Jeremiah 51:47","short":"Jer 51:47","text":"“Therefore, behold, the days are coming when I will punish the images of Babylon; her whole land shall be put to shame, and all her slain shall fall in the midst of her.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":47},{"ref":"Jeremiah 51:48","short":"Jer 51:48","text":"Then the heavens and the earth, and all that is in them, shall sing for joy over Babylon, for the destroyers shall come against them out of the north, declares the LORD.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":48},{"ref":"Jeremiah 51:49","short":"Jer 51:49","text":"Babylon must fall for the slain of Israel, just as for Babylon have fallen the slain of all the earth.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":49},{"ref":"Jeremiah 51:50","short":"Jer 51:50","text":"“You who have escaped from the sword, go, do not stand still! Remember the LORD from far away, and let Jerusalem come into your mind:","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":50},{"ref":"Jeremiah 51:51","short":"Jer 51:51","text":"‘We are put to shame, for we have heard reproach; dishonor has covered our face, for foreigners have come into the holy places of the LORD’s house.’","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":51},{"ref":"Jeremiah 51:52","short":"Jer 51:52","text":"“Therefore, behold, the days are coming, declares the LORD, when I will execute judgment upon her images, and through all her land the wounded shall groan.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":52},{"ref":"Jeremiah 51:53","short":"Jer 51:53","text":"Though Babylon should mount up to heaven, and though she should fortify her strong height, yet destroyers would come from me against her, declares the LORD.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":53},{"ref":"Jeremiah 51:54","short":"Jer 51:54","text":"“A voice! A cry from Babylon! The noise of great destruction from the land of the Chaldeans!","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":54},{"ref":"Jeremiah 51:55","short":"Jer 51:55","text":"For the LORD is laying Babylon waste and stilling her mighty voice. Their waves roar like many waters; the noise of their voice is raised,","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":55},{"ref":"Jeremiah 51:56","short":"Jer 51:56","text":"for a destroyer has come upon her, upon Babylon; her warriors are taken; their bows are broken in pieces, for the LORD is a God of recompense; he will surely repay.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":56},{"ref":"Jeremiah 51:57","short":"Jer 51:57","text":"I will make drunk her officials and her wise men, her governors, her commanders, and her warriors; they shall sleep a perpetual sleep and not wake, declares the King, whose name is the LORD of hosts.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":57},{"ref":"Jeremiah 51:58","short":"Jer 51:58","text":"“Thus says the LORD of hosts: The broad wall of Babylon shall be leveled to the ground, and her high gates shall be burned with fire. The peoples labor for nothing, and the nations weary themselves only for fire.”","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":58},{"ref":"Jeremiah 51:59","short":"Jer 51:59","text":"The word that Jeremiah the prophet commanded Seraiah the son of Neriah, son of Mahseiah, when he went with Zedekiah king of Judah to Babylon, in the fourth year of his reign. Seraiah was the quartermaster.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":59},{"ref":"Jeremiah 51:60","short":"Jer 51:60","text":"Jeremiah wrote in a book all the disaster that should come upon Babylon, all these words that are written concerning Babylon.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":60},{"ref":"Jeremiah 51:61","short":"Jer 51:61","text":"And Jeremiah said to Seraiah: “When you come to Babylon, see that you read all these words,","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":61},{"ref":"Jeremiah 51:62","short":"Jer 51:62","text":"and say, ‘O LORD, you have said concerning this place that you will cut it off, so that nothing shall dwell in it, neither man nor beast, and it shall be desolate forever.’","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":62},{"ref":"Jeremiah 51:63","short":"Jer 51:63","text":"When you finish reading this book, tie a stone to it and cast it into the midst of the Euphrates,","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":63},{"ref":"Jeremiah 51:64","short":"Jer 51:64","text":"and say, ‘Thus shall Babylon sink, to rise no more, because of the disaster that I am bringing upon her, and they shall become exhausted.’” Thus far are the words of Jeremiah.","url":"ot/jeremiah/Jeremiah_51.html","book":"Jeremiah","ch":51,"v":64},{"ref":"Jeremiah 52:1","short":"Jer 52:1","text":"Zedekiah was twenty-one years old when he became king, and he reigned eleven years in Jerusalem. His mother’s name was Hamutal the daughter of Jeremiah of Libnah.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":1},{"ref":"Jeremiah 52:2","short":"Jer 52:2","text":"And he did what was evil in the sight of the LORD, according to all that Jehoiakim had done.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":2},{"ref":"Jeremiah 52:3","short":"Jer 52:3","text":"For because of the anger of the LORD it came to the point in Jerusalem and Judah that he cast them out from his presence. And Zedekiah rebelled against the king of Babylon.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":3},{"ref":"Jeremiah 52:4","short":"Jer 52:4","text":"And in the ninth year of his reign, in the tenth month, on the tenth day of the month, Nebuchadnezzar king of Babylon came with all his army against Jerusalem, and laid siege to it. And they built siegeworks all around it.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":4},{"ref":"Jeremiah 52:5","short":"Jer 52:5","text":"So the city was besieged till the eleventh year of King Zedekiah.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":5},{"ref":"Jeremiah 52:6","short":"Jer 52:6","text":"On the ninth day of the fourth month the famine was so severe in the city that there was no food for the people of the land.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":6},{"ref":"Jeremiah 52:7","short":"Jer 52:7","text":"Then a breach was made in the city, and all the men of war fled and went out from the city by night by the way of a gate between the two walls, by the king’s garden, and the Chaldeans were around the city. And they went in the direction of the Arabah.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":7},{"ref":"Jeremiah 52:8","short":"Jer 52:8","text":"But the army of the Chaldeans pursued the king and overtook Zedekiah in the plains of Jericho, and all his army was scattered from him.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":8},{"ref":"Jeremiah 52:9","short":"Jer 52:9","text":"Then they captured the king and brought him up to the king of Babylon at Riblah in the land of Hamath, and he passed sentence on him.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":9},{"ref":"Jeremiah 52:10","short":"Jer 52:10","text":"The king of Babylon slaughtered the sons of Zedekiah before his eyes, and also slaughtered all the officials of Judah at Riblah.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":10},{"ref":"Jeremiah 52:11","short":"Jer 52:11","text":"He put out the eyes of Zedekiah, and bound him in chains, and the king of Babylon took him to Babylon, and put him in prison till the day of his death.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":11},{"ref":"Jeremiah 52:12","short":"Jer 52:12","text":"In the fifth month, on the tenth day of the month—that was the nineteenth year of King Nebuchadnezzar, king of Babylon—Nebuzaradan the captain of the bodyguard, who served the king of Babylon, entered Jerusalem.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":12},{"ref":"Jeremiah 52:13","short":"Jer 52:13","text":"And he burned the house of the LORD, and the king’s house and all the houses of Jerusalem; every great house he burned down.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":13},{"ref":"Jeremiah 52:14","short":"Jer 52:14","text":"And all the army of the Chaldeans, who were with the captain of the guard, broke down all the walls around Jerusalem.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":14},{"ref":"Jeremiah 52:15","short":"Jer 52:15","text":"And Nebuzaradan the captain of the guard carried away captive some of the poorest of the people and the rest of the people who were left in the city and the deserters who had deserted to the king of Babylon, together with the rest of the artisans.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":15},{"ref":"Jeremiah 52:16","short":"Jer 52:16","text":"But Nebuzaradan the captain of the guard left some of the poorest of the land to be vinedressers and plowmen.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":16},{"ref":"Jeremiah 52:17","short":"Jer 52:17","text":"And the pillars of bronze that were in the house of the LORD, and the stands and the bronze sea that were in the house of the LORD, the Chaldeans broke in pieces, and carried all the bronze to Babylon.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":17},{"ref":"Jeremiah 52:18","short":"Jer 52:18","text":"And they took away the pots and the shovels and the snuffers and the basins and the dishes for incense and all the vessels of bronze used in the temple service;","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":18},{"ref":"Jeremiah 52:19","short":"Jer 52:19","text":"also the small bowls and the fire pans and the basins and the pots and the lampstands and the dishes for incense and the bowls for drink offerings. What was of gold the captain of the guard took away as gold, and what was of silver, as silver.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":19},{"ref":"Jeremiah 52:20","short":"Jer 52:20","text":"As for the two pillars, the one sea, the twelve bronze bulls that were under the sea, and the stands, which Solomon the king had made for the house of the LORD, the bronze of all these things was beyond weight.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":20},{"ref":"Jeremiah 52:21","short":"Jer 52:21","text":"As for the pillars, the height of the one pillar was eighteen cubits, its circumference was twelve cubits, and its thickness was four fingers, and it was hollow.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":21},{"ref":"Jeremiah 52:22","short":"Jer 52:22","text":"On it was a capital of bronze. The height of the one capital was five cubits. A network and pomegranates, all of bronze, were around the capital. And the second pillar had the same, with pomegranates.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":22},{"ref":"Jeremiah 52:23","short":"Jer 52:23","text":"There were ninety-six pomegranates on the sides; all the pomegranates were a hundred upon the network all around.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":23},{"ref":"Jeremiah 52:24","short":"Jer 52:24","text":"And the captain of the guard took Seraiah the chief priest, and Zephaniah the second priest and the three keepers of the threshold;","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":24},{"ref":"Jeremiah 52:25","short":"Jer 52:25","text":"and from the city he took an officer who had been in command of the men of war, and seven men of the king’s council, who were found in the city; and the secretary of the commander of the army, who mustered the people of the land; and sixty men of the people of the land, who were found in the midst of the city.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":25},{"ref":"Jeremiah 52:26","short":"Jer 52:26","text":"And Nebuzaradan the captain of the guard took them and brought them to the king of Babylon at Riblah.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":26},{"ref":"Jeremiah 52:27","short":"Jer 52:27","text":"And the king of Babylon struck them down and put them to death at Riblah in the land of Hamath. So Judah was taken into exile out of its land.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":27},{"ref":"Jeremiah 52:28","short":"Jer 52:28","text":"This is the number of the people whom Nebuchadnezzar carried away captive: in the seventh year, 3,023 Judeans;","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":28},{"ref":"Jeremiah 52:29","short":"Jer 52:29","text":"in the eighteenth year of Nebuchadnezzar he carried away captive from Jerusalem 832 persons;","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":29},{"ref":"Jeremiah 52:30","short":"Jer 52:30","text":"in the twenty-third year of Nebuchadnezzar, Nebuzaradan the captain of the guard carried away captive of the Judeans 745 persons; all the persons were 4,600.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":30},{"ref":"Jeremiah 52:31","short":"Jer 52:31","text":"And in the thirty-seventh year of the exile of Jehoiachin king of Judah, in the twelfth month, on the twenty-fifth day of the month, Evil-merodach king of Babylon, in the year that he began to reign, graciously freed Jehoiachin king of Judah and brought him out of prison.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":31},{"ref":"Jeremiah 52:32","short":"Jer 52:32","text":"And he spoke kindly to him and gave him a seat above the seats of the kings who were with him in Babylon.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":32},{"ref":"Jeremiah 52:33","short":"Jer 52:33","text":"So Jehoiachin put off his prison garments. And every day of his life he dined regularly at the king’s table,","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":33},{"ref":"Jeremiah 52:34","short":"Jer 52:34","text":"and for his allowance, a regular allowance was given him by the king, according to his daily needs, until the day of his death, as long as he lived.","url":"ot/jeremiah/Jeremiah_52.html","book":"Jeremiah","ch":52,"v":34}];
if(!window.VERSES_ALL)window.VERSES_ALL=[];
window.VERSES_ALL=window.VERSES_ALL.concat(VERSES_JEREMIAH);
